#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum DesktopLanguage {
    English,
    Chinese,
}

impl DesktopLanguage {
    fn from_code(code: &str) -> Self {
        match code.trim().to_ascii_lowercase().as_str() {
            "zh" | "zh-cn" | "zh-hans" | "cn" | "chinese" => Self::Chinese,
            _ => Self::English,
        }
    }

    const fn code(self) -> &'static str {
        match self {
            Self::English => "en",
            Self::Chinese => "zh",
        }
    }

    const fn is_chinese(self) -> bool {
        matches!(self, Self::Chinese)
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum DesktopThemeMode {
    Dark,
    Light,
}

impl DesktopThemeMode {
    fn parse(code: &str) -> Option<Self> {
        match code.trim().to_ascii_lowercase().as_str() {
            "dark" | "night" | "black" => Some(Self::Dark),
            "light" | "day" | "white" => Some(Self::Light),
            _ => None,
        }
    }

    fn from_code(code: &str) -> Self {
        Self::parse(code).unwrap_or(Self::Dark)
    }

    const fn code(self) -> &'static str {
        match self {
            Self::Dark => "dark",
            Self::Light => "light",
        }
    }

    const fn is_dark(self) -> bool {
        matches!(self, Self::Dark)
    }
}

