    #[allow(clippy::match_same_arms, clippy::too_many_lines)]
    fn localized_security_assessment_summary(
        &self,
        assessment: &SecurityAssessment,
    ) -> &'static str {
        match (
            self.ui_language(),
            assessment.severity,
            assessment.primary_driver,
        ) {
            (DesktopLanguage::Chinese, SecurityAssessmentSeverity::Hardened, _) => {
                "当前姿态较窄，适合继续保守地扩展自动化。"
            }
            (
                DesktopLanguage::Chinese,
                SecurityAssessmentSeverity::Critical,
                SecurityAssessmentDriver::GatewayInvalid,
            ) => "先回到已知安全的本机姿态，再继续依赖网关转交。",
            (
                DesktopLanguage::Chinese,
                SecurityAssessmentSeverity::Critical,
                SecurityAssessmentDriver::FullAccessSandbox,
            ) => "整机访问已放开，扩大自动化前必须先收紧沙箱。",
            (
                DesktopLanguage::Chinese,
                SecurityAssessmentSeverity::Critical,
                SecurityAssessmentDriver::DangerousPolicy,
            ) => "当前策略允许过宽的危险执行，应该先恢复保守配置。",
            (DesktopLanguage::Chinese, SecurityAssessmentSeverity::Critical, _) => {
                "当前存在严重安全姿态问题，扩大自动化前应先收紧。"
            }
            (
                DesktopLanguage::Chinese,
                SecurityAssessmentSeverity::Exposed,
                SecurityAssessmentDriver::RemoteGatewayExposure
                | SecurityAssessmentDriver::BridgeRemoteExposure,
            ) => "当前已经暴露到远程面，应该先确认这是否真是必要能力。",
            (
                DesktopLanguage::Chinese,
                SecurityAssessmentSeverity::Exposed,
                SecurityAssessmentDriver::GatewayNeedsAttention
                | SecurityAssessmentDriver::TrustedProxiesWeak,
            ) => "安全面已经打开，但健康或信任边界还不够干净。",
            (
                DesktopLanguage::Chinese,
                SecurityAssessmentSeverity::Exposed,
                SecurityAssessmentDriver::ConflictGuardDisabled
                | SecurityAssessmentDriver::BrowserAutomationExposure,
            ) => "自动化能力高于当前保护强度，建议先回退到更稳的姿态。",
            (DesktopLanguage::Chinese, SecurityAssessmentSeverity::Exposed, _) => {
                "当前安全面偏开放，应该继续缩小暴露与授权。"
            }
            (
                DesktopLanguage::Chinese,
                SecurityAssessmentSeverity::Guarded,
                SecurityAssessmentDriver::PermissionSurfaceExpanded,
            ) => "整体仍受控，但历史授权已经扩大了实际能力边界。",
            (
                DesktopLanguage::Chinese,
                SecurityAssessmentSeverity::Guarded,
                SecurityAssessmentDriver::ScopeMissing,
            ) => "虽然选了 scoped 模式，但还没有用目录范围真正约束住它。",
            (DesktopLanguage::Chinese, SecurityAssessmentSeverity::Guarded, _) => {
                "整体受控，但仍有本机暴露面或保留权限需要继续整理。"
            }
            (_, SecurityAssessmentSeverity::Hardened, _) => {
                "The posture is narrow enough to keep scaling automation carefully."
            }
            (_, SecurityAssessmentSeverity::Critical, SecurityAssessmentDriver::GatewayInvalid) => {
                "Return to a known-safe local posture before trusting gateway handoff."
            }
            (
                _,
                SecurityAssessmentSeverity::Critical,
                SecurityAssessmentDriver::FullAccessSandbox,
            ) => "The desktop currently has full machine access and should be narrowed first.",
            (
                _,
                SecurityAssessmentSeverity::Critical,
                SecurityAssessmentDriver::DangerousPolicy,
            ) => "Dangerous fallback execution is too open and should be tightened first.",
            (_, SecurityAssessmentSeverity::Critical, _) => {
                "A critical security posture exists and should be reduced before trusting automation."
            }
            (
                _,
                SecurityAssessmentSeverity::Exposed,
                SecurityAssessmentDriver::RemoteGatewayExposure
                | SecurityAssessmentDriver::BridgeRemoteExposure,
            ) => "A remote surface is already live, so exposure should be justified explicitly.",
            (
                _,
                SecurityAssessmentSeverity::Exposed,
                SecurityAssessmentDriver::GatewayNeedsAttention
                | SecurityAssessmentDriver::TrustedProxiesWeak,
            ) => "The surface is open while health or trust boundaries are still weak.",
            (
                _,
                SecurityAssessmentSeverity::Exposed,
                SecurityAssessmentDriver::ConflictGuardDisabled
                | SecurityAssessmentDriver::BrowserAutomationExposure,
            ) => "Automation reach is broader than the current guardrails.",
            (_, SecurityAssessmentSeverity::Exposed, _) => {
                "The active posture is broader than necessary and should be reduced."
            }
            (
                _,
                SecurityAssessmentSeverity::Guarded,
                SecurityAssessmentDriver::PermissionSurfaceExpanded,
            ) => "The local posture is mostly controlled, but retained grants widen execution.",
            (_, SecurityAssessmentSeverity::Guarded, SecurityAssessmentDriver::ScopeMissing) => {
                "Scoped mode is selected, but no directories are actually constraining it."
            }
            (_, SecurityAssessmentSeverity::Guarded, _) => {
                "The posture is local and controlled, but still broader than a hardened baseline."
            }
        }
    }

    #[allow(clippy::match_same_arms, clippy::too_many_lines)]
    fn localized_security_assessment_driver_detail(
        &self,
        driver: SecurityAssessmentDriver,
    ) -> String {
        let security = &self.snapshot.context.security;
        let bridge = &self.snapshot.context.local_bridge;
        let runtime = &self.snapshot.runtime;
        let allowed_decisions = security
            .permission_decisions
            .iter()
            .filter(|decision| decision.allow)
            .count();

        match (self.ui_language(), driver) {
            (DesktopLanguage::Chinese, SecurityAssessmentDriver::HardenedBaseline) => {
                "网关、bridge、沙箱和授权面都保持在较窄范围内。".to_string()
            }
            (DesktopLanguage::Chinese, SecurityAssessmentDriver::GatewayInvalid) => security
                .gateway
                .diagnostics
                .first()
                .cloned()
                .unwrap_or_else(|| "网关存在无效配置，需要先回到本机已知安全姿态。".to_string()),
            (DesktopLanguage::Chinese, SecurityAssessmentDriver::FullAccessSandbox) => {
                "sandboxMode=full_access，当前工作区之外的整机面已经被打开。".to_string()
            }
            (DesktopLanguage::Chinese, SecurityAssessmentDriver::DangerousPolicy) => format!(
                "profile={} · defaultPermissive={} · allowDangerous={}",
                security.profile, security.default_permissive, security.allow_dangerous
            ),
            (DesktopLanguage::Chinese, SecurityAssessmentDriver::GatewayNeedsAttention) => security
                .gateway
                .diagnostics
                .first()
                .cloned()
                .unwrap_or_else(|| "网关需要重新检查连通性或鉴权。".to_string()),
            (DesktopLanguage::Chinese, SecurityAssessmentDriver::RemoteGatewayExposure) => format!(
                "{} · {}",
                self.localized_gateway_preset_label(security.gateway.preset),
                self.localized_gateway_remote_label(&security.gateway)
            ),
            (DesktopLanguage::Chinese, SecurityAssessmentDriver::GatewayLocalSurface) => format!(
                "{} · bind={} · auth={}",
                security.gateway.effective_endpoint,
                security.gateway.bind,
                security.gateway.auth_mode
            ),
            (DesktopLanguage::Chinese, SecurityAssessmentDriver::BridgeRemoteExposure) => format!(
                "{} · {}",
                bridge.endpoint(),
                if bridge.device_id.is_some() {
                    "已存在远程配对"
                } else {
                    "已填写远程 control plane"
                }
            ),
            (DesktopLanguage::Chinese, SecurityAssessmentDriver::BridgeLocalSurface) => format!(
                "{} · {}",
                bridge.endpoint(),
                if runtime.bridge_processes > 0 {
                    "bridge 进程运行中"
                } else {
                    "bridge 仅已配置"
                }
            ),
            (DesktopLanguage::Chinese, SecurityAssessmentDriver::ConflictGuardDisabled) => {
                "冲突保护已关闭，并发编辑与高风险操作更容易相互踩踏。".to_string()
            }
            (DesktopLanguage::Chinese, SecurityAssessmentDriver::BrowserAutomationExposure) => {
                "浏览器自动化已启用，当前姿态下应只在必要时开放。".to_string()
            }
            (DesktopLanguage::Chinese, SecurityAssessmentDriver::ScopeMissing) => {
                "当前选择了 workspace_scoped，但没有配置任何 scopedDirectories。".to_string()
            }
            (DesktopLanguage::Chinese, SecurityAssessmentDriver::TrustedProxiesWeak) => format!(
                "trustedProxies={}",
                if security.gateway.trusted_proxies.is_empty() {
                    "none".to_string()
                } else {
                    security.gateway.trusted_proxies.join(", ")
                }
            ),
            (DesktopLanguage::Chinese, SecurityAssessmentDriver::PermissionSurfaceExpanded) => {
                format!("{allowed_decisions} 条允许授权已持久化到权限存储。")
            }
            (_, SecurityAssessmentDriver::HardenedBaseline) => {
                "Gateway, bridge, sandbox, and stored grants are staying narrow.".to_string()
            }
            (_, SecurityAssessmentDriver::GatewayInvalid) => security
                .gateway
                .diagnostics
                .first()
                .cloned()
                .unwrap_or_else(|| {
                    "The gateway configuration is invalid and should be reduced.".to_string()
                }),
            (_, SecurityAssessmentDriver::FullAccessSandbox) => {
                "sandboxMode=full_access, so the desktop is no longer constrained to the workspace."
                    .to_string()
            }
            (_, SecurityAssessmentDriver::DangerousPolicy) => format!(
                "profile={} · defaultPermissive={} · allowDangerous={}",
                security.profile, security.default_permissive, security.allow_dangerous
            ),
            (_, SecurityAssessmentDriver::GatewayNeedsAttention) => security
                .gateway
                .diagnostics
                .first()
                .cloned()
                .unwrap_or_else(|| {
                    "The gateway should be re-checked for reachability or auth.".to_string()
                }),
            (_, SecurityAssessmentDriver::RemoteGatewayExposure) => format!(
                "{} · {}",
                self.localized_gateway_preset_label(security.gateway.preset),
                self.localized_gateway_remote_label(&security.gateway)
            ),
            (_, SecurityAssessmentDriver::GatewayLocalSurface) => format!(
                "{} · bind={} · auth={}",
                security.gateway.effective_endpoint,
                security.gateway.bind,
                security.gateway.auth_mode
            ),
            (_, SecurityAssessmentDriver::BridgeRemoteExposure) => format!(
                "{} · {}",
                bridge.endpoint(),
                if bridge.device_id.is_some() {
                    "remote pairing is active"
                } else {
                    "a remote control plane URL is configured"
                }
            ),
            (_, SecurityAssessmentDriver::BridgeLocalSurface) => format!(
                "{} · {}",
                bridge.endpoint(),
                if runtime.bridge_processes > 0 {
                    "bridge process live"
                } else {
                    "bridge configured only"
                }
            ),
            (_, SecurityAssessmentDriver::ConflictGuardDisabled) => {
                "Conflict guard is off, so concurrent edits and risky actions can overlap."
                    .to_string()
            }
            (_, SecurityAssessmentDriver::BrowserAutomationExposure) => {
                "Browser automation is enabled and should only stay on when truly needed."
                    .to_string()
            }
            (_, SecurityAssessmentDriver::ScopeMissing) => {
                "workspace_scoped is selected, but no scoped directories are configured."
                    .to_string()
            }
            (_, SecurityAssessmentDriver::TrustedProxiesWeak) => format!(
                "trustedProxies={}",
                if security.gateway.trusted_proxies.is_empty() {
                    "none".to_string()
                } else {
                    security.gateway.trusted_proxies.join(", ")
                }
            ),
            (_, SecurityAssessmentDriver::PermissionSurfaceExpanded) => {
                format!("{allowed_decisions} allow decisions are retained in the permission store.")
            }
        }
    }

    fn security_assessment_chip(&self, assessment: &SecurityAssessment) -> Container<'_, Message> {
        match assessment.severity {
            SecurityAssessmentSeverity::Hardened => self.status_chip_success(format!(
                "{} · {}",
                self.tr("Security", "安全"),
                self.localized_security_assessment_severity_label(assessment.severity)
            )),
            SecurityAssessmentSeverity::Guarded
            | SecurityAssessmentSeverity::Exposed
            | SecurityAssessmentSeverity::Critical => self.status_chip_warning(format!(
                "{} · {}",
                self.tr("Security", "安全"),
                self.localized_security_assessment_severity_label(assessment.severity)
            )),
        }
    }

    fn security_recommendation_button(
        &self,
        recommendation: SecurityRecommendation,
    ) -> Button<'static, Message> {
        match recommendation {
            SecurityRecommendation::ApplySafePreset => self
                .primary_button(self.tr("Lock safe preset", "切到安全预设"))
                .on_press(Message::ApplySecurityPreset(SecurityPreset::Safe)),
            SecurityRecommendation::ApplyBalancedPreset => self
                .primary_button(self.tr("Apply balanced plan", "应用平衡方案"))
                .on_press(Message::ApplySecurityPreset(SecurityPreset::Balanced)),
            SecurityRecommendation::DisableBridge => self
                .secondary_button(self.tr("Disable bridge", "关闭 bridge"))
                .on_press(Message::ApplyLocalBridgeQuickAction(
                    LocalBridgeQuickAction::Disable,
                )),
            SecurityRecommendation::SetLocalGateway => self
                .secondary_button(self.tr("Set local gateway", "切到本机网关"))
                .on_press(Message::ApplyGatewayPreset(GatewayPresetMode::LocalOnly)),
            SecurityRecommendation::RunGatewayHealthCheck => self
                .secondary_button(self.tr("Check gateway", "检查网关"))
                .on_press(Message::RunGatewayHealthCheck),
            SecurityRecommendation::RotateGatewayToken => self
                .secondary_button(self.tr("Rotate token", "轮换令牌"))
                .on_press(Message::RotateGatewayToken),
            SecurityRecommendation::OpenPermissions => self
                .secondary_button(self.tr("Open permissions", "打开权限"))
                .on_press(Message::OpenPath(
                    self.snapshot.context.security.permissions_path.clone(),
                )),
            SecurityRecommendation::OpenAuth => self
                .secondary_button(self.tr("Open auth", "打开凭据"))
                .on_press(Message::OpenPath(
                    self.snapshot.context.security.auth_path.clone(),
                )),
        }
    }

    fn sync_control_selection(&mut self) {
        let selected_exists = self
            .snapshot
            .context
            .systems
            .iter()
            .any(|system| system.id == self.selected_control_system_id);
        if !selected_exists
            && !self.snapshot.context.active_system_id.trim().is_empty()
            && (self.snapshot.context.systems.is_empty()
                || self
                    .snapshot
                    .context
                    .systems
                    .iter()
                    .any(|system| system.id == self.snapshot.context.active_system_id))
        {
            self.selected_control_system_id = self.snapshot.context.active_system_id.clone();
        }
        if self.selected_control_system_id.trim().is_empty() {
            self.selected_control_system_id = self
                .snapshot
                .context
                .systems
                .first()
                .map(|system| system.id.clone())
                .unwrap_or_else(|| self.snapshot.context.active_system_id.clone());
        }

        let selected_partition_exists = self
            .selected_control_workbench()
            .and_then(|system| {
                system
                    .memory_partition(self.selected_control_memory_partition)
                    .map(|_| ())
            })
            .is_some();
        if !selected_partition_exists {
            self.selected_control_memory_partition =
                crate::memory_v2::MemoryPartition::ProjectContext;
        }
    }

    fn selected_control_system_summary(&self) -> Option<&SystemSummary> {
        self.snapshot
            .context
            .systems
            .iter()
            .find(|system| system.id == self.selected_control_system_id)
            .or_else(|| self.snapshot.context.active_system())
    }

    fn selected_control_workbench(&self) -> Option<&ControlWorkbenchSystem> {
        self.snapshot
            .workbench
            .system(&self.selected_control_system_id)
            .or_else(|| {
                self.selected_control_system_summary()
                    .and_then(|system| self.snapshot.workbench.system(&system.id))
            })
    }

    fn active_chat_profile(&self) -> Option<&AgentProfileSummary> {
        let starter = self.effective_chat_agent_id();
        self.snapshot
            .context
            .agent_profile(starter)
            .or_else(|| self.snapshot.context.agent_profiles.first())
    }

    fn desktop_defaults_dirty(&self) -> bool {
        let defaults = &self.snapshot.context.defaults;
        infer_desktop_provider_preset_id(
            self.drafts.default_provider.trim(),
            Some(self.drafts.default_provider_preset.trim()),
        ) != infer_desktop_provider_preset_id(
            defaults.default_provider.trim(),
            Some(defaults.default_provider_preset.trim()),
        ) || self.drafts.default_provider.trim() != defaults.default_provider.trim()
            || self.drafts.default_model.trim() != defaults.default_model.trim()
            || self.drafts.default_base_url.trim() != defaults.default_base_url.trim()
            || self.drafts.starter_agent.trim() != defaults.starter_agent.trim()
            || self.drafts.desktop_language.trim() != defaults.desktop_language.trim()
            || self.drafts.desktop_theme.trim() != defaults.desktop_theme.trim()
            || self.drafts.check_for_updates != defaults.check_for_updates
            || !self.drafts.default_api_key_input.trim().is_empty()
    }

    fn local_bridge_dirty(&self) -> bool {
        let bridge = &self.snapshot.context.local_bridge;
        let draft_port = match self.drafts.local_bridge_port.trim() {
            "" => Some(crate::bridge::DEFAULT_BRIDGE_PORT),
            value => value.parse::<u16>().ok(),
        };
        self.drafts.local_bridge_enabled != bridge.enabled
            || draft_port != Some(bridge.port)
            || self.drafts.local_bridge_control_plane_url.trim() != bridge.control_plane_url.trim()
            || self.drafts.local_bridge_device_label.trim() != bridge.device_label.trim()
    }

    fn active_new_chat_target(&self) -> Option<RpcLaunchDefaults> {
        let profile = self.active_chat_profile();
        let provider = profile
            .filter(|profile| profile.mode_id == "override")
            .and_then(|profile| profile.provider.as_deref())
            .unwrap_or(self.effective_default_provider())
            .trim();
        let model = profile
            .filter(|profile| profile.mode_id == "override")
            .and_then(|profile| profile.model.as_deref())
            .unwrap_or(self.effective_default_model())
            .trim();
        if provider.is_empty() || model.is_empty() {
            return None;
        }
        Some(RpcLaunchDefaults {
            agent_profile: profile
                .map(|profile| profile.id.clone())
                .unwrap_or_else(|| "main".to_string()),
            provider: provider.to_string(),
            model: model.to_string(),
        })
    }

    fn effective_chat_agent_id(&self) -> &str {
        let focused = self.drafts.session_agent_focus.trim();
        if !focused.is_empty()
            && focused != ALL_AGENT_LANE_ID
            && focused != UNASSIGNED_AGENT_LANE_ID
            && self.snapshot.context.agent_profile(focused).is_some()
        {
            return focused;
        }
        self.effective_starter_agent_id()
    }

    fn effective_starter_agent_id(&self) -> &str {
        let starter = self.drafts.starter_agent.trim();
        if starter.is_empty() {
            self.snapshot.context.defaults.starter_agent.trim()
        } else {
            starter
        }
    }

    fn effective_default_provider(&self) -> &str {
        let provider = self.drafts.default_provider.trim();
        if provider.is_empty() {
            self.snapshot.context.defaults.default_provider.trim()
        } else {
            provider
        }
    }

    fn effective_default_provider_preset(&self) -> String {
        let draft_preset = self.drafts.default_provider_preset.trim();
        let snapshot_preset = self
            .snapshot
            .context
            .defaults
            .default_provider_preset
            .trim();
        let selected_preset = if draft_preset.is_empty() {
            snapshot_preset
        } else {
            draft_preset
        };
        infer_desktop_provider_preset_id(self.effective_default_provider(), Some(selected_preset))
    }

    fn effective_default_model(&self) -> &str {
        let model = self.drafts.default_model.trim();
        if model.is_empty() {
            self.snapshot.context.defaults.default_model.trim()
        } else {
            model
        }
    }

    fn effective_default_base_url_override(&self) -> &str {
        let provider_preset = self.effective_default_provider_preset();
        resolve_desktop_default_base_url(
            self.effective_default_provider(),
            &provider_preset,
            self.drafts.default_base_url.trim(),
            self.snapshot.context.defaults.default_provider.trim(),
            &self.snapshot.context.defaults.default_provider_preset,
            self.snapshot.context.defaults.default_base_url.trim(),
        )
    }

    fn resolved_fallback_api_url(&self) -> String {
        let provider_preset = self.effective_default_provider_preset();
        resolve_provider_base_url(
            self.effective_default_provider(),
            Some(&provider_preset),
            Some(self.effective_default_base_url_override()),
        )
        .unwrap_or_else(|| self.tr("Not configured", "未配置").to_string())
    }

    fn workspace_title(&self) -> String {
        infer_title_from_cwd(&self.snapshot.context.cwd, &self.snapshot.context.cwd)
    }

    fn provider_default_api_url(&self) -> String {
        let provider_preset = self.effective_default_provider_preset();
        provider_default_base_url(self.effective_default_provider(), Some(&provider_preset))
            .filter(|value| !value.trim().is_empty())
            .unwrap_or_else(|| {
                self.tr(
                    "Provider metadata has no default URL",
                    "当前 provider 没有内置默认地址",
                )
                .to_string()
            })
    }

    fn desktop_runtime_readiness_summary(&self) -> (ReadinessState, String) {
        let provider = self.effective_default_provider().trim();
        let provider_preset = self.effective_default_provider_preset();
        if provider.is_empty() {
            return (
                ReadinessState::Blocked,
                self.tr(
                    "Provider is missing. Use openai for third-party OpenAI-compatible operators.",
                    "Provider 为空。第三方 OpenAI 兼容运营商请填写 openai。",
                )
                .to_string(),
            );
        }

        let model = self.effective_default_model().trim();
        if model.is_empty() {
            return (
                ReadinessState::Blocked,
                self.tr(
                    "Model is missing. Fill the exact model id exposed by your operator.",
                    "Model 为空。请填写运营商实际提供的模型 ID。",
                )
                .to_string(),
            );
        }

        if let Err(err) = validate_provider_base_url(self.drafts.default_base_url.trim()) {
            return (ReadinessState::Blocked, err);
        }

        if provider_preset_requires_base_url(provider, Some(&provider_preset))
            && self.effective_default_base_url_override().trim().is_empty()
        {
            return (
                ReadinessState::Blocked,
                self.tr(
                    "Gateway URL is missing. Fill the operator URL before saving this route.",
                    "网关地址为空。请先填写运营商 URL，再保存这套路由。",
                )
                .to_string(),
            );
        }

        if self.desktop_defaults_dirty() {
            return (
                ReadinessState::Attention,
                self.tr(
                    "Runtime edits are not applied yet. Save to make new threads use this route.",
                    "运行时修改尚未生效。请先保存，新线程才会使用这套路由。",
                )
                .to_string(),
            );
        }

        if !desktop_provider_auth_ready(provider) {
            return (
                ReadinessState::Blocked,
                self.tr(
                    "API key is still missing for this provider. Paste a key and save.",
                    "这个 Provider 还没有可用 API Key。请粘贴密钥并保存。",
                )
                .to_string(),
            );
        }

        (
            ReadinessState::Ready,
            self.tr(
                "New threads can use main immediately with the saved provider, model, URL, and key.",
                "新线程已经可以直接使用 main 的已保存 provider、model、API URL 和密钥。",
            )
            .to_string(),
        )
    }

    fn desktop_model_suggestions(&self) -> Vec<String> {
        let provider_preset = self.effective_default_provider_preset();
        desktop_model_suggestions(self.effective_default_provider(), Some(&provider_preset))
    }

    fn readiness_chip(&self, state: ReadinessState) -> Container<'_, Message> {
        match state {
            ReadinessState::Ready => {
                self.status_chip_success(self.localized_readiness_label(state))
            }
            ReadinessState::Attention | ReadinessState::Blocked => {
                self.status_chip_warning(self.localized_readiness_label(state))
            }
        }
    }

    fn window_toolbar_panel(&self) -> Container<'_, Message> {
        let workspace_title = compact_middle(&self.workspace_title(), 22);
        let (runtime_state, _) = self.desktop_runtime_readiness_summary();
        let theme_toggle_target = if self.ui_theme_mode().is_dark() {
            DesktopThemeMode::Light
        } else {
            DesktopThemeMode::Dark
        };
        let focus_label = match self.active_tab {
            Tab::Chat => self
                .chat_target_session()
                .map(|session| compact_middle(&session.title, 26))
                .unwrap_or_else(|| self.tr("architect_session", "当前线程").to_string()),
            _ => self.localized_tab_label(self.active_tab).to_string(),
        };
        let breadcrumb = row![
            text(workspace_title)
                .font(self.ui_font())
                .size(11)
                .style(style::secondary_text()),
            text("/")
                .font(self.ui_font())
                .size(11)
                .style(style::secondary_text()),
            text(focus_label)
                .font(self.ui_font())
                .size(11)
                .style(style::heading_text()),
        ]
        .spacing(8)
        .align_items(alignment::Alignment::Center)
        .width(Length::Fill);
        let inspector_toggle = if self.active_tab == Tab::Chat {
            Some(
                self.inline_button(if self.chat_inspector_collapsed {
                    self.tr("Inspect", "详情")
                } else {
                    self.tr("Hide Inspector", "收起详情")
                })
                .on_press(Message::ToggleChatInspector),
            )
        } else {
            None
        };
        let mut actions = row![
            self.readiness_chip(runtime_state),
            self.status_chip(self.localized_heartbeat_label(self.snapshot.runtime.heartbeat)),
        ]
        .spacing(8)
        .align_items(alignment::Alignment::Center);
        if let Some(inspector_toggle) = inspector_toggle {
            actions = actions.push(inspector_toggle);
        }
        actions = actions
            .push(
                self.inline_button(self.localized_theme_mode_label(theme_toggle_target))
                    .on_press(Message::PersistDesktopTheme(
                        theme_toggle_target.code().to_string(),
                    )),
            )
            .push(
                self.inline_button(self.tr("Refresh", "刷新"))
                    .on_press(Message::RequestRefresh),
            )
            .push(
                self.inline_button(self.tr("Settings", "设置"))
                    .on_press(Message::SelectTab(Tab::Settings)),
            );

        container(
            row![breadcrumb, actions]
                .spacing(18)
                .align_items(alignment::Alignment::Center),
        )
        .padding([12, 20])
        .style(style::title_bar())
    }

