    fn provider_surface_inventory(&self) -> Vec<ProviderSurfaceSummary> {
        let mut providers: BTreeMap<String, BTreeSet<String>> = BTreeMap::new();
        let mut attach = |provider: &str, source: String| {
            let provider = canonical_provider_id(provider).unwrap_or(provider).trim();
            if provider.is_empty() {
                return;
            }
            providers
                .entry(provider.to_string())
                .or_default()
                .insert(source);
        };

        attach(
            &self.snapshot.context.defaults.default_provider,
            self.tr("Desktop default", "桌面默认").to_string(),
        );
        attach(
            &self.snapshot.context.onboarding.chosen_provider,
            self.tr("Onboarding", "Onboarding").to_string(),
        );
        for system in &self.snapshot.context.systems {
            if let Some(provider) = system.provider.as_deref() {
                attach(
                    provider,
                    self.tr("System runtime", "系统运行时").to_string(),
                );
            }
        }
        for profile in &self.snapshot.context.agent_profiles {
            if let Some(provider) = profile.provider.as_deref() {
                attach(provider, self.tr("Agent override", "分工覆盖").to_string());
            }
        }
        for session in &self.snapshot.sessions {
            if let Some(provider) = session.provider.as_deref() {
                attach(provider, self.tr("Session history", "会话历史").to_string());
            }
        }

        providers
            .into_iter()
            .map(|(provider_id, sources)| {
                let display_name = provider_metadata(&provider_id)
                    .and_then(|meta| meta.display_name)
                    .unwrap_or(provider_id.as_str())
                    .to_string();
                let route_summary = if let Some(base_url) =
                    load_provider_base_url_override_for_settings(&provider_id)
                {
                    let protocol = provider_routing_defaults(&provider_id)
                        .map(|defaults| defaults.api.to_string())
                        .unwrap_or_else(|| self.tr("custom route", "自定义路由").to_string());
                    self.tr(
                        &format!("{protocol} · override {}", compact_middle(&base_url, 34)),
                        &format!("{protocol} · 覆盖 {}", compact_middle(&base_url, 34)),
                    )
                    .to_string()
                } else if let Some(defaults) = provider_routing_defaults(&provider_id) {
                    format!(
                        "{} · {}",
                        defaults.api,
                        compact_middle(defaults.base_url, 34)
                    )
                } else {
                    self.tr(
                        "Adapter-managed / no built-in default route",
                        "适配器管理 / 没有内置默认路由",
                    )
                    .to_string()
                };
                let env_keys = if provider_auth_env_keys(&provider_id).is_empty() {
                    self.tr("No env fallback", "没有环境变量回退").to_string()
                } else {
                    provider_auth_env_keys(&provider_id).join(" / ")
                };

                ProviderSurfaceSummary {
                    id: provider_id.clone(),
                    display_name,
                    auth_ready: desktop_provider_auth_ready(&provider_id),
                    sources: sources.into_iter().collect(),
                    onboarding_mode: self.localized_provider_onboarding_mode(&provider_id),
                    route_summary,
                    env_keys,
                }
            })
            .collect()
    }

