    fn control_workbench_header_panel(&self) -> Container<'_, Message> {
        let selected_system = self.selected_control_system_summary();
        let system_name = selected_system
            .map(|system| system.name.clone())
            .unwrap_or_else(|| self.tr("No system selected", "当前没有系统").to_string());
        let workbench = self.selected_control_workbench();
        let section_buttons = ControlSection::all()
            .iter()
            .copied()
            .fold(row![].spacing(8), |row, section| {
                row.push(self.control_section_button(section))
            });
        let body = column![
            row![
                self.status_chip(self.tr("Control workbench", "控制台工作台")),
                selected_system.map_or_else(
                    || self.status_chip_warning(self.tr("System missing", "系统缺失")),
                    |system| {
                        if system.is_active {
                            self.status_chip_success(self.tr("Active system", "当前系统"))
                        } else {
                            self.status_chip(self.tr("Selected system", "已选系统"))
                        }
                    }
                ),
                self.status_chip(system_name),
                workbench.map_or_else(
                    || self.status_chip(self.tr("No V2 data", "暂无 V2 数据")),
                    |system| {
                        self.status_chip(self.tr(
                            &format!("{} snapshots", system.vault_snapshots.len()),
                            &format!("{} 个快照", system.vault_snapshots.len()),
                        ))
                    }
                ),
                workbench.map_or_else(
                    || self.status_chip(self.tr("0 artifacts", "0 份证据")),
                    |system| {
                        self.status_chip(self.tr(
                            &format!("{} artifacts", system.artifacts.len()),
                            &format!("{} 份证据", system.artifacts.len()),
                        ))
                    }
                ),
                workbench.map_or_else(
                    || self.status_chip(self.tr("0 memory", "0 条记忆")),
                    |system| {
                        self.status_chip(self.tr(
                            &format!("{} memory", system.total_memory_entries()),
                            &format!("{} 条记忆", system.total_memory_entries()),
                        ))
                    }
                ),
                workbench.map_or_else(
                    || self.status_chip(self.tr("0 automations", "0 个自动化")),
                    |system| {
                        self.status_chip(self.tr(
                            &format!("{} automations", system.enabled_automation_count()),
                            &format!("{} 个自动化", system.enabled_automation_count()),
                        ))
                    }
                ),
            ]
            .spacing(8)
            .wrap(),
            text(self.localized_control_section_description(self.active_control_section))
                .font(self.ui_font())
                .size(12)
                .style(style::secondary_text()),
            section_buttons,
            row![
                self.secondary_button(self.tr("Open vault", "打开 Vault"))
                    .on_press(Message::OpenPath(
                        self.snapshot.context.vault_root_path.clone()
                    )),
                self.secondary_button(self.tr("Open artifacts", "打开证据"))
                    .on_press(Message::OpenPath(
                        self.snapshot.context.artifact_library_path.clone()
                    )),
                self.secondary_button(self.tr("Open control state", "打开控制台状态"))
                    .on_press(Message::OpenPath(
                        self.snapshot.context.control_plane_state_path.clone()
                    )),
                self.secondary_button(self.tr("Project settings", "项目设置"))
                    .on_press(Message::OpenPath(
                        self.snapshot.context.project_settings_path.clone()
                    )),
            ]
            .spacing(10),
        ]
        .spacing(12);

        self.panel_shell_with_subtitle(
            self.tr("Control workbench", "控制台工作台"),
            Some(self.tr(
                "Systems / Vault / Artifacts / Memory / Automations",
                "系统 / Vault / 证据 / 记忆 / 自动化",
            )),
            body,
        )
    }

