    fn system_cultivation_panel(&self) -> Container<'_, Message> {
        let Some(system) = self.selected_control_system_summary() else {
            return self.surface_card(
                self.tr("System cultivation", "系统养成"),
                self.tr(
                    "No visible SystemProfile is indexed yet. The desktop is still operating like a session shell.",
                    "当前还没有可见的 SystemProfile。桌面仍然更像会话壳层，而不是系统工作台。",
                ),
            );
        };

        let description = if system.description.trim().is_empty() {
            if system.is_fallback {
                self.tr(
                    "Fallback system synthesized from desktop defaults until a persisted profile is created.",
                    "当前系统由桌面默认值临时合成，等持久化 SystemProfile 创建后会替换。",
                )
                .to_string()
            } else {
                self.tr(
                    "This system has no description yet. Add one in settings.json to clarify its operating intent.",
                    "这个系统还没有描述。可以在 settings.json 中补充其运行意图。",
                )
                .to_string()
            }
        } else {
            system.description.clone()
        };

        let top_roles = if system.top_roles.is_empty() {
            self.tr("No role blueprint yet", "当前还没有角色蓝图")
                .to_string()
        } else {
            system.top_roles.join(" · ")
        };
        let lineage_baseline = system
            .baseline_snapshot_id
            .as_deref()
            .map(|value| compact_middle(value, 24))
            .unwrap_or_else(|| self.tr("Not snapshotted", "尚未快照").to_string());
        let lineage_active = system
            .active_snapshot_id
            .as_deref()
            .map(|value| compact_middle(value, 24))
            .unwrap_or_else(|| self.tr("No active snapshot", "没有当前快照").to_string());
        let lineage_branch = system
            .current_branch_id
            .as_deref()
            .map(|value| compact_middle(value, 24))
            .unwrap_or_else(|| self.tr("Main branch", "主分支").to_string());

        let body = column![
            row![
                self.status_chip(self.localized_system_status_label(&system.status)),
                self.status_chip(system.template_type.clone()),
                if system.id == self.snapshot.context.active_system_id {
                    self.status_chip_success(self.tr("Active runtime", "当前运行系统"))
                } else {
                    self.status_chip(self.tr("Inspection focus", "当前查看"))
                },
                self.status_chip(if system.is_fallback {
                    self.tr("Fallback runtime", "回退系统")
                } else {
                    self.tr("Persisted profile", "持久化系统")
                }),
            ]
            .spacing(8)
            .wrap(),
            text(&description)
                .font(self.ui_font())
                .size(12)
                .style(style::secondary_text()),
            row![
                self.detail_row(
                    self.tr("Selected system", "当前查看系统"),
                    format!("{} · {}", system.name, compact_middle(&system.id, 22)),
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Runtime", "运行时"),
                    self.system_runtime_label(system),
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            row![
                self.detail_row(
                    self.tr("Team blueprint", "团队蓝图"),
                    format!("{} roles · {}", system.role_count, top_roles),
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Memory strategy", "记忆策略"),
                    self.tr(
                        &format!(
                            "{} / {} buckets enabled",
                            system.enabled_memory_count, system.total_memory_count
                        ),
                        &format!(
                            "{} / {} 个记忆桶启用",
                            system.enabled_memory_count, system.total_memory_count
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            row![
                self.detail_row(
                    self.tr("Routing", "路由"),
                    format!(
                        "{} · {}",
                        system.default_role.as_deref().unwrap_or_else(|| {
                            self.tr("No default role", "没有默认角色")
                        }),
                        self.tr(
                            &format!("{} task mappings", system.task_route_count),
                            &format!("{} 条任务映射", system.task_route_count),
                        )
                    ),
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Permissions", "权限策略"),
                    system.permission_summary.clone(),
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            row![
                self.detail_row(
                    self.tr("Catalog", "目录能力"),
                    self.tr(
                        &format!(
                            "{} skills · {} prompts",
                            system.skill_count, system.prompt_count
                        ),
                        &format!(
                            "{} 个技能 · {} 条提示",
                            system.skill_count, system.prompt_count
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Registry source", "注册表来源"),
                    if system.is_fallback {
                        self.tr(
                            "Synthesized from desktop defaults + project state",
                            "由桌面默认值和项目状态临时合成",
                        )
                        .to_string()
                    } else {
                        self.tr(
                            "Persisted in project settings systems[]",
                            "持久化在项目设置的 systems[] 中",
                        )
                        .to_string()
                    },
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            row![
                self.detail_row(
                    self.tr("Cultivation state", "养成状态"),
                    self.tr(
                        &format!(
                            "{} artifacts · {} snapshots · {} branches",
                            system.artifact_count, system.snapshot_count, system.branch_count
                        ),
                        &format!(
                            "{} 份证据 · {} 个快照 · {} 条分支",
                            system.artifact_count, system.snapshot_count, system.branch_count
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Bindings / automations", "接入 / 自动化"),
                    format!(
                        "{} · {}",
                        self.tr(
                            &format!("{} bindings", system.binding_count),
                            &format!("{} 个接入", system.binding_count),
                        ),
                        self.tr(
                            &format!("{} automations", system.automation_count),
                            &format!("{} 个自动化", system.automation_count),
                        )
                    ),
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            row![
                self.compact_detail_row(self.tr("Baseline", "基线快照"), lineage_baseline),
                self.compact_detail_row(self.tr("Active snapshot", "当前快照"), lineage_active),
                self.compact_detail_row(self.tr("Branch", "分支"), lineage_branch),
            ]
            .spacing(10),
            row![
                self.secondary_button(self.tr("Open project settings", "打开项目设置"))
                    .on_press(Message::OpenPath(
                        self.snapshot.context.project_settings_path.clone()
                    )),
                if system.id != self.snapshot.context.active_system_id {
                    self.secondary_button(self.tr("Show active system", "查看当前运行系统"))
                        .on_press(Message::SelectControlSystem(
                            self.snapshot.context.active_system_id.clone(),
                        ))
                } else {
                    self.secondary_button(self.tr("Control overview", "控制台总览"))
                        .on_press(Message::SelectControlSection(ControlSection::Overview))
                },
                self.secondary_button(self.tr("Open vault", "打开 Vault"))
                    .on_press(Message::OpenPath(
                        self.snapshot.context.vault_root_path.clone()
                    )),
                self.secondary_button(self.tr("Open artifacts", "打开证据"))
                    .on_press(Message::OpenPath(
                        self.snapshot.context.artifact_library_path.clone()
                    )),
            ]
            .spacing(10),
        ]
        .spacing(12);

        self.panel_shell_with_subtitle(
            self.tr("System cultivation", "系统养成"),
            Some(self.tr("System / Memory / Vault", "系统 / 记忆 / Vault")),
            body,
        )
    }

    fn system_registry_panel(&self) -> Container<'_, Message> {
        if self.snapshot.context.systems.is_empty() {
            return self.surface_card(
                self.tr("System registry", "系统注册表"),
                self.tr("No systems are indexed yet.", "当前还没有可索引的系统。"),
            );
        }

        let persisted_count = self
            .snapshot
            .context
            .systems
            .iter()
            .filter(|system| !system.is_fallback)
            .count();
        let fallback_count = self
            .snapshot
            .context
            .systems
            .iter()
            .filter(|system| system.is_fallback)
            .count();
        let rows = self.snapshot.context.systems.iter().take(5).fold(
            Column::new()
                .spacing(10)
                .push(
                    row![
                        self.status_chip(self.tr(
                            &format!("{} total", self.snapshot.context.systems.len()),
                            &format!("{} 个系统", self.snapshot.context.systems.len()),
                        )),
                        self.status_chip(self.tr(
                            &format!("{persisted_count} persisted"),
                            &format!("{persisted_count} 个持久化"),
                        )),
                        self.status_chip(self.tr(
                            &format!("{fallback_count} fallback"),
                            &format!("{fallback_count} 个回退"),
                        )),
                    ]
                    .spacing(8)
                    .wrap(),
                )
                .push(self.detail_row(
                    self.tr("Config authority", "配置来源"),
                    self.tr(
                        &format!(
                            "active_system_id={} · {}",
                            compact_middle(&self.snapshot.context.active_system_id, 22),
                            compact_middle(&self.snapshot.context.project_settings_path, 32)
                        ),
                        &format!(
                            "active_system_id={} · {}",
                            compact_middle(&self.snapshot.context.active_system_id, 22),
                            compact_middle(&self.snapshot.context.project_settings_path, 32)
                        ),
                    ),
                )),
            |column, system| {
                let is_selected = self.selected_control_system_id == system.id;
                column.push(
                    container(
                        column![
                            row![
                                column![
                                    text(&system.name)
                                        .font(self.ui_font())
                                        .size(14)
                                        .style(style::heading_text()),
                                    text(format!(
                                        "{} · {}",
                                        compact_middle(&system.id, 24),
                                        self.system_runtime_label(system),
                                    ))
                                    .font(self.ui_font())
                                    .size(12)
                                    .style(style::secondary_text()),
                                ]
                                .spacing(4)
                                .width(Length::Fill),
                                self.status_chip(
                                    self.localized_system_status_label(&system.status)
                                ),
                                if is_selected {
                                    self.status_chip(self.tr("Selected", "已选"))
                                } else {
                                    self.status_chip(self.tr("Browse", "浏览"))
                                },
                                if system.is_active {
                                    self.status_chip_success(self.tr("Active", "当前"))
                                } else {
                                    self.status_chip(self.tr("Available", "可用"))
                                },
                            ]
                            .spacing(8)
                            .align_items(alignment::Alignment::Start),
                            row![
                                self.compact_detail_row(
                                    self.tr("Template", "模板"),
                                    system.template_type.clone(),
                                ),
                                self.compact_detail_row(
                                    self.tr("Team", "团队"),
                                    self.tr(
                                        &format!("{} roles", system.role_count),
                                        &format!("{} 个角色", system.role_count),
                                    ),
                                ),
                                self.compact_detail_row(
                                    self.tr("Memory", "记忆"),
                                    self.tr(
                                        &format!(
                                            "{}/{} enabled",
                                            system.enabled_memory_count, system.total_memory_count
                                        ),
                                        &format!(
                                            "{}/{} 启用",
                                            system.enabled_memory_count, system.total_memory_count
                                        ),
                                    ),
                                ),
                            ]
                            .spacing(10),
                            row![
                                self.compact_detail_row(
                                    self.tr("Vault", "Vault"),
                                    self.tr(
                                        &format!(
                                            "{} snapshots · {} branches",
                                            system.snapshot_count, system.branch_count
                                        ),
                                        &format!(
                                            "{} 快照 · {} 分支",
                                            system.snapshot_count, system.branch_count
                                        ),
                                    ),
                                ),
                                self.compact_detail_row(
                                    self.tr("Evidence", "证据"),
                                    self.tr(
                                        &format!("{} artifacts", system.artifact_count),
                                        &format!("{} 份证据", system.artifact_count),
                                    ),
                                ),
                                self.compact_detail_row(
                                    self.tr("Updated", "更新时间"),
                                    system
                                        .updated_at
                                        .clone()
                                        .unwrap_or_else(|| self.tr("Unknown", "未知").to_string()),
                                ),
                            ]
                            .spacing(10),
                            row![
                                if is_selected {
                                    self.primary_button(self.tr("Inspecting", "查看中"))
                                } else {
                                    self.secondary_button(self.tr("Inspect", "查看"))
                                }
                                .on_press(Message::SelectControlSystem(system.id.clone())),
                                self.inline_button(self.tr("Vault", "Vault"))
                                    .on_press(Message::SelectControlSection(ControlSection::Vault)),
                                self.inline_button(self.tr("Artifacts", "证据")).on_press(
                                    Message::SelectControlSection(ControlSection::Artifacts)
                                ),
                            ]
                            .spacing(10),
                        ]
                        .spacing(8),
                    )
                    .padding([12, 14])
                    .style(style::subtle_card()),
                )
            },
        );

        self.panel_shell_with_subtitle(
            self.tr("System registry", "系统注册表"),
            Some(self.tr("Portable work systems", "可迁移工作系统")),
            rows,
        )
    }

    fn control_vault_summary_panel(&self) -> Container<'_, Message> {
        let Some(system) = self.selected_control_system_summary() else {
            return self.surface_card(
                self.tr("Vault posture", "Vault 状态"),
                self.tr("Select a system first.", "请先选择一个系统。"),
            );
        };
        let Some(workbench) = self.selected_control_workbench() else {
            return self.surface_card(
                self.tr("Vault posture", "Vault 状态"),
                self.tr(
                    "No workbench data is available for the selected system yet.",
                    "当前选中系统还没有可用的工作台数据。",
                ),
            );
        };

        let latest_snapshot = workbench
            .vault_snapshots
            .first()
            .map(|snapshot| snapshot.display_label())
            .unwrap_or_else(|| self.tr("No snapshots yet", "还没有快照").to_string());
        let latest_branch = workbench
            .vault_branches
            .iter()
            .find(|branch| branch.is_active)
            .map(|branch| branch.name.clone())
            .or_else(|| {
                workbench
                    .vault_branches
                    .first()
                    .map(|branch| branch.name.clone())
            })
            .unwrap_or_else(|| self.tr("Main branch", "主分支").to_string());

        let body = column![
            row![
                self.status_chip(self.tr(
                    &format!("{} snapshots", workbench.vault_snapshots.len()),
                    &format!("{} 个快照", workbench.vault_snapshots.len()),
                )),
                self.status_chip(self.tr(
                    &format!("{} branches", workbench.vault_branches.len()),
                    &format!("{} 条分支", workbench.vault_branches.len()),
                )),
                if system.has_baseline {
                    self.status_chip_success(self.tr("Baseline sealed", "已有基线"))
                } else {
                    self.status_chip_warning(self.tr("Baseline missing", "还没有基线"))
                },
            ]
            .spacing(8)
            .wrap(),
            self.detail_row(self.tr("Latest snapshot", "最近快照"), latest_snapshot,),
            self.detail_row(self.tr("Branch focus", "当前分支"), latest_branch),
            self.detail_row(
                self.tr("Vault root", "Vault 根目录"),
                self.snapshot.context.vault_root_path.clone(),
            ),
            row![
                self.secondary_button(self.tr("Open vault root", "打开 Vault 根目录"))
                    .on_press(Message::OpenPath(
                        self.snapshot.context.vault_root_path.clone()
                    )),
                self.secondary_button(self.tr("Browse snapshots", "浏览快照"))
                    .on_press(Message::SelectControlSection(ControlSection::Vault)),
            ]
            .spacing(10),
        ]
        .spacing(12);

        self.panel_shell_with_subtitle(
            self.tr("Vault posture", "Vault 状态"),
            Some(self.tr("Recoverable system state", "可恢复系统状态")),
            body,
        )
    }

    fn control_memory_summary_panel(&self) -> Container<'_, Message> {
        let Some(workbench) = self.selected_control_workbench() else {
            return self.surface_card(
                self.tr("Memory posture", "记忆状态"),
                self.tr(
                    "No partitioned memory is indexed for the selected system yet.",
                    "当前选中系统还没有被索引的分区记忆。",
                ),
            );
        };
        let populated_partitions = workbench
            .memory_partitions
            .iter()
            .filter(|partition| !partition.entries.is_empty())
            .count();
        let frozen_entries = workbench
            .memory_partitions
            .iter()
            .map(|partition| partition.frozen_count)
            .sum::<usize>();
        let last_ingest = workbench
            .memory_partitions
            .iter()
            .filter_map(|partition| partition.last_ingest_at.clone())
            .max()
            .unwrap_or_else(|| {
                self.tr("No retained memory yet", "还没有保留记忆")
                    .to_string()
            });

        let body = column![
            row![
                self.status_chip(self.tr(
                    &format!("{} partitions", workbench.memory_partitions.len()),
                    &format!("{} 个分区", workbench.memory_partitions.len()),
                )),
                self.status_chip(self.tr(
                    &format!("{} populated", populated_partitions),
                    &format!("{} 个有内容", populated_partitions),
                )),
                self.status_chip(self.tr(
                    &format!("{frozen_entries} frozen"),
                    &format!("{frozen_entries} 个冻结"),
                )),
            ]
            .spacing(8)
            .wrap(),
            self.detail_row(
                self.tr("Retained entries", "保留条目"),
                self.tr(
                    &format!("{}", workbench.total_memory_entries()),
                    &format!("{}", workbench.total_memory_entries()),
                ),
            ),
            self.detail_row(self.tr("Latest ingest", "最近写入"), last_ingest),
            self.secondary_button(self.tr("Open memory partitions", "打开记忆分区"))
                .on_press(Message::SelectControlSection(ControlSection::Memory)),
        ]
        .spacing(12);

        self.panel_shell_with_subtitle(
            self.tr("Memory posture", "记忆状态"),
            Some(self.tr("Partitioned retention", "分区保留")),
            body,
        )
    }

    fn control_vault_snapshot_panel(&self) -> Container<'_, Message> {
        let Some(workbench) = self.selected_control_workbench() else {
            return self.surface_card(
                self.tr("Vault snapshots", "Vault 快照"),
                self.tr("No selected system is available.", "当前没有可用系统。"),
            );
        };
        if workbench.vault_snapshots.is_empty() {
            return self.surface_card(
                self.tr("Vault snapshots", "Vault 快照"),
                self.tr(
                    "No snapshots have been saved for this system yet.",
                    "这个系统还没有保存过快照。",
                ),
            );
        }

        let rows = workbench.vault_snapshots.iter().take(6).fold(
            Column::new().spacing(10),
            |column, snapshot| {
                let runtime = format_runtime_label(
                    snapshot.system.provider.as_deref().unwrap_or_default(),
                    snapshot.system.model.as_deref().unwrap_or_default(),
                )
                .unwrap_or_else(|| {
                    self.tr("Follows system defaults", "跟随系统默认")
                        .to_string()
                });
                column.push(
                    container(
                        column![
                            row![
                                column![
                                    text(snapshot.display_label())
                                        .font(self.ui_font())
                                        .size(14)
                                        .style(style::heading_text()),
                                    text(format!(
                                        "{} · {}",
                                        snapshot.kind.label(),
                                        snapshot.created_at
                                    ))
                                    .font(self.ui_font())
                                    .size(12)
                                    .style(style::secondary_text()),
                                ]
                                .spacing(4)
                                .width(Length::Fill),
                                if snapshot.system.active_snapshot_id.as_deref()
                                    == Some(snapshot.id.as_str())
                                {
                                    self.status_chip_success(self.tr("Active", "当前"))
                                } else {
                                    self.status_chip(self.tr("Stored", "已存档"))
                                },
                            ]
                            .spacing(8)
                            .align_items(alignment::Alignment::Center),
                            row![
                                self.compact_detail_row(self.tr("Runtime", "运行时"), runtime,),
                                self.compact_detail_row(
                                    self.tr("Roles", "角色"),
                                    self.tr(
                                        &format!("{} roles", snapshot.system.role_count()),
                                        &format!("{} 个角色", snapshot.system.role_count()),
                                    ),
                                ),
                                self.compact_detail_row(
                                    self.tr("Bindings", "接入"),
                                    self.tr(
                                        &format!("{} bindings", snapshot.system.bindings.len()),
                                        &format!("{} 个接入", snapshot.system.bindings.len()),
                                    ),
                                ),
                            ]
                            .spacing(10),
                        ]
                        .spacing(8),
                    )
                    .padding([12, 14])
                    .style(style::subtle_card()),
                )
            },
        );

        self.panel_shell_with_subtitle(
            self.tr("Vault snapshots", "Vault 快照"),
            Some(self.tr("Newest first", "按最新排序")),
            rows,
        )
    }

    fn control_vault_branch_panel(&self) -> Container<'_, Message> {
        let Some(workbench) = self.selected_control_workbench() else {
            return self.surface_card(
                self.tr("Vault branches", "Vault 分支"),
                self.tr("No selected system is available.", "当前没有可用系统。"),
            );
        };
        if workbench.vault_branches.is_empty() {
            return self.surface_card(
                self.tr("Vault branches", "Vault 分支"),
                self.tr(
                    "No experimental branches are tracked for this system yet.",
                    "这个系统还没有被追踪的实验分支。",
                ),
            );
        }

        let rows = workbench.vault_branches.iter().take(6).fold(
            Column::new().spacing(10),
            |column, branch| {
                column.push(
                    container(
                        column![
                            row![
                                column![
                                    text(&branch.name)
                                        .font(self.ui_font())
                                        .size(14)
                                        .style(style::heading_text()),
                                    text(format!(
                                        "{} · {}",
                                        compact_middle(&branch.id, 24),
                                        branch.created_at
                                    ))
                                    .font(self.ui_font())
                                    .size(12)
                                    .style(style::secondary_text()),
                                ]
                                .spacing(4)
                                .width(Length::Fill),
                                if branch.is_active {
                                    self.status_chip_success(self.tr("Active", "当前"))
                                } else {
                                    self.status_chip(self.tr("Standby", "待命"))
                                },
                            ]
                            .spacing(8)
                            .align_items(alignment::Alignment::Center),
                            self.detail_row(
                                self.tr("Parent snapshot", "父快照"),
                                compact_middle(&branch.parent_snapshot_id, 26),
                            ),
                        ]
                        .spacing(8),
                    )
                    .padding([12, 14])
                    .style(style::subtle_card()),
                )
            },
        );

        self.panel_shell_with_subtitle(
            self.tr("Vault branches", "Vault 分支"),
            Some(self.tr("Experiment lanes", "实验分支")),
            rows,
        )
    }

    fn control_artifact_library_panel(&self) -> Container<'_, Message> {
        let Some(workbench) = self.selected_control_workbench() else {
            return self.surface_card(
                self.tr("Artifact library", "证据库"),
                self.tr("No selected system is available.", "当前没有可用系统。"),
            );
        };
        if workbench.artifacts.is_empty() {
            return self.surface_card(
                self.tr("Artifact library", "证据库"),
                self.tr(
                    "No durable artifacts have been written for this system yet.",
                    "这个系统还没有 durable artifact。",
                ),
            );
        }

        let cwd = Path::new(&self.snapshot.context.cwd).to_path_buf();
        let rows = workbench.artifacts.iter().take(6).fold(
            Column::new().spacing(10),
            |column, artifact| {
                let artifact_path = cwd
                    .join(".pi")
                    .join("artifacts")
                    .join(&artifact.system_id)
                    .join(format!("{}.json", artifact.id));
                let status_label = artifact.status.label().replace('_', " ");
                let tags = if artifact.tags.is_empty() {
                    self.tr("No tags", "没有标签").to_string()
                } else {
                    artifact
                        .tags
                        .iter()
                        .take(3)
                        .cloned()
                        .collect::<Vec<_>>()
                        .join(" · ")
                };
                column.push(
                    container(
                        column![
                            row![
                                column![
                                    text(&artifact.task_summary)
                                        .font(self.ui_font())
                                        .size(14)
                                        .style(style::heading_text()),
                                    text(format!(
                                        "{} · {}",
                                        compact_middle(&artifact.id, 24),
                                        artifact.updated_at
                                    ))
                                    .font(self.ui_font())
                                    .size(12)
                                    .style(style::secondary_text()),
                                ]
                                .spacing(4)
                                .width(Length::Fill),
                                if artifact.status.is_actionable() {
                                    self.status_chip_success(status_label)
                                } else {
                                    self.status_chip(status_label)
                                },
                            ]
                            .spacing(8)
                            .align_items(alignment::Alignment::Center),
                            row![
                                self.compact_detail_row(
                                    self.tr("Type", "类型"),
                                    if artifact.artifact_type.trim().is_empty() {
                                        artifact.schema.clone().unwrap_or_else(|| {
                                            self.tr("unspecified", "未指定").to_string()
                                        })
                                    } else {
                                        artifact.artifact_type.clone()
                                    },
                                ),
                                self.compact_detail_row(
                                    self.tr("Deliverables", "交付物"),
                                    self.tr(
                                        &format!("{}", artifact.deliverables.len()),
                                        &format!("{}", artifact.deliverables.len()),
                                    ),
                                ),
                                self.compact_detail_row(
                                    self.tr("Evidence", "证据"),
                                    self.tr(
                                        &format!("{}", artifact.evidence.len()),
                                        &format!("{}", artifact.evidence.len()),
                                    ),
                                ),
                            ]
                            .spacing(10),
                            self.detail_row(self.tr("Tags", "标签"), tags),
                            row![
                                self.secondary_button(self.tr("Open artifact", "打开证据"))
                                    .on_press(Message::OpenPath(
                                        artifact_path.display().to_string()
                                    )),
                                self.inline_button(self.tr("Library root", "证据库根目录"))
                                    .on_press(Message::OpenPath(
                                        self.snapshot.context.artifact_library_path.clone()
                                    )),
                            ]
                            .spacing(10),
                        ]
                        .spacing(8),
                    )
                    .padding([12, 14])
                    .style(style::subtle_card()),
                )
            },
        );

        self.panel_shell_with_subtitle(
            self.tr("Artifact library", "证据库"),
            Some(self.tr("Durable result pages", "持久化结果页")),
            rows,
        )
    }

    fn control_artifact_delivery_panel(&self) -> Container<'_, Message> {
        let Some(workbench) = self.selected_control_workbench() else {
            return self.surface_card(
                self.tr("Artifact spotlight", "证据聚焦"),
                self.tr("No selected system is available.", "当前没有可用系统。"),
            );
        };
        let Some(artifact) = workbench.artifacts.first() else {
            return self.surface_card(
                self.tr("Artifact spotlight", "证据聚焦"),
                self.tr(
                    "The latest durable artifact will appear here once one is written.",
                    "有 durable artifact 以后，这里会展示最近的一份。",
                ),
            );
        };

        let deliverables = if artifact.deliverables.is_empty() {
            Column::new().push(
                text(self.tr("No deliverables attached.", "还没有附带交付物。"))
                    .font(self.ui_font())
                    .size(12)
                    .style(style::secondary_text()),
            )
        } else {
            artifact.deliverables.iter().take(4).fold(
                Column::new().spacing(8),
                |column, deliverable| {
                    let path_label = deliverable
                        .path
                        .as_deref()
                        .map(|path| display_path_label(Path::new(path)))
                        .unwrap_or_else(|| self.tr("Inline content", "内联内容").to_string());
                    column.push(
                        container(
                            column![
                                text(&deliverable.title)
                                    .font(self.ui_font())
                                    .size(13)
                                    .style(style::heading_text()),
                                text(path_label)
                                    .font(self.ui_font())
                                    .size(11)
                                    .style(style::secondary_text()),
                            ]
                            .spacing(4),
                        )
                        .padding([10, 12])
                        .style(style::subtle_card()),
                    )
                },
            )
        };

        let body = column![
            row![
                self.status_chip(artifact.status.label().replace('_', " ")),
                self.status_chip(if artifact.artifact_type.trim().is_empty() {
                    artifact.schema.clone().unwrap_or_default()
                } else {
                    artifact.artifact_type.clone()
                }),
            ]
            .spacing(8)
            .wrap(),
            self.detail_row(
                self.tr("Latest artifact", "最近证据"),
                artifact.task_summary.clone()
            ),
            self.detail_row(self.tr("Updated", "更新时间"), artifact.updated_at.clone(),),
            self.detail_row(
                self.tr("Next steps", "下一步"),
                self.tr(
                    &format!("{}", artifact.next_steps.len()),
                    &format!("{}", artifact.next_steps.len()),
                ),
            ),
            deliverables,
        ]
        .spacing(12);

        self.panel_shell_with_subtitle(
            self.tr("Artifact spotlight", "证据聚焦"),
            Some(self.tr("Latest durable output", "最近的持久化输出")),
            body,
        )
    }

    fn control_memory_partition_panel(&self) -> Container<'_, Message> {
        let Some(workbench) = self.selected_control_workbench() else {
            return self.surface_card(
                self.tr("Memory partitions", "记忆分区"),
                self.tr("No selected system is available.", "当前没有可用系统。"),
            );
        };

        let rows = workbench.memory_partitions.iter().fold(
            Column::new().spacing(8),
            |column, partition| {
                let active = partition.partition == self.selected_control_memory_partition;
                column.push(
                    button(
                        row![
                            column![
                                text(partition.partition.label())
                                    .font(self.ui_font())
                                    .size(12)
                                    .style(if active {
                                        style::heading_text()
                                    } else {
                                        style::button_text()
                                    }),
                                text(partition.last_ingest_at.clone().unwrap_or_else(|| {
                                    self.tr("No entries yet", "还没有条目").to_string()
                                }))
                                .font(self.ui_font())
                                .size(10)
                                .style(style::secondary_text()),
                            ]
                            .spacing(3)
                            .width(Length::Fill),
                            self.status_chip(self.tr(
                                &format!("{}", partition.entries.len()),
                                &format!("{}", partition.entries.len()),
                            )),
                        ]
                        .align_items(alignment::Alignment::Center),
                    )
                    .padding([10, 12])
                    .style(if active {
                        style::ButtonStyle::PanelActive
                    } else {
                        style::ButtonStyle::Secondary
                    })
                    .on_press(Message::SelectControlMemoryPartition(partition.partition)),
                )
            },
        );

        self.panel_shell_with_subtitle(
            self.tr("Memory partitions", "记忆分区"),
            Some(self.tr("Choose a partition", "选择一个分区")),
            rows,
        )
    }

    fn memory_tiers_panel(&self) -> Container<'_, Message> {
        let Some(workbench) = self.selected_control_workbench() else {
            return self.surface_card(
                self.tr("Memory tiers", "记忆层级"),
                self.tr("No selected system is available.", "当前没有可用系统。"),
            );
        };

        let context = &self.snapshot.context;
        let runtime_memory_root = Path::new(&context.cwd)
            .join(".pi")
            .join("memory")
            .join(&workbench.system_id)
            .display()
            .to_string();
        let durable_ready = context.workspace_memory_exists && context.workspace_heartbeat_exists;
        let daily_root_exists = Path::new(&context.workspace_daily_memory_root).is_dir();
        let retained_count = workbench.total_memory_entries();
        let frozen_count = workbench.frozen_memory_entries();
        let populated_partition_count = workbench.populated_memory_partition_count();
        let active_partition_focus = workbench
            .memory_partition(self.selected_control_memory_partition)
            .map(|partition| {
                self.tr(
                    &format!(
                        "{} · {} entries · {} frozen",
                        partition.partition.label(),
                        partition.entries.len(),
                        partition.frozen_count
                    ),
                    &format!(
                        "{} · {} 条记录 · {} 条冻结",
                        partition.partition.label(),
                        partition.entries.len(),
                        partition.frozen_count
                    ),
                )
                .to_string()
            })
            .unwrap_or_else(|| {
                self.tr("No partition selected", "当前没有选中的分区")
                    .to_string()
            });

        let durable_tier = container(
            column![
                row![
                    column![
                        text(self.tr("Durable doctrine", "持久准则"))
                            .font(self.ui_font())
                            .size(13)
                            .style(style::heading_text()),
                        text(self.tr(
                            "AGENTS.md, MEMORY.md, and HEARTBEAT.md define the operator rules that survive restarts.",
                            "AGENTS.md、MEMORY.md 和 HEARTBEAT.md 定义了跨重启保留的运行准则。",
                        ))
                        .font(self.ui_font())
                        .size(11)
                        .line_height(LineHeight::Relative(1.2))
                        .style(style::secondary_text()),
                    ]
                    .spacing(4)
                    .width(Length::Fill),
                    if durable_ready {
                        self.status_chip_success(self.tr("Ready", "就绪"))
                    } else {
                        self.status_chip_warning(self.tr("Incomplete", "不完整"))
                    },
                    if context.workspace_memory_exists {
                        self.inline_button(self.tr("Open MEMORY", "打开 MEMORY"))
                            .on_press(Message::OpenPath(context.workspace_memory_path.clone()))
                    } else {
                        self.inline_button(self.tr("Open workspace", "打开工作区"))
                            .on_press(Message::OpenPath(context.cwd.clone()))
                    },
                ]
                .spacing(8)
                .align_items(alignment::Alignment::Center),
                row![
                    self.compact_detail_row(
                        self.tr("Files", "文件"),
                        context.doctrine_file_count().to_string(),
                    ),
                    self.compact_detail_row(
                        self.tr("MEMORY", "MEMORY"),
                        if context.workspace_memory_exists {
                            self.tr("present", "已存在").to_string()
                        } else {
                            self.tr("missing", "缺失").to_string()
                        },
                    ),
                    self.compact_detail_row(
                        self.tr("HEARTBEAT", "HEARTBEAT"),
                        if context.workspace_heartbeat_exists {
                            self.tr("present", "已存在").to_string()
                        } else {
                            self.tr("missing", "缺失").to_string()
                        },
                    ),
                ]
                .spacing(10)
                .wrap(),
            ]
            .spacing(10),
        )
        .padding([12, 14])
        .style(style::subtle_card());

        let daily_tier = container(
            column![
                row![
                    column![
                        text(self.tr("Daily learning log", "每日学习日志"))
                            .font(self.ui_font())
                            .size(13)
                            .style(style::heading_text()),
                        text(self.tr(
                            "Timestamped notes capture what changed today so the operator can resume with context instead of re-learning it.",
                            "按时间记录的每日笔记会保存当天发生的变化，让系统恢复时不必重新学习上下文。",
                        ))
                        .font(self.ui_font())
                        .size(11)
                        .line_height(LineHeight::Relative(1.2))
                        .style(style::secondary_text()),
                    ]
                    .spacing(4)
                    .width(Length::Fill),
                    if daily_root_exists {
                        self.status_chip_success(self.tr("Live", "在线"))
                    } else {
                        self.status_chip_warning(self.tr("Missing", "缺失"))
                    },
                    if daily_root_exists {
                        self.inline_button(self.tr("Open notes", "打开日志"))
                            .on_press(Message::OpenPath(context.workspace_daily_memory_root.clone()))
                    } else {
                        self.inline_button(self.tr("Open workspace", "打开工作区"))
                            .on_press(Message::OpenPath(context.cwd.clone()))
                    },
                ]
                .spacing(8)
                .align_items(alignment::Alignment::Center),
                row![
                    self.compact_detail_row(
                        self.tr("Notes", "记录"),
                        context.workspace_daily_memory_note_count.to_string(),
                    ),
                    self.compact_detail_row(
                        self.tr("Folder", "目录"),
                        if daily_root_exists {
                            self.tr("present", "已存在").to_string()
                        } else {
                            self.tr("missing", "缺失").to_string()
                        },
                    ),
                    self.compact_detail_row(
                        self.tr("Retention", "保留方式"),
                        self.tr("markdown timeline", "Markdown 时间线").to_string(),
                    ),
                ]
                .spacing(10)
                .wrap(),
            ]
            .spacing(10),
        )
        .padding([12, 14])
        .style(style::subtle_card());

        let runtime_tier = container(
            column![
                row![
                    column![
                        text(self.tr("Retained runtime memory", "运行时保留记忆"))
                            .font(self.ui_font())
                            .size(13)
                            .style(style::heading_text()),
                        text(self.tr(
                            "Structured .pi memory partitions feed routing, recall, and evidence-aware task execution.",
                            "结构化的 .pi 记忆分区会为路由、召回和证据驱动的任务执行提供支持。",
                        ))
                        .font(self.ui_font())
                        .size(11)
                        .line_height(LineHeight::Relative(1.2))
                        .style(style::secondary_text()),
                    ]
                    .spacing(4)
                    .width(Length::Fill),
                    if retained_count > 0 {
                        self.status_chip_success(self.tr("Indexed", "已索引"))
                    } else {
                        self.status_chip_warning(self.tr("Empty", "为空"))
                    },
                    self.inline_button(self.tr("Open store", "打开存储"))
                        .on_press(Message::OpenPath(runtime_memory_root.clone())),
                ]
                .spacing(8)
                .align_items(alignment::Alignment::Center),
                row![
                    self.compact_detail_row(
                        self.tr("Entries", "条目"),
                        retained_count.to_string(),
                    ),
                    self.compact_detail_row(
                        self.tr("Partitions", "分区"),
                        populated_partition_count.to_string(),
                    ),
                    self.compact_detail_row(
                        self.tr("Frozen", "冻结"),
                        frozen_count.to_string(),
                    ),
                ]
                .spacing(10)
                .wrap(),
            ]
            .spacing(10),
        )
        .padding([12, 14])
        .style(style::subtle_card());

        let body = column![
            row![
                self.status_chip(self.tr("3 tiers", "3 层")),
                self.status_chip(self.tr(
                    &format!("{retained_count} retained"),
                    &format!("{retained_count} 条保留"),
                )),
                self.status_chip(self.tr(
                    &format!("{} daily notes", context.workspace_daily_memory_note_count),
                    &format!("{} 条日记忆", context.workspace_daily_memory_note_count),
                )),
                self.status_chip(self.tr(
                    &format!("{frozen_count} frozen"),
                    &format!("{frozen_count} 条冻结"),
                )),
            ]
            .spacing(8)
            .wrap(),
            text(self.tr(
                "Good operator memory is layered: doctrine for durable rules, daily notes for chronology, and retained runtime partitions for structured recall.",
                "好的 operator 记忆应该分层：准则负责长期规则，每日笔记负责时间线，运行时分区负责结构化召回。",
            ))
            .font(self.ui_font())
            .size(12)
            .line_height(LineHeight::Relative(1.25))
            .style(style::secondary_text()),
            durable_tier,
            daily_tier,
            runtime_tier,
            self.detail_row(
                self.tr("Active partition focus", "当前分区焦点"),
                active_partition_focus,
            ),
        ]
        .spacing(12);

        self.panel_shell_with_subtitle(
            self.tr("Memory tiers", "记忆层级"),
            Some(self.tr(
                "Doctrine / daily log / retained runtime",
                "准则 / 每日日志 / 运行时保留",
            )),
            body,
        )
    }

    fn control_memory_entry_panel(&self) -> Container<'_, Message> {
        let Some(workbench) = self.selected_control_workbench() else {
            return self.surface_card(
                self.tr("Memory detail", "记忆详情"),
                self.tr("No selected system is available.", "当前没有可用系统。"),
            );
        };
        let Some(partition) = workbench.memory_partition(self.selected_control_memory_partition)
        else {
            return self.surface_card(
                self.tr("Memory detail", "记忆详情"),
                self.tr(
                    "The selected partition is not available for this system.",
                    "当前系统没有这个分区。",
                ),
            );
        };
        if partition.entries.is_empty() {
            return self.surface_card(
                self.tr("Memory detail", "记忆详情"),
                self.tr(
                    "This partition has no retained entries yet.",
                    "这个分区还没有保留任何记忆。",
                ),
            );
        }

        let rows = partition.entries.iter().rev().take(8).fold(
            Column::new().spacing(10),
            |column, entry| {
                column.push(
                    container(
                        column![
                            row![
                                column![
                                    text(&entry.summary)
                                        .font(self.ui_font())
                                        .size(14)
                                        .style(style::heading_text()),
                                    text(format!("{} · {}", entry.provenance, entry.created_at))
                                        .font(self.ui_font())
                                        .size(12)
                                        .style(style::secondary_text()),
                                ]
                                .spacing(4)
                                .width(Length::Fill),
                                if entry.frozen {
                                    self.status_chip_success(self.tr("Frozen", "冻结"))
                                } else {
                                    self.status_chip(self.tr("Live", "活动"))
                                },
                            ]
                            .spacing(8)
                            .align_items(alignment::Alignment::Center),
                            text(&entry.value)
                                .font(self.ui_font())
                                .size(12)
                                .style(style::secondary_text()),
                            row![
                                self.compact_detail_row(
                                    self.tr("Confidence", "置信度"),
                                    format!("{:.0}%", entry.confidence * 100.0),
                                ),
                                self.compact_detail_row(
                                    self.tr("Source", "来源"),
                                    entry.source_id.clone().unwrap_or_else(|| {
                                        self.tr("No source id", "没有来源 ID").to_string()
                                    }),
                                ),
                            ]
                            .spacing(10),
                        ]
                        .spacing(8),
                    )
                    .padding([12, 14])
                    .style(style::subtle_card()),
                )
            },
        );

        self.panel_shell_with_subtitle(
            self.tr("Memory detail", "记忆详情"),
            Some(partition.partition.label()),
            rows,
        )
    }

    fn control_automation_library_panel(&self) -> Container<'_, Message> {
        let Some(workbench) = self.selected_control_workbench() else {
            return self.surface_card(
                self.tr("Automation library", "自动化库"),
                self.tr("No selected system is available.", "当前没有可用系统。"),
            );
        };
        if workbench.automations.is_empty() {
            return self.surface_card(
                self.tr("Automation library", "自动化库"),
                self.tr(
                    "No saved automations are defined for this system yet.",
                    "这个系统还没有已保存的自动化定义。",
                ),
            );
        }

        let rows = workbench.automations.iter().take(6).fold(
            Column::new().spacing(10),
            |column, automation| {
                let last_run = automation
                    .last_run_at
                    .clone()
                    .unwrap_or_else(|| self.tr("Never run", "从未运行").to_string());
                let status_chip: Container<'_, Message> = match automation.last_run_status {
                    Some(crate::automations::AutomationRunStatus::Succeeded) => {
                        self.status_chip_success(self.tr("Last run ok", "最近运行成功"))
                    }
                    Some(crate::automations::AutomationRunStatus::Failed) => {
                        self.status_chip_warning(self.tr("Last run failed", "最近运行失败"))
                    }
                    Some(status) => self.status_chip(status.label().replace('_', " ")),
                    None => self.status_chip(self.tr("No runs", "无运行记录")),
                };
                column.push(
                    container(
                        column![
                            row![
                                column![
                                    text(&automation.name)
                                        .font(self.ui_font())
                                        .size(14)
                                        .style(style::heading_text()),
                                    text(format!(
                                        "{} · {}",
                                        compact_middle(&automation.id, 24),
                                        last_run
                                    ))
                                    .font(self.ui_font())
                                    .size(12)
                                    .style(style::secondary_text()),
                                ]
                                .spacing(4)
                                .width(Length::Fill),
                                if automation.enabled {
                                    self.status_chip_success(self.tr("Enabled", "启用"))
                                } else {
                                    self.status_chip_warning(self.tr("Disabled", "停用"))
                                },
                                status_chip,
                            ]
                            .spacing(8)
                            .align_items(alignment::Alignment::Center),
                            self.detail_row(
                                self.tr("Trigger / action", "触发 / 动作"),
                                format!(
                                    "{} -> {}",
                                    automation.trigger.label(),
                                    automation.action.label()
                                ),
                            ),
                            self.detail_row(
                                self.tr("Failure budget", "失败预算"),
                                self.tr(
                                    &format!(
                                        "{} / {} consecutive failures",
                                        automation.consecutive_failures,
                                        automation.max_consecutive_failures
                                    ),
                                    &format!(
                                        "{}/{} 次连续失败",
                                        automation.consecutive_failures,
                                        automation.max_consecutive_failures
                                    ),
                                ),
                            ),
                        ]
                        .spacing(8),
                    )
                    .padding([12, 14])
                    .style(style::subtle_card()),
                )
            },
        );

        self.panel_shell_with_subtitle(
            self.tr("Automation library", "自动化库"),
            Some(self.tr("Repeatable jobs", "可重复执行任务")),
            rows,
        )
    }

    fn automation_dispatch_board_panel(&self) -> Container<'_, Message> {
        let control = &self.snapshot.control;
        let context = &self.snapshot.context;
        let (_ready_count, attention_count, blocked_count) = control.readiness_counts();
        let running_count = control.task_count(TaskLifecycleState::Running);
        let approval_count = control.approvals.len();
        let blocked_task_count = control.task_count(TaskLifecycleState::Blocked);
        let verifying_count = control.task_count(TaskLifecycleState::Verifying);
        let worker_attention_count = control
            .workers
            .iter()
            .filter(|worker| {
                matches!(
                    worker.status,
                    WorkerState::NeedsAttention | WorkerState::Blocked
                )
            })
            .count();
        let active_lane_count = context
            .agent_profiles
            .iter()
            .filter(|profile| self.profile_session_count(&profile.id) > 0)
            .count();
        let ready_reserve_count = context
            .agent_profiles
            .iter()
            .filter(|profile| {
                self.profile_route_ready(profile) && self.profile_session_count(&profile.id) == 0
            })
            .count();
        let auth_gap_count = context
            .agent_profiles
            .iter()
            .filter(|profile| self.profile_needs_auth(profile))
            .count();
        let route_gap_count = context
            .agent_profiles
            .iter()
            .filter(|profile| self.profile_route_missing(profile))
            .count();
        let route_blocker_count = context.channel_status_counts().3;
        let active_system_label = self
            .snapshot
            .context
            .active_system()
            .map(|system| format!("{} · {}", system.name, compact_middle(&system.id, 20)))
            .unwrap_or_else(|| context.active_system_id.clone());
        let intervention_label = if approval_count > 0 {
            self.tr(
                &format!(
                    "{approval_count} approvals are pausing dispatch. Human sign-off is the current bottleneck."
                ),
                &format!("{approval_count} 项审批正在暂停分发，当前瓶颈是人工签字。"),
            )
            .to_string()
        } else if blocked_task_count > 0 && (auth_gap_count > 0 || route_gap_count > 0) {
            self.tr(
                &format!(
                    "{blocked_task_count} blocked tasks are tied to {auth_gap_count} auth gaps and {route_gap_count} route gaps. Fix staffing routes before adding more work."
                ),
                &format!(
                    "{blocked_task_count} 个阻塞任务背后有 {auth_gap_count} 个鉴权缺口和 {route_gap_count} 个路由缺口。先修好分工路由，再加工作负载。"
                ),
            )
            .to_string()
        } else if worker_attention_count > 0 {
            self.tr(
                &format!(
                    "{worker_attention_count} workers need intervention. Stabilize retries and heartbeat before expanding throughput."
                ),
                &format!(
                    "{worker_attention_count} 个 Worker 需要处理。先稳定重试和心跳，再扩大吞吐。"
                ),
            )
            .to_string()
        } else if ready_reserve_count > 0 && running_count >= active_lane_count.max(1) {
            self.tr(
                &format!(
                    "{ready_reserve_count} idle ready lanes are available. New work can be shifted away from the currently loaded lanes."
                ),
                &format!(
                    "还有 {ready_reserve_count} 条空闲且已就绪的分工，可以把新工作从当前繁忙分工上分流出去。"
                ),
            )
            .to_string()
        } else if running_count > 0 && ready_reserve_count == 0 {
            self.tr(
                "There is no ready reserve capacity right now. Dispatch is running hot and should stay selective.",
                "当前没有可直接接手的新分工储备，分发面处于偏热状态，应当更谨慎地投放任务。",
            )
            .to_string()
        } else {
            self.tr(
                "Dispatch pressure is balanced. Keep the current route policy and let evidence accumulation drive the next promotion.",
                "当前分发压力比较平衡。保持现有路由策略，让证据积累来驱动下一次晋升或调整。",
            )
            .to_string()
        };
        let readiness_rows = if control.readiness.is_empty() {
            Column::new().spacing(0).push(self.detail_row(
                self.tr("Current posture", "当前姿态"),
                self.tr(
                    "No explicit readiness checks are published yet.",
                    "当前还没有发布显式的就绪检查项。",
                ),
            ))
        } else {
            control
                .readiness
                .iter()
                .take(4)
                .fold(Column::new().spacing(10), |column, item| {
                    column.push(
                        container(
                            row![
                                column![
                                    row![
                                        text(&item.title)
                                            .font(self.ui_font())
                                            .size(14)
                                            .style(style::heading_text()),
                                        self.status_chip(
                                            self.localized_readiness_label(item.state)
                                        ),
                                    ]
                                    .spacing(8)
                                    .align_items(alignment::Alignment::Center),
                                    text(&item.detail)
                                        .font(self.ui_font())
                                        .size(12)
                                        .style(style::secondary_text()),
                                ]
                                .spacing(5)
                                .width(Length::Fill),
                                self.inline_button(self.localized_tab_label(item.action_tab))
                                    .on_press(Message::SelectTab(item.action_tab)),
                            ]
                            .spacing(12)
                            .align_items(alignment::Alignment::Center),
                        )
                        .padding([12, 14])
                        .style(style::subtle_card()),
                    )
                })
        };
        let body = column![
            row![
                self.status_chip(self.tr(
                    &format!("{running_count} running"),
                    &format!("{running_count} 项执行中"),
                )),
                if blocked_task_count + approval_count + worker_attention_count == 0 {
                    self.status_chip_success(self.tr(
                        &format!("{ready_reserve_count} reserve"),
                        &format!("{ready_reserve_count} 条待命"),
                    ))
                } else {
                    self.status_chip_warning(self.tr(
                        &format!(
                            "{} interventions",
                            blocked_task_count + approval_count + worker_attention_count
                        ),
                        &format!(
                            "{} 项需要干预",
                            blocked_task_count + approval_count + worker_attention_count
                        ),
                    ))
                },
                self.status_chip(self.tr(
                    &format!("{blocked_task_count} blocked"),
                    &format!("{blocked_task_count} 项阻塞"),
                )),
                self.status_chip(self.tr(
                    &format!("{approval_count} approvals"),
                    &format!("{approval_count} 项审批"),
                )),
                self.status_chip(self.tr(
                    &format!("{verifying_count} verifying"),
                    &format!("{verifying_count} 项验证中"),
                )),
            ]
            .spacing(8)
            .wrap(),
            text(self.tr(
                "Dispatch should feel like an operator console: watch pressure, keep reserve capacity visible, and know exactly which human or route bottleneck is limiting throughput.",
                "分发面应该像一个操作控制台：持续观察压力、看清待命容量，并明确知道当前限制吞吐的是哪一个人工或路由瓶颈。",
            ))
            .font(self.ui_font())
            .size(12)
            .line_height(LineHeight::Relative(1.25))
            .style(style::secondary_text()),
            row![
                self.detail_row(
                    self.tr("Dispatch pressure", "分发压力"),
                    self.tr(
                        &format!(
                            "{running_count} running · {blocked_task_count} blocked · {attention_count} readiness warnings"
                        ),
                        &format!(
                            "{running_count} 项执行中 · {blocked_task_count} 项阻塞 · {attention_count} 项就绪预警"
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Reserve capacity", "待命容量"),
                    self.tr(
                        &format!(
                            "{ready_reserve_count} idle ready lanes · {active_lane_count} active lanes"
                        ),
                        &format!(
                            "{ready_reserve_count} 条空闲就绪分工 · {active_lane_count} 条活跃分工"
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Governance debt", "治理债务"),
                    self.tr(
                        &format!(
                            "{auth_gap_count} auth gaps · {route_gap_count} route gaps · {route_blocker_count} blocked bindings"
                        ),
                        &format!(
                            "{auth_gap_count} 个鉴权缺口 · {route_gap_count} 个路由缺口 · {route_blocker_count} 个阻塞绑定"
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            row![
                self.detail_row(
                    self.tr("Evidence loop", "证据闭环"),
                    self.tr(
                        &format!(
                            "{} verified · {verifying_count} verifying · {blocked_count} hard blockers",
                            control.verified_artifact_count()
                        ),
                        &format!(
                            "{} 条已验证 · {verifying_count} 项验证中 · {blocked_count} 个硬阻塞",
                            control.verified_artifact_count()
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Workers", "Worker"),
                    self.tr(
                        &format!(
                            "{} total · {worker_attention_count} need intervention",
                            control.workers.len()
                        ),
                        &format!(
                            "{} 个总计 · {worker_attention_count} 个需要处理",
                            control.workers.len()
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            self.detail_row(self.tr("Active system", "当前系统"), active_system_label,),
            self.detail_row(self.tr("Intervention", "干预建议"), intervention_label),
            row![
                self.secondary_button(self.tr("Agents", "分工"))
                    .on_press(Message::SelectTab(Tab::Agents)),
                self.secondary_button(self.tr("Channels", "渠道"))
                    .on_press(Message::SelectTab(Tab::Channels)),
                self.secondary_button(self.tr("Open evidence", "打开证据"))
                    .on_press(Message::OpenPath(context.artifact_library_path.clone())),
                self.secondary_button(self.tr("Control state", "控制台状态"))
                    .on_press(Message::OpenPath(context.control_plane_state_path.clone())),
            ]
            .spacing(10)
            .wrap(),
            readiness_rows,
        ]
        .spacing(14);

        self.panel_shell_with_subtitle(
            self.tr("Dispatch control", "分发控制"),
            Some(self.tr("Pressure / reserve / intervention", "压力 / 待命 / 干预")),
            body,
        )
    }

    fn automation_manual_followup_panel(&self) -> Container<'_, Message> {
        if self.snapshot.control.approvals.is_empty() {
            return self.surface_card(
                self.tr("Approval inbox", "审批收件箱"),
                self.tr(
                    "Nothing is waiting on a human right now. The control plane is free to keep moving.",
                    "当前没有等待人工确认的项目。控制面可以继续推进。",
                ),
            );
        }

        let rows = self.snapshot.control.approvals.iter().fold(
            Column::new().spacing(10),
            |column, approval| {
                column.push(
                    container(
                        row![
                            column![
                                text(&approval.title)
                                    .font(self.ui_font())
                                    .size(14)
                                    .style(style::heading_text()),
                                text(format!("{} · {}", approval.task_title, approval.reason))
                                    .font(self.ui_font())
                                    .size(12)
                                    .style(style::secondary_text()),
                            ]
                            .spacing(4)
                            .width(Length::Fill),
                            self.inline_button(self.localized_tab_label(approval.action_tab))
                                .on_press(Message::SelectTab(approval.action_tab)),
                        ]
                        .spacing(12)
                        .align_items(alignment::Alignment::Center),
                    )
                    .padding([12, 14])
                    .style(style::subtle_card()),
                )
            },
        );

        self.panel_shell_with_subtitle(
            self.tr("Approval inbox", "审批收件箱"),
            Some(self.tr("Human required", "需要人工")),
            rows,
        )
    }

    fn automation_workspace_pipeline_panel(&self) -> Container<'_, Message> {
        if self.snapshot.control.tasks.is_empty() {
            return self.surface_card(
                self.tr("Task board", "任务看板"),
                self.tr(
                    "No live tasks are visible yet. Start or resume a thread to populate the control board.",
                    "当前还没有可见的活跃任务。先开始或恢复一个线程，再回来查看控制台。",
                ),
            );
        }

        let rows = self.snapshot.control.tasks.iter().take(6).fold(
            Column::new().spacing(10),
            |column, task| {
                let detail_card = if let Some(reason) = &task.blocked_reason {
                    self.detail_row(self.tr("Blocked reason", "阻塞原因"), reason.clone())
                } else {
                    self.detail_row(
                        self.tr("Acceptance", "验收标准"),
                        task.acceptance_criteria.clone(),
                    )
                };
                let is_selected = self
                    .selected_session_path
                    .as_deref()
                    .is_some_and(|path| path == task.session_path);
                let mut actions = row![
                    if is_selected {
                        self.primary_button(self.tr("Open thread", "打开线程"))
                    } else {
                        self.secondary_button(self.tr("Open thread", "打开线程"))
                    }
                    .on_press(Message::SelectSession(task.session_path.clone())),
                    self.inline_button(self.tr("Open folder", "打开目录"))
                        .on_press(Message::OpenPath(task.workspace_path.clone())),
                ]
                .spacing(10);
                if task.workspace
                    == infer_title_from_cwd(&self.snapshot.context.cwd, &self.snapshot.context.cwd)
                {
                    actions =
                        actions.push(self.status_chip(self.tr("Current workspace", "当前工作区")));
                }
                column.push(
                    container(
                        column![
                            row![
                                column![
                                    text(&task.title)
                                        .font(self.ui_font())
                                        .size(15)
                                        .style(style::heading_text()),
                                    text(format!(
                                        "{} · {} · {}",
                                        task.workspace,
                                        task.runtime_label,
                                        relative_time_label(task.updated_at_ms)
                                    ))
                                    .font(self.ui_font())
                                    .size(12)
                                    .style(style::secondary_text()),
                                ]
                                .spacing(4)
                                .width(Length::Fill),
                                self.status_chip(self.localized_task_status_label(task.status)),
                            ]
                            .align_items(alignment::Alignment::Center),
                            row![
                                self.status_chip(task.owner.clone()),
                                self.status_chip(task.priority.clone()),
                                self.status_chip(self.tr(
                                    &format!("{} artifacts", task.artifact_count),
                                    &format!("{} 份证据", task.artifact_count),
                                )),
                            ]
                            .spacing(8)
                            .wrap(),
                            text(&task.next_action)
                                .font(self.ui_font())
                                .size(12)
                                .style(style::secondary_text()),
                            detail_card,
                            actions,
                        ]
                        .spacing(10),
                    )
                    .padding([14, 16])
                    .style(style::subtle_card()),
                )
            },
        );

        self.panel_shell_with_subtitle(
            self.tr("Task board", "任务看板"),
            Some(self.tr("Goal / Task / Run", "目标 / 任务 / 运行")),
            rows,
        )
    }

    fn automation_agent_queue_panel(&self) -> Container<'_, Message> {
        if self.snapshot.control.workers.is_empty() {
            return self.surface_card(
                self.tr("Worker lanes", "Worker 分工"),
                self.tr(
                    "No worker lanes are visible yet. Once managed tasks start executing, heartbeat and retry state will appear here.",
                    "当前还没有可见的 Worker 分工。开始执行托管任务后，这里会显示心跳和重试状态。",
                ),
            );
        }

        let running_count = self
            .snapshot
            .control
            .workers
            .iter()
            .filter(|worker| worker.status == WorkerState::Running)
            .count();
        let healthy_count = self
            .snapshot
            .control
            .workers
            .iter()
            .filter(|worker| worker.status == WorkerState::Healthy)
            .count();
        let idle_count = self
            .snapshot
            .control
            .workers
            .iter()
            .filter(|worker| worker.status == WorkerState::Idle)
            .count();
        let needs_attention_count = self
            .snapshot
            .control
            .workers
            .iter()
            .filter(|worker| worker.status == WorkerState::NeedsAttention)
            .count();
        let blocked_count = self
            .snapshot
            .control
            .workers
            .iter()
            .filter(|worker| worker.status == WorkerState::Blocked)
            .count();
        let retry_pressure_count = self
            .snapshot
            .control
            .workers
            .iter()
            .filter(|worker| worker.attempt_count + 1 >= worker.max_attempts)
            .count();
        let queue_posture = if blocked_count > 0 {
            self.tr(
                &format!("{blocked_count} workers are blocked. Clear lane policy or runtime failures before scaling further."),
                &format!("{blocked_count} 个 Worker 已阻塞。继续扩容前，先清理分工策略或运行时故障。"),
            )
            .to_string()
        } else if needs_attention_count > 0 {
            self.tr(
                &format!("{needs_attention_count} workers are drifting. Review heartbeat and retry loops now."),
                &format!("{needs_attention_count} 个 Worker 状态在漂移，建议现在检查心跳和重试循环。"),
            )
            .to_string()
        } else if idle_count > 0 && running_count > 0 {
            self.tr(
                &format!("{idle_count} workers are standing by while {running_count} are active. There is room to rebalance new work."),
                &format!("当前有 {idle_count} 个 Worker 待命、{running_count} 个执行中，说明仍有空间把新任务重新平衡。"),
            )
            .to_string()
        } else {
            self.tr(
                "Worker supply is roughly aligned with the current managed workload.",
                "当前 Worker 供给和托管工作负载大致匹配。",
            )
            .to_string()
        };

        let rows = self.snapshot.control.workers.iter().take(6).fold(
            Column::new().spacing(10),
            |column, worker| {
                column.push(
                    container(
                        column![
                            row![
                                text(&worker.agent_name)
                                    .font(self.ui_font())
                                    .size(14)
                                    .style(style::heading_text()),
                                Space::with_width(Length::Fill),
                                self.status_chip(self.localized_worker_state_label(worker.status)),
                            ]
                            .align_items(alignment::Alignment::Center),
                            text(format!(
                                "{} · {}",
                                worker.runtime_label, worker.heartbeat_label
                            ))
                            .font(self.ui_font())
                            .size(12)
                            .style(style::secondary_text()),
                            self.detail_row(self.tr("Task", "任务"), worker.task_title.clone(),),
                            row![
                                self.compact_detail_row(
                                    self.tr("Attempts", "尝试"),
                                    format!("{}/{}", worker.attempt_count, worker.max_attempts),
                                ),
                                self.compact_detail_row(
                                    self.tr("Reflection", "反思"),
                                    worker.reflection.clone(),
                                ),
                            ]
                            .spacing(10),
                            self.secondary_button(self.tr("Open worker lane", "打开角色"))
                                .on_press(Message::SelectSessionAgentLane(worker.id.clone())),
                        ]
                        .spacing(8),
                    )
                    .padding([12, 14])
                    .style(style::subtle_card()),
                )
            },
        );

        self.panel_shell_with_subtitle(
            self.tr("Worker lanes", "Worker 分工"),
            Some(self.tr("Capacity + heartbeat", "容量 + 心跳")),
            column![
                row![
                    self.status_chip(self.tr(
                        &format!("{running_count} running"),
                        &format!("{running_count} 个执行中"),
                    )),
                    self.status_chip(self.tr(
                        &format!("{healthy_count} healthy"),
                        &format!("{healthy_count} 个健康"),
                    )),
                    self.status_chip(self.tr(
                        &format!("{idle_count} idle"),
                        &format!("{idle_count} 个待命"),
                    )),
                    if blocked_count + needs_attention_count == 0 {
                        self.status_chip_success(self.tr(
                            &format!("{retry_pressure_count} near retry limit"),
                            &format!("{retry_pressure_count} 个接近重试上限"),
                        ))
                    } else {
                        self.status_chip_warning(self.tr(
                            &format!("{} intervention", blocked_count + needs_attention_count),
                            &format!("{} 个需干预", blocked_count + needs_attention_count),
                        ))
                    },
                ]
                .spacing(8)
                .wrap(),
                self.detail_row(self.tr("Queue posture", "队列姿态"), queue_posture),
                rows,
            ]
            .spacing(12),
        )
    }

    fn automation_runtime_health_panel(&self) -> Container<'_, Message> {
        if self.snapshot.control.artifacts.is_empty() {
            return self.surface_card(
                self.tr("Evidence board", "证据板"),
                self.tr(
                    "No retained artifacts are visible yet. Run a task and the control plane will surface evidence here.",
                    "当前还没有可见的结构化证据。先运行任务，控制面会在这里展示证据。",
                ),
            );
        }

        let verified_count = self
            .snapshot
            .control
            .artifacts
            .iter()
            .filter(|artifact| artifact.state == ArtifactState::Verified)
            .count();
        let pending_count = self
            .snapshot
            .control
            .artifacts
            .iter()
            .filter(|artifact| artifact.state == ArtifactState::Pending)
            .count();
        let failed_count = self
            .snapshot
            .control
            .artifacts
            .iter()
            .filter(|artifact| artifact.state == ArtifactState::Failed)
            .count();

        let rows = self.snapshot.control.artifacts.iter().take(6).fold(
            Column::new().spacing(10),
            |column, artifact| {
                column.push(
                    container(
                        column![
                            row![
                                column![
                                    row![
                                        text(self.localized_artifact_kind_label(artifact.kind))
                                            .font(self.ui_font())
                                            .size(14)
                                            .style(style::heading_text()),
                                        self.status_chip(
                                            self.localized_artifact_state_label(artifact.state)
                                        ),
                                    ]
                                    .spacing(8)
                                    .align_items(alignment::Alignment::Center),
                                    text(&artifact.summary)
                                        .font(self.ui_font())
                                        .size(12)
                                        .style(style::secondary_text()),
                                ]
                                .spacing(4)
                                .width(Length::Fill),
                                self.status_chip(artifact.created_at_label.clone()),
                            ]
                            .align_items(alignment::Alignment::Center),
                            row![
                                self.compact_detail_row(
                                    self.tr("Task", "任务"),
                                    artifact.task_id.clone(),
                                ),
                                self.compact_detail_row(
                                    self.tr("Source", "来源"),
                                    display_path_label(Path::new(&artifact.uri)),
                                ),
                            ]
                            .spacing(10),
                            self.secondary_button(self.tr("Open evidence", "打开证据"))
                                .on_press(Message::OpenPath(artifact.uri.clone())),
                        ]
                        .spacing(8),
                    )
                    .padding([12, 14])
                    .style(style::subtle_card()),
                )
            },
        );

        self.panel_shell_with_subtitle(
            self.tr("Evidence board", "证据板"),
            Some(self.tr("Verified / pending / failed", "已验证 / 待确认 / 失败")),
            column![
                row![
                    self.status_chip(self.tr(
                        &format!("{verified_count} verified"),
                        &format!("{verified_count} 条已验证"),
                    )),
                    self.status_chip(self.tr(
                        &format!("{pending_count} pending"),
                        &format!("{pending_count} 条待确认"),
                    )),
                    self.status_chip(self.tr(
                        &format!("{failed_count} failed"),
                        &format!("{failed_count} 条失败"),
                    )),
                ]
                .spacing(8)
                .wrap(),
                self.detail_row(
                    self.tr("Evidence labels", "证据标签"),
                    self.tr(
                        "Verified = completion proof; Pending = work signal; Failed = negative proof",
                        "已验证 = 完成证据；待确认 = 过程信号；失败 = 负向证据",
                    ),
                ),
                row![
                    self.secondary_button(self.tr("Open artifact library", "打开证据库"))
                        .on_press(Message::OpenPath(
                            self.snapshot.context.artifact_library_path.clone()
                        )),
                    self.secondary_button(self.tr("Open control state", "打开控制台状态"))
                        .on_press(Message::OpenPath(
                            self.snapshot.context.control_plane_state_path.clone()
                        )),
                ]
                .spacing(10),
                rows,
            ]
            .spacing(12),
        )
    }

    fn sessions_manager_panel(&self) -> Container<'_, Message> {
        if self.snapshot.sessions.is_empty() {
            return self.surface_card(
                self.tr("Session board", "会话看板"),
                self.tr(
                    "There are no resumable sessions yet. Start a thread and it will appear here as a real work item.",
                    "当前还没有可恢复的会话。开始一个线程后，它会作为真实工作项出现在这里。",
                ),
            );
        }

        let filtered_sessions = self.filtered_sessions();
        let workspace_scope = if self.drafts.workspace_focus.trim().is_empty() {
            self.tr("All workspaces", "全部工作区").to_string()
        } else {
            infer_title_from_cwd(&self.drafts.workspace_focus, &self.drafts.workspace_focus)
        };
        let agent_scope = self
            .session_lane_summaries()
            .into_iter()
            .find(|lane| lane.id == self.drafts.session_agent_focus)
            .map(|lane| lane.display_name)
            .unwrap_or_else(|| self.tr("All profiles", "全部角色").to_string());
        let mut rows = Column::new().spacing(12);
        rows = rows.push(
            row![
                self.status_chip(self.tr(
                    &format!("{} matches", filtered_sessions.len()),
                    &format!("{} 条匹配", filtered_sessions.len()),
                )),
                self.status_chip(format!(
                    "{} · {}",
                    self.tr("Workspace", "工作区"),
                    workspace_scope
                )),
                self.status_chip(format!("{} · {}", self.tr("Agent", "角色"), agent_scope)),
            ]
            .spacing(8)
            .wrap(),
        );
        if !self.drafts.session_filter.trim().is_empty() {
            rows = rows.push(
                container(
                    row![
                        text(format!(
                            "{} {}",
                            self.tr("Search", "搜索"),
                            self.drafts.session_filter
                        ))
                        .font(self.ui_font())
                        .size(12)
                        .style(style::secondary_text())
                        .width(Length::Fill),
                        self.inline_button(self.tr("Clear", "清除"))
                            .on_press(Message::ClearSessionFilter),
                    ]
                    .spacing(10)
                    .align_items(alignment::Alignment::Center),
                )
                .padding([10, 12])
                .style(style::subtle_card()),
            );
        }

        if filtered_sessions.is_empty() {
            rows = rows.push(self.detail_row(
                self.tr("No sessions found", "没有找到会话"),
                self.tr(
                    "Nothing matched the current workspace, agent, or search filters. Clear scope and try again.",
                    "当前工作区、角色或搜索条件下没有结果。清除范围后再试。",
                ),
            ));
            return self.panel_shell_with_subtitle(
                self.tr("Session board", "会话看板"),
                Some(self.tr("Resumable work", "可恢复工作")),
                rows,
            );
        }

        rows = filtered_sessions
            .into_iter()
            .take(14)
            .fold(rows, |column, session| {
                let is_selected = self
                    .selected_session_path
                    .as_deref()
                    .is_some_and(|path| path == session.path);
                let active_chip: Element<'_, Message> = if is_selected {
                    self.status_chip_success(self.tr("Active", "当前")).into()
                } else {
                    Space::with_width(Length::Shrink).into()
                };
                let runtime_label = self
                    .snapshot
                    .preview_by_path(&session.path)
                    .and_then(|preview| {
                        preview
                            .provider
                            .as_deref()
                            .zip(preview.model.as_deref())
                            .map(|(provider, model)| format!("{provider} / {model}"))
                    })
                    .or_else(|| {
                        session
                            .provider
                            .as_deref()
                            .zip(session.model.as_deref())
                            .map(|(provider, model)| format!("{provider} / {model}"))
                    })
                    .unwrap_or_else(|| self.tr("Runtime pending", "运行时待补全").to_string());
                column.push(
                    container(
                        column![
                            row![
                                row![
                                    text(&session.title)
                                        .font(self.ui_font())
                                        .size(14)
                                        .style(style::heading_text()),
                                    Space::with_width(Length::Fill),
                                    self.status_chip(session.workspace_name()),
                                    active_chip,
                                ]
                                .align_items(alignment::Alignment::Center),
                                Space::with_width(Length::Fill),
                                text(session.last_active_label.clone())
                                    .font(self.ui_font())
                                    .size(10)
                                    .style(style::secondary_text()),
                            ]
                            .spacing(8)
                            .align_items(alignment::Alignment::Center),
                            row![
                                text(format!(
                                    "{} · {}",
                                    self.session_agent_meta_label(session),
                                    runtime_label
                                ))
                                .font(self.ui_font())
                                .size(11)
                                .style(style::secondary_text())
                                .width(Length::Fill),
                                self.status_chip(self.tr(
                                    &format!("{} msgs", session.message_count),
                                    &format!("{} 条消息", session.message_count),
                                )),
                            ]
                            .spacing(8)
                            .align_items(alignment::Alignment::Center),
                            text(compact_middle(&session.path, 72))
                                .font(self.ui_font())
                                .size(10)
                                .style(style::secondary_text()),
                            row![
                                if is_selected {
                                    self.primary_button(self.tr("Resume", "恢复"))
                                } else {
                                    self.secondary_button(self.tr("Resume", "恢复"))
                                }
                                .on_press(Message::SelectSession(session.path.clone())),
                                self.inline_button(self.tr("Open file", "打开文件"))
                                    .on_press(Message::OpenPath(session.path.clone())),
                                self.inline_button(self.tr("Open folder", "打开目录"))
                                    .on_press(Message::OpenPath(session.cwd.clone())),
                            ]
                            .spacing(8),
                        ]
                        .spacing(6),
                    )
                    .padding([10, 12])
                    .style(style::list_row(is_selected)),
                )
            });

        self.panel_shell_with_subtitle(
            self.tr("Session board", "会话看板"),
            Some(self.tr("Resumable work", "可恢复工作")),
            rows,
        )
    }

    fn agent_profiles_panel(&self) -> Container<'_, Message> {
        if self.snapshot.context.agent_profiles.is_empty() {
            return self.surface_card(
                self.tr("Profiles", "角色"),
                self.tr(
                    "No agent profiles are available yet.",
                    "当前没有可用的角色配置。",
                ),
            );
        }

        let rows = self.snapshot.context.agent_profiles.iter().fold(
            Column::new().spacing(10),
            |column, profile| {
                let is_default = self.drafts.starter_agent == profile.id;
                let is_selected = self.drafts.selected_agent_profile == profile.id;
                let selected_chip: Element<'_, Message> = if is_selected {
                    self.status_chip_success(self.tr("Open", "打开")).into()
                } else {
                    Space::with_width(Length::Shrink).into()
                };
                let lane_count = self
                    .snapshot
                    .sessions
                    .iter()
                    .filter(|session| {
                        session.agent_profile_id.as_deref() == Some(profile.id.as_str())
                    })
                    .count();
                let runtime_label = self.agent_runtime_label(profile);
                let status_label = if is_default {
                    self.tr("Starter", "默认")
                } else {
                    self.tr("Available", "可用")
                };
                let origin_label = if profile.has_customizations {
                    self.tr("Customized", "已定制")
                } else if profile.is_builtin {
                    self.tr("Shipped", "内置")
                } else {
                    self.tr("Custom", "自定义")
                };

                column.push(
                    container(
                        column![
                            row![
                                text(&profile.display_name)
                                    .font(self.ui_font())
                                    .size(14)
                                    .style(style::heading_text())
                                    .width(Length::Fill),
                                self.status_chip(origin_label),
                                self.status_chip(status_label),
                                selected_chip,
                            ]
                            .spacing(8)
                            .align_items(alignment::Alignment::Center),
                            text(&profile.description)
                                .font(self.ui_font())
                                .size(11)
                                .style(style::secondary_text()),
                            row![
                                self.status_chip(runtime_label),
                                self.status_chip(self.tr(
                                    &format!("{lane_count} sessions",),
                                    &format!("{lane_count} 个会话"),
                                )),
                                self.status_chip(format!(
                                    "{} · {}",
                                    self.tr("Mode", "模式"),
                                    profile.mode_label
                                )),
                            ]
                            .spacing(8)
                            .wrap(),
                            text(if profile.skills.is_empty() {
                                self.tr("No extra skills attached yet.", "当前还没有附加技能。")
                                    .to_string()
                            } else {
                                format!("{} · {}", profile.skill_scope, profile.skills.join(", "))
                            })
                            .font(self.ui_font())
                            .size(10)
                            .style(style::secondary_text()),
                            row![
                                if is_selected {
                                    self.primary_button(self.tr("Open", "打开"))
                                } else {
                                    self.secondary_button(self.tr("Open", "打开"))
                                }
                                .on_press(Message::SelectAgentProfile(profile.id.clone())),
                                self.inline_button(if is_default {
                                    self.tr("Starter", "默认")
                                } else {
                                    self.tr("Set Starter", "设为默认")
                                })
                                .on_press(Message::PersistStarterAgent(profile.id.clone())),
                            ]
                            .spacing(8),
                        ]
                        .spacing(6),
                    )
                    .padding([10, 12])
                    .style(style::list_row(is_selected)),
                )
            },
        );

        self.panel_shell_with_subtitle(
            self.tr("Agent board", "角色看板"),
            Some(self.tr("Profiles", "角色")),
            rows,
        )
    }

    fn agent_portfolio_panel(&self) -> Container<'_, Message> {
        let profiles = &self.snapshot.context.agent_profiles;
        if profiles.is_empty() {
            return self.surface_card(
                self.tr("Lane portfolio", "分工组合"),
                self.tr("No lanes are available yet.", "当前还没有可管理的分工。"),
            );
        }

        let active_lane_count = profiles
            .iter()
            .filter(|profile| self.profile_session_count(&profile.id) > 0)
            .count();
        let override_count = profiles
            .iter()
            .filter(|profile| profile.mode_id == "override")
            .count();
        let auth_gap_count = profiles
            .iter()
            .filter(|profile| self.profile_needs_auth(profile))
            .count();
        let ready_lane_count = profiles
            .iter()
            .filter(|profile| self.profile_route_ready(profile))
            .count();
        let custom_pack_count = profiles
            .iter()
            .filter(|profile| !profile.skills.is_empty() || !profile.prompts.is_empty())
            .count();
        let selected_id = self.drafts.selected_agent_profile.clone();
        let starter_id = self.effective_starter_agent_id().to_string();
        let mut lane_rows = profiles
            .iter()
            .map(|profile| {
                (
                    profile,
                    self.profile_session_count(&profile.id),
                    self.profile_latest_session_title(&profile.id)
                        .unwrap_or_else(|| {
                            self.tr("No live thread yet", "还没有活跃线程").to_string()
                        }),
                    self.profile_needs_auth(profile),
                    self.profile_route_ready(profile),
                )
            })
            .collect::<Vec<_>>();
        lane_rows.sort_by(|left, right| {
            let left_selected = left.0.id == selected_id;
            let right_selected = right.0.id == selected_id;
            let left_starter = left.0.id == starter_id;
            let right_starter = right.0.id == starter_id;
            right_selected
                .cmp(&left_selected)
                .then_with(|| right_starter.cmp(&left_starter))
                .then_with(|| right.1.cmp(&left.1))
                .then_with(|| left.0.display_name.cmp(&right.0.display_name))
        });

        let rows = lane_rows.into_iter().take(6).fold(
            Column::new().spacing(10),
            |column, (profile, session_count, latest_title, needs_auth, route_ready)| {
                let is_selected = profile.id == self.drafts.selected_agent_profile;
                let is_starter = profile.id == starter_id;
                column.push(
                    container(
                        column![
                            row![
                                text(&profile.display_name)
                                    .font(self.ui_font())
                                    .size(14)
                                    .style(style::heading_text())
                                    .width(Length::Fill),
                                if is_selected {
                                    self.status_chip_success(self.tr("Selected", "已选中"))
                                } else {
                                    self.status_chip(self.tr("Available", "可用"))
                                },
                                if is_starter {
                                    self.status_chip(self.tr("Starter", "默认"))
                                } else if profile.mode_id == "override" {
                                    self.status_chip(self.tr("Dedicated", "独立路由"))
                                } else {
                                    self.status_chip(self.tr("Follow main", "跟随主路由"))
                                },
                                if needs_auth {
                                    self.status_chip_warning(if profile.mode_id == "override" {
                                        self.tr("Auth gap", "鉴权缺口")
                                    } else {
                                        self.tr("Main blocked", "主路由阻塞")
                                    })
                                } else if route_ready {
                                    if session_count == 0 {
                                        self.status_chip(self.tr("Reserve", "待命"))
                                    } else {
                                        self.status_chip_success(self.tr("Live", "运行中"))
                                    }
                                } else {
                                    self.status_chip_warning(self.tr("Needs route", "需要路由"))
                                },
                            ]
                            .spacing(8)
                            .align_items(alignment::Alignment::Center),
                            text(&profile.description)
                                .font(self.ui_font())
                                .size(11)
                                .style(style::secondary_text()),
                            row![
                                self.status_chip(self.agent_runtime_label(profile)),
                                self.status_chip(self.tr(
                                    &format!("{session_count} sessions"),
                                    &format!("{session_count} 个会话"),
                                )),
                                self.status_chip(self.tr(
                                    &format!("{} skills", profile.skills.len()),
                                    &format!("{} 个技能", profile.skills.len()),
                                )),
                                self.status_chip(self.tr(
                                    &format!("{} prompts", profile.prompts.len()),
                                    &format!("{} 个提示", profile.prompts.len()),
                                )),
                            ]
                            .spacing(8)
                            .wrap(),
                            self.detail_row(self.tr("Latest work", "最近工作"), latest_title),
                            row![
                                if is_selected {
                                    self.primary_button(self.tr("Open lane", "打开分工"))
                                } else {
                                    self.secondary_button(self.tr("Open lane", "打开分工"))
                                }
                                .on_press(Message::SelectAgentProfile(profile.id.clone())),
                                self.inline_button(if is_starter {
                                    self.tr("Starter", "默认")
                                } else {
                                    self.tr("Set starter", "设为默认")
                                })
                                .on_press(Message::PersistStarterAgent(profile.id.clone())),
                            ]
                            .spacing(8),
                        ]
                        .spacing(8),
                    )
                    .padding([12, 14])
                    .style(style::subtle_card()),
                )
            },
        );

        let body = column![
            row![
                self.status_chip(self.tr(
                    &format!("{} lanes", profiles.len()),
                    &format!("{} 条分工", profiles.len()),
                )),
                self.status_chip(self.tr(
                    &format!("{active_lane_count} active"),
                    &format!("{active_lane_count} 条活跃"),
                )),
                self.status_chip(self.tr(
                    &format!("{ready_lane_count} ready"),
                    &format!("{ready_lane_count} 条就绪"),
                )),
                self.status_chip(self.tr(
                    &format!("{auth_gap_count} need keys"),
                    &format!("{auth_gap_count} 条缺少密钥"),
                )),
                self.status_chip(self.tr(
                    &format!("{custom_pack_count} with packs"),
                    &format!("{custom_pack_count} 条带扩展包"),
                )),
            ]
            .spacing(8)
            .wrap(),
            text(self.tr(
                "Manage lanes like staffing: which ones are active, which remain ready reserve, which are blocked by route policy, and which carry custom behavior that needs supervision.",
                "把分工当作编组来管理：哪些正在工作，哪些是待命储备，哪些被路由策略卡住，哪些承载了需要监管的自定义行为。",
            ))
            .font(self.ui_font())
            .size(12)
            .line_height(LineHeight::Relative(1.25))
            .style(style::secondary_text()),
            row![
                self.detail_row(
                    self.tr("Fleet posture", "舰队姿态"),
                    self.tr(
                        &format!(
                            "{active_lane_count} active · {} idle · {override_count} dedicated runtime lanes",
                            profiles.len().saturating_sub(active_lane_count)
                        ),
                        &format!(
                            "{active_lane_count} 条活跃 · {} 条待命 · {override_count} 条独立运行时分工",
                            profiles.len().saturating_sub(active_lane_count)
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Deployment debt", "部署债务"),
                    self.tr(
                        &format!("{auth_gap_count} auth gaps · {} lanes still follow main", profiles.len().saturating_sub(override_count)),
                        &format!("{auth_gap_count} 条鉴权缺口 · {} 条仍跟随主路由", profiles.len().saturating_sub(override_count)),
                    ),
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            rows,
            row![
                self.secondary_button(self.tr("Sessions", "会话"))
                    .on_press(Message::SelectTab(Tab::Sessions)),
                self.secondary_button(self.tr("Skills", "技能"))
                    .on_press(Message::SelectTab(Tab::Skills)),
                self.secondary_button(self.tr("Settings", "设置"))
                    .on_press(Message::SelectTab(Tab::Settings)),
            ]
            .spacing(10),
        ]
        .spacing(12);

        self.panel_shell_with_subtitle(
            self.tr("Lane portfolio", "分工组合"),
            Some(self.tr("Staffing / health / deployment", "编组 / 健康度 / 部署")),
            body,
        )
    }

    fn agent_editor_panel(&self) -> Container<'_, Message> {
        let Some(profile) = self.selected_agent_profile() else {
            return self.surface_card(
                self.tr("Route editor", "路由编辑器"),
                self.tr(
                    "Select an agent profile to tune its route, naming, skills, and prompts.",
                    "选择一个角色后，这里会显示它的路由、命名、技能和提示设置。",
                ),
            );
        };

        let mode_buttons = row![
            if self.drafts.agent_mode_id == "follow_main" {
                self.primary_button("Follow main")
            } else {
                self.secondary_button("Follow main")
            }
            .on_press(Message::SetAgentModeFollowMain),
            if self.drafts.agent_mode_id == "override" {
                self.primary_button("Override")
            } else {
                self.secondary_button("Override")
            }
            .on_press(Message::SetAgentModeOverride),
        ]
        .spacing(8);

        let live_session_count = self
            .snapshot
            .sessions
            .iter()
            .filter(|session| session.agent_profile_id.as_deref() == Some(profile.id.as_str()))
            .count();
        let custom_skill_count = split_path_input(&self.drafts.agent_skills).len();
        let prompt_count = split_path_input(&self.drafts.agent_prompts).len();
        let inherited_provider = self.drafts.default_provider.trim();
        let inherited_model = self.drafts.default_model.trim();
        let runtime_summary = if self.drafts.agent_mode_id == "override" {
            if self.drafts.agent_provider.trim().is_empty()
                || self.drafts.agent_model.trim().is_empty()
            {
                self.tr(
                    "Override route is not fully configured yet",
                    "覆盖路由还没有配置完整",
                )
                .to_string()
            } else {
                format!(
                    "{} · {}",
                    self.drafts.agent_provider.trim(),
                    self.drafts.agent_model.trim()
                )
            }
        } else if inherited_provider.is_empty() && inherited_model.is_empty() {
            self.tr(
                "Follow main · main route is not configured yet",
                "跟随主路由 · 主路由尚未配置",
            )
            .to_string()
        } else {
            self.tr(
                &format!("Follow main · {} · {}", inherited_provider, inherited_model),
                &format!("跟随主路由 · {} · {}", inherited_provider, inherited_model),
            )
            .to_string()
        };
        let starter_lane_label = if profile.id == self.drafts.starter_agent {
            self.tr(
                "This lane launches by default",
                "这个分工会作为默认入口启动",
            )
            .to_string()
        } else {
            self.snapshot
                .context
                .agent_profile(&self.drafts.starter_agent)
                .map(|starter| starter.display_name.clone())
                .unwrap_or_else(|| {
                    self.tr("No default lane selected", "当前没有默认分工")
                        .to_string()
                })
        };

        let mut body = column![
            row![
                self.status_chip(profile.id.clone()),
                self.status_chip(self.agent_runtime_label(profile)),
                self.status_chip(profile.mode_label.clone()),
            ]
            .spacing(8)
            .wrap(),
            self.action_block(
                self.tr("Lane brief", "分工简报"),
                Some(
                    self.tr(
                        "Tune one isolated operator lane at a time. Keep the lane easy to recognize before you change its runtime.",
                        "一次只整理一个隔离分工。先让分工的职责和身份清晰，再去改运行时。",
                    )
                    .to_string(),
                ),
                column![
                    self.detail_row(self.tr("Resolved runtime", "当前运行时"), runtime_summary),
                    row![
                        self.compact_detail_row(
                            self.tr("Live threads", "活跃线程"),
                            live_session_count.to_string(),
                        ),
                        self.compact_detail_row(
                            self.tr("Skill packs", "技能包"),
                            self.tr(
                                &format!("{custom_skill_count} custom / {} shipped", profile.builtin_skills.len()),
                                &format!("{custom_skill_count} 个自定义 / {} 个内置", profile.builtin_skills.len()),
                            ),
                        ),
                        self.compact_detail_row(
                            self.tr("Prompts", "提示"),
                            prompt_count.to_string(),
                        ),
                    ]
                    .spacing(10)
                    .wrap(),
                    self.detail_row(self.tr("Default lane", "默认分工"), starter_lane_label),
                ]
                .spacing(10)
                .into(),
            ),
            self.action_block(
                self.tr("Route mode", "路由模式"),
                Some(
                    self.tr(
                        "Follow main keeps cognition low. Only use Override when this lane genuinely needs a dedicated provider or model.",
                        "跟随主路由能降低认知负担。只有当这个分工确实需要独立 provider 或模型时，再使用覆盖模式。",
                    )
                    .to_string(),
                ),
                mode_buttons.into(),
            ),
            self.action_block(
                self.tr("Identity", "身份"),
                Some(
                    self.tr(
                        "These fields control how the lane appears in the UI and how humans understand its role.",
                        "这些字段决定了分工在界面中的呈现方式，以及人如何理解它的职责。",
                    )
                    .to_string(),
                ),
                column![
                    self.editor_block(
                        self.tr("Display name", "显示名称"),
                        Some(
                            self.tr(
                                "Short label shown in lane lists and session headers.",
                                "显示在分工列表和会话标题中的简短名称。",
                            )
                            .to_string(),
                        ),
                        text_input("Display name", &self.drafts.agent_display_name)
                            .on_input(Message::UpdateAgentDisplayName)
                            .style(style::TextInputStyle::Field)
                            .padding(12)
                            .into(),
                    ),
                    self.editor_block(
                        self.tr("Description", "描述"),
                        Some(
                            self.tr(
                                "One sentence describing what this lane should take ownership of.",
                                "用一句话描述这个分工应该负责什么。",
                            )
                            .to_string(),
                        ),
                        text_input("Description", &self.drafts.agent_description)
                            .on_input(Message::UpdateAgentDescription)
                            .style(style::TextInputStyle::Field)
                            .padding(12)
                            .into(),
                    ),
                ]
                .spacing(10)
                .into(),
            ),
        ]
        .spacing(12);

        if self.drafts.agent_mode_id == "override" {
            body = body.push(
                self.action_block(
                    self.tr("Runtime override", "运行时覆盖"),
                    Some(
                        self.tr(
                            "This lane will stop inheriting the main route. Fill both fields so the route is explicit and reviewable.",
                            "这个分工将不再继承主路由。请把两个字段都填写完整，让路由明确且可审查。",
                        )
                        .to_string(),
                    ),
                    column![
                        self.editor_block(
                            self.tr("Provider override", "Provider 覆盖"),
                            Some(
                                self.tr(
                                    "Example: openai, anthropic, gemini.",
                                    "例如：openai、anthropic、gemini。",
                                )
                                .to_string(),
                            ),
                            text_input("Provider override", &self.drafts.agent_provider)
                                .on_input(Message::UpdateAgentProvider)
                                .style(style::TextInputStyle::Field)
                                .padding(12)
                                .into(),
                        ),
                        self.editor_block(
                            self.tr("Model override", "模型覆盖"),
                            Some(
                                self.tr(
                                    "Use a specific model id for this lane only.",
                                    "为这个分工单独指定一个模型 ID。",
                                )
                                .to_string(),
                            ),
                            text_input("Model override", &self.drafts.agent_model)
                                .on_input(Message::UpdateAgentModel)
                                .style(style::TextInputStyle::Field)
                                .padding(12)
                                .into(),
                        ),
                    ]
                    .spacing(10)
                    .into(),
                ),
            );
        } else {
            body = body.push(
                self.action_block(
                    self.tr("Runtime override", "运行时覆盖"),
                    Some(
                        self.tr(
                            "This lane is currently inheriting the main route. Switch to Override only if you need a different provider/model pair.",
                            "这个分工当前正在继承主路由。只有当你确实需要不同的 provider/model 组合时，再切换到覆盖模式。",
                        )
                        .to_string(),
                    ),
                    column![
                        self.detail_row(
                            self.tr("Inherited provider", "继承的 provider"),
                            if inherited_provider.is_empty() {
                                self.tr("Not configured", "未配置").to_string()
                            } else {
                                inherited_provider.to_string()
                            },
                        ),
                        self.detail_row(
                            self.tr("Inherited model", "继承的模型"),
                            if inherited_model.is_empty() {
                                self.tr("Not configured", "未配置").to_string()
                            } else {
                                inherited_model.to_string()
                            },
                        ),
                    ]
                    .spacing(10)
                    .into(),
                ),
            );
        }

        body = body
            .push(
                self.action_block(
                    self.tr("Behavior packs", "行为包"),
                    Some(
                        self.tr(
                            "Only keep packs that meaningfully change how this lane routes, reasons, or writes.",
                            "只保留那些会实质改变这个分工如何路由、思考或输出的包。",
                        )
                        .to_string(),
                    ),
                    column![
                        self.editor_block(
                            self.tr("Skills", "技能"),
                            Some(
                                self.tr(
                                    "Use ; or , to separate packs. Leave empty to keep the lane lean.",
                                    "使用 ; 或 , 分隔多个包。留空可以让分工保持轻量。",
                                )
                                .to_string(),
                            ),
                            text_input("Skills (use ; or ,)", &self.drafts.agent_skills)
                                .on_input(Message::UpdateAgentSkills)
                                .style(style::TextInputStyle::Field)
                                .padding(12)
                                .into(),
                        ),
                        self.editor_block(
                            self.tr("Prompts", "提示"),
                            Some(
                                self.tr(
                                    "Prompt packs should add real operator guidance, not decorative text.",
                                    "提示包应该补充真实的操作指引，而不是装饰性文本。",
                                )
                                .to_string(),
                            ),
                            text_input("Prompts (use ; or ,)", &self.drafts.agent_prompts)
                                .on_input(Message::UpdateAgentPrompts)
                                .style(style::TextInputStyle::Field)
                                .padding(12)
                                .into(),
                        ),
                    ]
                    .spacing(10)
                    .into(),
                ),
            )
            .push(
                self.action_block(
                    self.tr("Profile actions", "角色动作"),
                    Some(
                        self.tr(
                            "Save edits into the current lane, or fork the current setup into a custom lane with its own id.",
                            "把修改保存到当前分工，或者用单独的 ID 把当前设置复制成一个自定义分工。",
                        )
                        .to_string(),
                    ),
                    column![
                        self.editor_block(
                            self.tr("Custom agent id", "自定义角色 ID"),
                            Some(
                                self.tr(
                                    "Used only when you create a new custom lane from the current draft.",
                                    "只在基于当前草稿创建新自定义分工时使用。",
                                )
                                .to_string(),
                            ),
                            text_input("Custom agent id", &self.drafts.custom_agent_id)
                                .on_input(Message::UpdateCustomAgentId)
                                .style(style::TextInputStyle::Field)
                                .padding(12)
                                .into(),
                        ),
                        row![
                            self.primary_button(self.tr("Save profile", "保存角色"))
                                .on_press(Message::SaveAgentProfile),
                            self.secondary_button(self.tr("Create custom", "创建自定义角色"))
                                .on_press(Message::CreateAgentProfile),
                            self.secondary_button(self.tr("Reset shipped", "恢复内置"))
                                .on_press(Message::ResetAgentProfile),
                        ]
                        .spacing(10)
                        .wrap(),
                    ]
                    .spacing(10)
                    .into(),
                ),
            );

        self.panel_shell_with_subtitle(
            self.tr("Lane setup", "分工设置"),
            Some(self.tr("Identity / route / packs", "身份 / 路由 / 包")),
            body,
        )
    }

    fn agent_lanes_panel(&self) -> Container<'_, Message> {
        let profiles = &self.snapshot.context.agent_profiles;
        let starter_profile = self
            .snapshot
            .context
            .agent_profile(&self.drafts.starter_agent)
            .or_else(|| profiles.first());
        let override_count = profiles
            .iter()
            .filter(|profile| profile.mode_id == "override")
            .count();
        let custom_skill_count = profiles
            .iter()
            .filter(|profile| !profile.skills.is_empty())
            .count();
        let active_lane_count = profiles
            .iter()
            .filter(|profile| {
                self.snapshot
                    .sessions
                    .iter()
                    .any(|session| session.agent_profile_id.as_deref() == Some(profile.id.as_str()))
            })
            .count();
        let auth_gap_count = profiles
            .iter()
            .filter(|profile| self.profile_needs_auth(profile))
            .count();
        let route_gap_count = profiles
            .iter()
            .filter(|profile| self.profile_route_missing(profile))
            .count();
        let ready_reserve_count = profiles
            .iter()
            .filter(|profile| {
                self.profile_route_ready(profile) && self.profile_session_count(&profile.id) == 0
            })
            .count();
        let total_live_sessions = self.snapshot.sessions.len();
        let pressure_threshold = if active_lane_count == 0 {
            0
        } else {
            (total_live_sessions + active_lane_count - 1) / active_lane_count
        };
        let hot_lane_count = profiles
            .iter()
            .filter(|profile| {
                let session_count = self.profile_session_count(&profile.id);
                session_count > pressure_threshold && session_count > 0
            })
            .count();
        let hottest_lane = profiles
            .iter()
            .map(|profile| (profile, self.profile_session_count(&profile.id)))
            .filter(|(_, session_count)| *session_count > 0)
            .max_by_key(|(_, session_count)| *session_count);
        let load_shape = hottest_lane.map_or_else(
            || {
                self.tr(
                    "No active lane pressure yet",
                    "当前还没有形成活跃分工压力",
                )
                .to_string()
            },
            |(profile, session_count)| {
                self.tr(
                    &format!(
                        "{} is carrying {session_count} sessions across {total_live_sessions} live threads",
                        profile.display_name
                    ),
                    &format!(
                        "{} 当前承载 {session_count} 个会话，总活跃线程为 {total_live_sessions}",
                        profile.display_name
                    ),
                )
                .to_string()
            },
        );
        let intervention_label = if auth_gap_count > 0 {
            self.tr(
                &format!(
                    "Repair credentials on {auth_gap_count} lanes before promoting them into the working set."
                ),
                &format!("先修复 {auth_gap_count} 条分工的凭证，再把它们提入工作集。"),
            )
            .to_string()
        } else if route_gap_count > 0 {
            self.tr(
                &format!(
                    "{route_gap_count} lanes still have incomplete provider/model routes. Finish route setup before dispatch."
                ),
                &format!(
                    "还有 {route_gap_count} 条分工的 provider/model 路由不完整，分发前先把路由补齐。"
                ),
            )
            .to_string()
        } else if hot_lane_count > 0 && ready_reserve_count > 0 {
            self.tr(
                &format!(
                    "{hot_lane_count} lanes are carrying above-average load while {ready_reserve_count} ready lanes are idle. Shift the next thread into reserve."
                ),
                &format!(
                    "有 {hot_lane_count} 条分工负载高于平均值，而 {ready_reserve_count} 条就绪分工仍在待命。下一条线程应当向待命分工转移。"
                ),
            )
            .to_string()
        } else if total_live_sessions > 0 && ready_reserve_count == 0 {
            self.tr(
                "Every ready lane is already carrying load. Add capacity or keep concurrency selective.",
                "当前每条就绪分工都已经承载了负载，需要扩容，或者更谨慎地控制并发。",
            )
            .to_string()
        } else {
            self.tr(
                "Lane capacity is in a good state for the current workload.",
                "当前工作负载下，分工容量状态比较健康。",
            )
            .to_string()
        };

        let body = column![
            row![
                self.status_chip(self.tr(
                    &format!("{} lanes", profiles.len()),
                    &format!("{} 条分工", profiles.len()),
                )),
                self.status_chip(self.tr(
                    &format!("{active_lane_count} active"),
                    &format!("{active_lane_count} 条活跃"),
                )),
                self.status_chip(self.tr(
                    &format!("{ready_reserve_count} reserve"),
                    &format!("{ready_reserve_count} 条待命"),
                )),
                self.status_chip(self.tr(
                    &format!("{hot_lane_count} hot"),
                    &format!("{hot_lane_count} 条偏热"),
                )),
                if auth_gap_count + route_gap_count == 0 {
                    self.status_chip_success(self.tr(
                        &format!("{override_count} dedicated"),
                        &format!("{override_count} 条独立路由"),
                    ))
                } else {
                    self.status_chip_warning(self.tr(
                        &format!("{} blocked", auth_gap_count + route_gap_count),
                        &format!("{} 条阻塞", auth_gap_count + route_gap_count),
                    ))
                },
            ]
            .spacing(8)
            .wrap(),
            text(self.tr(
                "This is the staffing surface: decide which lanes stay shared, which graduate into dedicated routes, and where reserve capacity exists before new work lands.",
                "这里是编组管理面：在新工作落下之前，先决定哪些分工继续共享，哪些需要晋升为独立路由，以及哪里还有待命容量。",
            ))
            .font(self.ui_font())
            .size(12)
            .line_height(LineHeight::Relative(1.25))
            .style(style::secondary_text()),
            row![
                self.detail_row(
                    self.tr("Dispatch baseline", "分发基线"),
                    starter_profile.map_or_else(
                        || self.tr("Not configured", "未配置").to_string(),
                        |profile| format!(
                            "{} · {}",
                            profile.display_name,
                            self.agent_runtime_label(profile)
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Reserve capacity", "待命容量"),
                    self.tr(
                        &format!(
                            "{ready_reserve_count} idle ready · {auth_gap_count} auth gaps · {route_gap_count} route gaps"
                        ),
                        &format!(
                            "{ready_reserve_count} 条空闲就绪 · {auth_gap_count} 个鉴权缺口 · {route_gap_count} 个路由缺口"
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            row![
                self.detail_row(
                    self.tr("Policy split", "策略分布"),
                    self.tr(
                        &format!(
                            "{override_count} dedicated · {} follow main · {custom_skill_count} custom packs",
                            profiles.len().saturating_sub(override_count)
                        ),
                        &format!(
                            "{override_count} 条独立路由 · {} 条跟随主路由 · {custom_skill_count} 条带自定义包",
                            profiles.len().saturating_sub(override_count)
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Load shape", "负载形态"),
                    load_shape,
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            self.detail_row(self.tr("Intervention", "干预建议"), intervention_label),
            row![
                self.secondary_button(self.tr("Sessions", "会话"))
                    .on_press(Message::SelectTab(Tab::Sessions)),
                self.secondary_button(self.tr("Channels", "渠道"))
                    .on_press(Message::SelectTab(Tab::Channels)),
                self.secondary_button(self.tr("Security", "安全"))
                    .on_press(Message::SelectTab(Tab::Security)),
            ]
            .spacing(10),
        ]
        .spacing(12);

        self.panel_shell_with_subtitle(
            self.tr("Lane governance", "分工治理"),
            Some(self.tr("Capacity / reserve / policy", "容量 / 待命 / 策略")),
            body,
        )
    }

    fn agent_runtime_panel(&self) -> Container<'_, Message> {
        let Some(profile) = self.selected_agent_profile() else {
            return self.surface_card(
                self.tr("Selected lane", "当前分工"),
                self.tr(
                    "Choose a lane to inspect its route, dispatch eligibility, and attached packs.",
                    "选择一个分工后，这里会显示它的路由、分发资格和附加包状态。",
                ),
            );
        };

        let lane_count = self.profile_session_count(&profile.id);
        let runtime_label = self.agent_runtime_label(profile);
        let latest_session_title = self
            .profile_latest_session_title(&profile.id)
            .unwrap_or_else(|| self.tr("No live thread yet", "还没有活跃线程").to_string());
        let is_starter = profile.id == self.effective_starter_agent_id();
        let needs_auth = self.profile_needs_auth(profile);
        let route_missing = self.profile_route_missing(profile);
        let route_ready = self.profile_route_ready(profile);
        let route_source = if profile.mode_id == "override" {
            self.tr(
                "Dedicated provider/model for this lane",
                "这个分工使用独立的 provider/model 路由",
            )
            .to_string()
        } else {
            self.tr(
                "Follows the desktop default route",
                "这个分工跟随桌面默认路由",
            )
            .to_string()
        };
        let dispatch_state = if route_ready && lane_count == 0 {
            self.tr(
                "Ready reserve lane. It can accept new work immediately.",
                "这是一个待命且就绪的分工，可以立刻接手新工作。",
            )
            .to_string()
        } else if route_ready {
            self.tr(
                &format!("{lane_count} live sessions are currently using this lane."),
                &format!("当前有 {lane_count} 个活跃会话正在使用这个分工。"),
            )
            .to_string()
        } else if needs_auth {
            self.tr(
                "Credentials are missing for the resolved provider. This lane cannot be promoted yet.",
                "解析后的 provider 缺少凭证，这个分工暂时不能晋升到可分发状态。",
            )
            .to_string()
        } else if route_missing {
            self.tr(
                "Provider or model is still incomplete. Finish the route before dispatch.",
                "provider 或 model 还没有配置完整，分发前要先补齐路由。",
            )
            .to_string()
        } else {
            self.tr(
                "Route status is waiting on additional setup.",
                "当前路由状态还在等待进一步配置。",
            )
            .to_string()
        };
        let pack_summary = self
            .tr(
                &format!(
                    "{} custom skills · {} builtin skills · {} prompt packs",
                    profile.skills.len(),
                    profile.builtin_skills.len(),
                    profile.prompts.len()
                ),
                &format!(
                    "{} 个自定义技能 · {} 个内置技能 · {} 个提示包",
                    profile.skills.len(),
                    profile.builtin_skills.len(),
                    profile.prompts.len()
                ),
            )
            .to_string();

        let rows = column![
            row![
                self.status_chip(self.tr(
                    &format!("{lane_count} sessions"),
                    &format!("{lane_count} 个会话"),
                )),
                self.status_chip(profile.mode_label.clone()),
                if is_starter {
                    self.status_chip(self.tr("Starter", "默认"))
                } else {
                    self.status_chip(self.tr("Selected", "已选中"))
                },
                if route_ready {
                    if lane_count == 0 {
                        self.status_chip_success(self.tr("Reserve", "待命"))
                    } else {
                        self.status_chip_success(self.tr("Live", "运行中"))
                    }
                } else if needs_auth {
                    self.status_chip_warning(self.tr("Auth gap", "鉴权缺口"))
                } else {
                    self.status_chip_warning(self.tr("Needs route", "需要路由"))
                },
            ]
            .spacing(8)
            .wrap(),
            self.detail_row(self.tr("Editing", "当前编辑"), profile.display_name.clone()),
            self.detail_row(self.tr("Resolved runtime", "解析运行时"), runtime_label),
            self.detail_row(self.tr("Route source", "路由来源"), route_source),
            self.detail_row(self.tr("Dispatch state", "分发状态"), dispatch_state),
            self.detail_row(self.tr("Attached packs", "附加包"), pack_summary),
            self.detail_row(
                self.tr("Prompt packs", "提示包"),
                if profile.prompts.is_empty() {
                    self.tr("No prompts attached", "当前没有附加提示包")
                        .to_string()
                } else {
                    profile.prompts.join(", ")
                },
            ),
            self.detail_row(self.tr("Latest work", "最近工作"), latest_session_title),
            row![
                self.secondary_button(self.tr("Settings", "设置"))
                    .on_press(Message::SelectTab(Tab::Settings)),
                self.secondary_button(self.tr("Sessions", "会话"))
                    .on_press(Message::SelectTab(Tab::Sessions)),
                if needs_auth {
                    self.secondary_button(self.tr("Security", "安全"))
                        .on_press(Message::SelectTab(Tab::Security))
                } else {
                    self.secondary_button(self.tr("Channels", "渠道"))
                        .on_press(Message::SelectTab(Tab::Channels))
                },
                if is_starter {
                    self.inline_button(self.tr("Starter", "默认"))
                } else {
                    self.inline_button(self.tr("Set starter", "设为默认"))
                        .on_press(Message::PersistStarterAgent(profile.id.clone()))
                },
            ]
            .spacing(10)
            .wrap(),
        ]
        .spacing(12);

        self.panel_shell_with_subtitle(
            self.tr("Selected lane", "当前分工"),
            Some(self.tr(
                "Current route / packs / dispatch",
                "当前路由 / 附加包 / 分发",
            )),
            rows,
        )
    }

    fn channel_bindings_panel(&self) -> Container<'_, Message> {
        if self.snapshot.context.channel_bindings.is_empty() {
            return self.surface_card(
                self.tr("Channel board", "渠道看板"),
                self.tr(
                    "There are no editable bindings yet.",
                    "当前还没有可编辑的渠道绑定。",
                ),
            );
        }

        let rows = self.snapshot.context.channel_bindings.iter().fold(
            Column::new().spacing(10),
            |column, binding| {
                let is_selected = self.drafts.selected_channel_binding == binding.id;
                let selected_chip: Element<'_, Message> = if is_selected {
                    self.status_chip_success(self.tr("Open", "打开")).into()
                } else {
                    Space::with_width(Length::Shrink).into()
                };
                let target_profile = self.channel_binding_target_profile(binding);
                let target_chip: Element<'_, Message> = match target_profile {
                    None => self
                        .status_chip_warning(self.tr("Lane missing", "分工缺失"))
                        .into(),
                    Some(profile) if self.profile_needs_auth(profile) => self
                        .status_chip_warning(self.tr("Auth gap", "鉴权缺口"))
                        .into(),
                    Some(profile) if self.profile_route_missing(profile) => self
                        .status_chip_warning(self.tr("Route gap", "路由缺口"))
                        .into(),
                    Some(_) if binding.enabled && binding.status == "ready" => self
                        .status_chip_success(self.tr("Deployable", "可部署"))
                        .into(),
                    Some(_) => self.status_chip(self.tr("Lane ready", "分工已就绪")).into(),
                };
                let (required_fields, filled_required_fields, _) =
                    self.channel_binding_required_progress(binding);
                let runtime_message: Element<'_, Message> =
                    if let Some(message) = &binding.validation_message {
                        text(message)
                            .font(self.ui_font())
                            .size(12)
                            .style(style::accent_text())
                            .into()
                    } else {
                        text(&binding.runtime_support)
                            .font(self.ui_font())
                            .size(12)
                            .style(style::secondary_text())
                            .into()
                    };
                column.push(
                    container(
                        column![
                            row![
                                text(&binding.name)
                                    .font(self.ui_font())
                                    .size(14)
                                    .style(style::heading_text())
                                    .width(Length::Fill),
                                if binding.enabled {
                                    self.status_chip_success(self.tr("Enabled", "已启用"))
                                } else {
                                    self.status_chip_warning(self.tr("Disabled", "已关闭"))
                                },
                                target_chip,
                                self.status_chip(
                                    self.localized_channel_binding_status_label(&binding.status)
                                ),
                                selected_chip,
                            ]
                            .spacing(8)
                            .align_items(alignment::Alignment::Center),
                            text(&binding.note)
                                .font(self.ui_font())
                                .size(11)
                                .style(style::secondary_text()),
                            row![
                                self.status_chip(format!(
                                    "{} · {}",
                                    self.tr("Platform", "平台"),
                                    binding.platform
                                )),
                                self.status_chip(format!(
                                    "{} · {}",
                                    self.tr("Lane", "分工"),
                                    target_profile
                                        .map(|profile| profile.display_name.clone())
                                        .unwrap_or_else(|| binding.agent_profile.clone())
                                )),
                                self.status_chip(format!(
                                    "{} · {filled_required_fields}/{required_fields}",
                                    self.tr("Setup", "配置"),
                                )),
                            ]
                            .spacing(8)
                            .wrap(),
                            runtime_message,
                            row![
                                if is_selected {
                                    self.primary_button(self.tr("Open", "打开"))
                                } else {
                                    self.secondary_button(self.tr("Open", "打开"))
                                }
                                .on_press(Message::SelectChannelBinding(binding.id.clone())),
                            ]
                            .spacing(8),
                        ]
                        .spacing(6),
                    )
                    .padding([10, 12])
                    .style(style::list_row(is_selected)),
                )
            },
        );

        self.panel_shell_with_subtitle(
            self.tr("Route board", "路由看板"),
            Some(self.tr("Bindings / target lanes", "绑定 / 目标分工")),
            rows,
        )
    }

    fn channel_editor_panel(&self) -> Container<'_, Message> {
        let Some(binding) = self.selected_channel_binding() else {
            return self.surface_card(
                self.tr("Binding editor", "绑定编辑器"),
                self.tr(
                    "Select a channel binding to edit route, enablement, and required fields.",
                    "选择一个渠道绑定后，这里会显示它的路由、启用状态和必填字段。",
                ),
            );
        };

        let required_field_count = binding.fields.iter().filter(|field| field.required).count();
        let filled_required_field_count = binding
            .fields
            .iter()
            .filter(|field| field.required)
            .filter(
                |field| match self.drafts.channel_field_values.get(&field.id) {
                    Some(ChannelDraftValue::Text(value)) => !value.trim().is_empty(),
                    Some(ChannelDraftValue::Bool(value)) => *value,
                    None => false,
                },
            )
            .count();
        let missing_required = binding
            .fields
            .iter()
            .filter(|field| field.required)
            .filter_map(
                |field| match self.drafts.channel_field_values.get(&field.id) {
                    Some(ChannelDraftValue::Text(value)) if !value.trim().is_empty() => None,
                    Some(ChannelDraftValue::Bool(true)) => None,
                    _ => Some(field.label.clone()),
                },
            )
            .collect::<Vec<_>>();
        let setup_status = self.localized_channel_binding_status_label(&binding.status);

        let mut body = column![
            row![
                self.status_chip(binding.id.clone()),
                self.status_chip(binding.platform.clone()),
                self.status_chip(self.localized_channel_binding_status_label(&binding.status)),
            ]
            .spacing(8)
            .wrap(),
            self.action_block(
                self.tr("Route briefing", "路由简报"),
                Some(
                    self.tr(
                        "Bindings are external doors into the system. Keep the lane target and setup state explicit before enabling them.",
                        "绑定是系统对外的入口。在启用之前，请把目标分工和配置状态都整理清楚。",
                    )
                    .to_string(),
                ),
                column![
                    self.detail_row(
                        self.tr("Operator lane", "目标分工"),
                        self.drafts.channel_agent_profile.clone(),
                    ),
                    row![
                        self.compact_detail_row(
                            self.tr("Required", "必填"),
                            format!("{filled_required_field_count}/{required_field_count}"),
                        ),
                        self.compact_detail_row(
                            self.tr("Delivery", "投递能力"),
                            binding.runtime_support.clone(),
                        ),
                        self.compact_detail_row(
                            self.tr("State", "状态"),
                            setup_status.clone(),
                        ),
                    ]
                    .spacing(10)
                    .wrap(),
                    self.detail_row(
                        self.tr("Current blocker", "当前阻塞"),
                        binding.validation_message.clone().unwrap_or_else(|| {
                            self.tr("No blocking setup issue", "当前没有阻塞问题")
                                .to_string()
                        }),
                    ),
                ]
                .spacing(10)
                .into(),
            ),
            self.action_block(
                self.tr("Binding state", "绑定状态"),
                Some(
                    self.tr(
                        "Turn the route on only after its target lane and required fields are in place.",
                        "只有当目标分工和必填字段都准备好之后，再把这个路由打开。",
                    )
                    .to_string(),
                ),
                column![
                    self.editor_block(
                        self.tr("Enablement", "启用状态"),
                        Some(
                            self.tr(
                                "Disabled bindings stay visible in the desktop but do not receive or send live traffic.",
                                "关闭的绑定仍会在桌面中可见，但不会接收或发送实时流量。",
                            )
                            .to_string(),
                        ),
                        checkbox(
                            self.tr("Enable this binding", "启用这个渠道"),
                            self.drafts.channel_enabled,
                        )
                        .size(14)
                        .style(style::CheckboxStyle::Field)
                        .on_toggle(Message::ToggleChannelEnabled)
                        .into(),
                    ),
                    self.editor_block(
                        self.tr("Agent profile", "角色路由"),
                        Some(
                            self.tr(
                                "Pick the operator lane that should own this channel.",
                                "指定哪个 operator 分工来负责这个渠道。",
                            )
                            .to_string(),
                        ),
                        text_input("Agent profile", &self.drafts.channel_agent_profile)
                            .on_input(Message::UpdateChannelAgentProfile)
                            .style(style::TextInputStyle::Field)
                            .padding(12)
                            .into(),
                    ),
                ]
                .spacing(10)
                .into(),
            ),
        ]
        .spacing(12);

        let mut fields_body = Column::new().spacing(10);
        for field in &binding.fields {
            match field.kind {
                ChannelFieldKind::Text => {
                    let value = self.drafts.channel_text_value(&field.id);
                    fields_body = fields_body.push(
                        self.editor_block(
                            field.label.clone(),
                            Some(
                                if field.required {
                                    self.tr(
                                        "Required for this route to become ready.",
                                        "这个字段填写后，路由才能进入就绪状态。",
                                    )
                                } else {
                                    self.tr(
                                        "Optional metadata for this binding.",
                                        "这个字段是绑定的可选附加信息。",
                                    )
                                }
                                .to_string(),
                            ),
                            text_input(&field.label, &value)
                                .on_input({
                                    let field_id = field.id.clone();
                                    move |value| {
                                        Message::UpdateChannelField(field_id.clone(), value)
                                    }
                                })
                                .style(style::TextInputStyle::Field)
                                .padding(12)
                                .into(),
                        ),
                    );
                }
                ChannelFieldKind::Checkbox => {
                    let checked = self.drafts.channel_bool_value(&field.id);
                    fields_body = fields_body.push(
                        self.editor_block(
                            field.label.clone(),
                            Some(
                                if field.required {
                                    self.tr(
                                        "Required toggle for this route.",
                                        "这是这个路由所需的必填开关。",
                                    )
                                } else {
                                    self.tr(
                                        "Optional toggle for this binding.",
                                        "这是这个绑定的可选开关。",
                                    )
                                }
                                .to_string(),
                            ),
                            checkbox(field.label.clone(), checked)
                                .size(14)
                                .style(style::CheckboxStyle::Field)
                                .on_toggle({
                                    let field_id = field.id.clone();
                                    move |value| {
                                        Message::ToggleChannelField(field_id.clone(), value)
                                    }
                                })
                                .into(),
                        ),
                    );
                }
            }
        }

        body = body.push(
            self.action_block(
                self.tr("Setup fields", "配置字段"),
                Some(
                    self.tr(
                        "Only the platform-specific secrets and toggles this binding actually needs are shown here.",
                        "这里只有这个绑定真正需要的平台字段和开关，没有多余表单。",
                    )
                    .to_string(),
                ),
                fields_body.into(),
            ),
        );

        body = body.push(
            self.action_block(
                self.tr("Binding actions", "绑定动作"),
                Some(
                    self.tr(
                        "Save when the route target and required setup fields are in place.",
                        "当目标分工和必填配置都就位后，再保存这个绑定。",
                    )
                    .to_string(),
                ),
                column![
                    self.detail_row(
                        self.tr("Missing required", "缺失的必填项"),
                        if missing_required.is_empty() {
                            self.tr("No required fields missing", "当前没有缺失的必填项")
                                .to_string()
                        } else {
                            missing_required.join(" · ")
                        },
                    ),
                    row![
                        self.primary_button(self.tr("Save binding", "保存绑定"))
                            .on_press(Message::SaveChannelBinding),
                        self.secondary_button(self.tr("Reset draft", "重置草稿"))
                            .on_press(Message::ResetChannelBinding),
                        self.secondary_button(self.tr("Project settings", "项目设置"))
                            .on_press(Message::OpenPath(
                                self.snapshot.context.project_settings_path.clone()
                            )),
                    ]
                    .spacing(10)
                    .wrap(),
                ]
                .spacing(10)
                .into(),
            ),
        );

        self.panel_shell_with_subtitle(
            self.tr("Route setup", "路由设置"),
            Some(self.tr("Ingress / target / secrets", "入口 / 目标 / 凭证")),
            body,
        )
    }

    fn channel_route_topology_panel(&self) -> Container<'_, Message> {
        let context = &self.snapshot.context;
        let enabled_count = context
            .channel_bindings
            .iter()
            .filter(|binding| binding.enabled)
            .count();
        let ready_count = context
            .channel_bindings
            .iter()
            .filter(|binding| binding.status == "ready")
            .count();
        let send_only_count = context
            .channel_bindings
            .iter()
            .filter(|binding| binding.status == "send_only")
            .count();
        let partial_count = context
            .channel_bindings
            .iter()
            .filter(|binding| binding.status == "partial")
            .count();
        let setup_count = context
            .channel_bindings
            .iter()
            .filter(|binding| binding.status == "needs_setup")
            .count();
        let platform_count = context
            .channel_bindings
            .iter()
            .map(|binding| binding.platform.clone())
            .collect::<std::collections::BTreeSet<_>>()
            .len();
        let staffed_lane_count = context
            .channel_bindings
            .iter()
            .filter_map(|binding| self.channel_binding_target_profile(binding))
            .map(|profile| profile.id.clone())
            .collect::<std::collections::BTreeSet<_>>()
            .len();
        let missing_lane_count = context
            .channel_bindings
            .iter()
            .filter(|binding| self.channel_binding_target_profile(binding).is_none())
            .count();
        let auth_gap_count = context
            .channel_bindings
            .iter()
            .filter_map(|binding| self.channel_binding_target_profile(binding))
            .filter(|profile| self.profile_needs_auth(profile))
            .count();
        let route_gap_count = context
            .channel_bindings
            .iter()
            .filter_map(|binding| self.channel_binding_target_profile(binding))
            .filter(|profile| self.profile_route_missing(profile))
            .count();
        let selected = self.selected_channel_binding();
        let intervention_label = if setup_count > 0 {
            self.tr(
                &format!(
                    "{setup_count} bindings still need required setup. Finish those before expanding ingress."
                ),
                &format!(
                    "还有 {setup_count} 个绑定缺少必填配置，扩展入口之前先把这些补齐。"
                ),
            )
            .to_string()
        } else if missing_lane_count > 0 {
            self.tr(
                &format!(
                    "{missing_lane_count} bindings point to missing lanes. Reattach them before enabling delivery."
                ),
                &format!(
                    "有 {missing_lane_count} 个绑定指向了不存在的分工，启用交付前先把目标重新接好。"
                ),
            )
            .to_string()
        } else if auth_gap_count > 0 || route_gap_count > 0 {
            self.tr(
                &format!(
                    "{auth_gap_count} targets have auth gaps and {route_gap_count} still miss runtime routes."
                ),
                &format!(
                    "当前有 {auth_gap_count} 个目标存在鉴权缺口，另有 {route_gap_count} 个目标还缺少运行时路由。"
                ),
            )
            .to_string()
        } else if send_only_count > 0 || partial_count > 0 {
            self.tr(
                &format!(
                    "{send_only_count} send-only and {partial_count} partial routes still need policy review before they count as full ingress."
                ),
                &format!(
                    "还有 {send_only_count} 个仅发送和 {partial_count} 个部分能力路由，需要策略复核后才能算作完整入口。"
                ),
            )
            .to_string()
        } else {
            self.tr(
                "Route coverage is in a healthy state for the current ingress surface.",
                "当前入口面的路由覆盖状态比较健康。",
            )
            .to_string()
        };

        let body = column![
            row![
                self.status_chip(self.tr(
                    &format!("{enabled_count} enabled"),
                    &format!("{enabled_count} 个已启用"),
                )),
                self.status_chip_success(self.tr(
                    &format!("{ready_count} ready"),
                    &format!("{ready_count} 个就绪"),
                )),
                self.status_chip(self.tr(
                    &format!("{send_only_count} send-only"),
                    &format!("{send_only_count} 个仅发送"),
                )),
                if setup_count + missing_lane_count + auth_gap_count + route_gap_count == 0 {
                    self.status_chip_success(self.tr(
                        &format!("{staffed_lane_count} staffed lanes"),
                        &format!("{staffed_lane_count} 条已编组"),
                    ))
                } else {
                    self.status_chip_warning(self.tr(
                        &format!(
                            "{} route debt",
                            setup_count + missing_lane_count + auth_gap_count + route_gap_count
                        ),
                        &format!(
                            "{} 项路由债务",
                            setup_count + missing_lane_count + auth_gap_count + route_gap_count
                        ),
                    ))
                },
            ]
            .spacing(8)
            .wrap(),
            text(self.tr(
                "Treat channels like governed ingress: every route needs clear target ownership, truthful delivery status, and visible setup debt before it is allowed to shape the system.",
                "把渠道当作受治理的入口：每条路由都需要明确的目标分工、真实的交付状态，以及可见的配置债务，然后才能影响整个系统。",
            ))
            .font(self.ui_font())
            .size(12)
            .line_height(LineHeight::Relative(1.25))
            .style(style::secondary_text()),
            row![
                self.detail_row(
                    self.tr("Coverage", "覆盖范围"),
                    self.tr(
                        &format!(
                            "{platform_count} platforms · {enabled_count} enabled · {staffed_lane_count} staffed lanes"
                        ),
                        &format!(
                            "{platform_count} 个平台 · {enabled_count} 个启用 · {staffed_lane_count} 条已编组"
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Delivery mix", "交付结构"),
                    self.tr(
                        &format!(
                            "{ready_count} full · {send_only_count} send-only · {partial_count} partial"
                        ),
                        &format!(
                            "{ready_count} 个完整 · {send_only_count} 个仅发送 · {partial_count} 个部分能力"
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            row![
                self.detail_row(
                    self.tr("Route debt", "路由债务"),
                    self.tr(
                        &format!(
                            "{setup_count} setup · {missing_lane_count} missing lanes · {auth_gap_count} auth gaps"
                        ),
                        &format!(
                            "{setup_count} 个待配置 · {missing_lane_count} 个分工缺失 · {auth_gap_count} 个鉴权缺口"
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Selected focus", "当前焦点"),
                    selected.map_or_else(
                        || self.tr("No binding open", "当前没有打开绑定").to_string(),
                        |binding| format!(
                            "{} · {}",
                            binding.name,
                            self.localized_channel_binding_status_label(&binding.status)
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            self.detail_row(self.tr("Intervention", "干预建议"), intervention_label),
            row![
                self.secondary_button(self.tr("Security", "安全"))
                    .on_press(Message::SelectTab(Tab::Security)),
                self.secondary_button(self.tr("Agents", "分工"))
                    .on_press(Message::SelectTab(Tab::Agents)),
                self.secondary_button(self.tr("Settings", "设置"))
                    .on_press(Message::OpenPath(context.project_settings_path.clone())),
                self.refresh_button(),
            ]
            .spacing(10),
        ]
        .spacing(12);

        self.panel_shell_with_subtitle(
            self.tr("Route governance", "路由治理"),
            Some(self.tr("Coverage / debt / targets", "覆盖 / 债务 / 目标")),
            body,
        )
    }

    fn channel_runtime_panel(&self) -> Container<'_, Message> {
        let context = &self.snapshot.context;
        let Some(binding) = self.selected_channel_binding() else {
            return self.surface_card(
                self.tr("Selected route", "当前路由"),
                self.tr(
                    "Select a route to inspect its lane target, delivery posture, and setup debt.",
                    "选择一条路由后，这里会显示它的目标分工、交付姿态和配置债务。",
                ),
            );
        };
        let target_profile = self.channel_binding_target_profile(binding);
        let (required_field_count, filled_required_count, missing_required) =
            self.channel_binding_required_progress(binding);
        let target_label = target_profile.map_or_else(
            || self.tr("Missing lane target", "缺少目标分工").to_string(),
            |profile| {
                format!(
                    "{} · {}",
                    profile.display_name,
                    self.agent_runtime_label(profile)
                )
            },
        );
        let route_posture = if !binding.enabled {
            self.tr(
                "This route is disabled. It stays visible for planning but does not receive live traffic.",
                "这条路由当前已关闭。它会继续保留在桌面中做规划用途，但不会接收实时流量。",
            )
            .to_string()
        } else if target_profile.is_none() {
            self.tr(
                "The binding has no valid target lane. Reattach ownership before enabling delivery.",
                "这个绑定没有有效的目标分工。恢复交付前先把归属重新接上。",
            )
            .to_string()
        } else if target_profile.is_some_and(|profile| self.profile_needs_auth(profile)) {
            self.tr(
                "The target lane still lacks credentials, so this route cannot be treated as deployable.",
                "目标分工仍缺少凭证，因此这条路由还不能算作可部署入口。",
            )
            .to_string()
        } else if target_profile.is_some_and(|profile| self.profile_route_missing(profile)) {
            self.tr(
                "The target lane still has an incomplete provider or model route.",
                "目标分工的 provider 或 model 路由还没有配置完整。",
            )
            .to_string()
        } else {
            match binding.status.as_str() {
                "ready" => self
                    .tr(
                        "The route and its target lane are both ready for full ingress.",
                        "这条路由及其目标分工都已就绪，可以承接完整入口流量。",
                    )
                    .to_string(),
                "send_only" => self
                    .tr(
                        "This route can deliver outward but does not yet qualify as full two-way ingress.",
                        "这条路由可以向外发送，但还不算完整的双向入口。",
                    )
                    .to_string(),
                "partial" => self
                    .tr(
                        "The route is partially configured. Treat it as experimental until delivery semantics are complete.",
                        "这条路由仍是部分配置，在交付语义完整前应当视作实验态。",
                    )
                    .to_string(),
                _ => self
                    .tr(
                        "The route is still blocked by setup or validation.",
                        "这条路由仍被配置或校验问题阻塞。",
                    )
                    .to_string(),
            }
        };
        let blocker_label = if !missing_required.is_empty() {
            missing_required.join(" · ")
        } else {
            binding.validation_message.clone().unwrap_or_else(|| {
                self.tr("No blocking validation issue", "当前没有阻塞问题")
                    .to_string()
            })
        };

        let rows = column![
            row![
                self.status_chip(binding.platform.clone()),
                if binding.enabled {
                    self.status_chip_success(self.tr("Enabled", "已启用"))
                } else {
                    self.status_chip_warning(self.tr("Disabled", "已关闭"))
                },
                self.status_chip(self.localized_channel_binding_status_label(&binding.status)),
                match target_profile {
                    None => self.status_chip_warning(self.tr("Lane missing", "分工缺失")),
                    Some(profile) if self.profile_needs_auth(profile) => {
                        self.status_chip_warning(self.tr("Auth gap", "鉴权缺口"))
                    }
                    Some(profile) if self.profile_route_missing(profile) => {
                        self.status_chip_warning(self.tr("Route gap", "路由缺口"))
                    }
                    Some(_) => self.status_chip_success(self.tr("Lane ready", "分工已就绪")),
                },
            ]
            .spacing(8)
            .wrap(),
            self.detail_row(self.tr("Binding", "绑定"), binding.name.clone()),
            self.detail_row(self.tr("Target lane", "目标分工"), target_label),
            self.detail_row(self.tr("Delivery posture", "交付姿态"), route_posture),
            self.detail_row(
                self.tr("Required setup", "必填配置"),
                if required_field_count == 0 {
                    self.tr("No required fields", "当前没有必填字段")
                        .to_string()
                } else {
                    self.tr(
                        &format!(
                            "{filled_required_count}/{required_field_count} required fields ready"
                        ),
                        &format!("{filled_required_count}/{required_field_count} 个必填字段已就绪"),
                    )
                    .to_string()
                },
            ),
            self.detail_row(
                self.tr("Runtime handoff", "运行时转交"),
                binding.runtime_support.clone(),
            ),
            self.detail_row(self.tr("Current blocker", "当前阻塞"), blocker_label),
            row![
                self.secondary_button(self.tr("Agents", "分工"))
                    .on_press(Message::SelectTab(Tab::Agents)),
                self.secondary_button(self.tr("Security", "安全"))
                    .on_press(Message::SelectTab(Tab::Security)),
                self.secondary_button(self.tr("Project settings", "项目设置"))
                    .on_press(Message::OpenPath(context.project_settings_path.clone())),
                self.refresh_button(),
            ]
            .spacing(10)
            .wrap(),
        ]
        .spacing(12);

        self.panel_shell_with_subtitle(
            self.tr("Selected route", "当前路由"),
            Some(self.tr("Target / posture / blocker", "目标 / 姿态 / 阻塞")),
            rows,
        )
    }

    fn security_command_center_panel(&self) -> Container<'_, Message> {
        let security = &self.snapshot.context.security;
        let bridge = &self.snapshot.context.local_bridge;
        let runtime = &self.snapshot.runtime;
        let assessment = build_security_assessment(security, bridge, runtime);
        let allowed_decisions = security
            .permission_decisions
            .iter()
            .filter(|decision| decision.allow)
            .count();
        let driver_rows =
            assessment
                .drivers
                .iter()
                .take(3)
                .fold(Column::new().spacing(8), |column, driver| {
                    column.push(
                        container(
                            column![
                                text(self.localized_security_assessment_driver_label(*driver))
                                    .font(self.ui_font())
                                    .size(12)
                                    .style(style::heading_text()),
                                text(self.localized_security_assessment_driver_detail(*driver))
                                    .font(self.ui_font())
                                    .size(11)
                                    .line_height(LineHeight::Relative(1.2))
                                    .style(style::secondary_text()),
                            ]
                            .spacing(5),
                        )
                        .padding([10, 12])
                        .style(style::subtle_card()),
                    )
                });
        let optimization_actions: Element<'_, Message> = if assessment.recommendations.is_empty() {
            container(
                text(self.tr(
                    "No immediate hardening change is required. Keep this posture narrow and intentional.",
                    "当前不需要立刻硬化。保持这个姿态收敛且有意识即可。",
                ))
                .font(self.ui_font())
                .size(11)
                .line_height(LineHeight::Relative(1.2))
                .style(style::secondary_text()),
            )
            .padding([10, 12])
            .style(style::subtle_card())
            .into()
        } else {
            assessment
                .recommendations
                .iter()
                .take(4)
                .fold(row![].spacing(8).wrap(), |row, recommendation| {
                    row.push(self.security_recommendation_button(*recommendation))
                })
                .into()
        };

        let body = column![
            row![
                self.security_assessment_chip(&assessment),
                self.status_chip(format!(
                    "{} · {}",
                    self.tr("Sandbox", "沙箱"),
                    security.sandbox_mode
                )),
                self.status_chip(format!(
                    "{} · {}",
                    self.tr("Gateway", "网关"),
                    self.localized_gateway_health_label(security.gateway.health)
                )),
                self.status_chip(format!(
                    "{} · {}",
                    self.tr("Bridge", "Bridge"),
                    self.localized_local_bridge_status_label(bridge)
                )),
            ]
            .spacing(8)
            .wrap(),
            text(self.localized_security_assessment_summary(&assessment))
                .font(self.ui_font())
                .size(12)
                .line_height(LineHeight::Relative(1.25))
                .style(style::secondary_text()),
            row![
                self.detail_row(
                    self.tr("Active posture", "当前姿态"),
                    format!("{} · {}", security.profile, security.sandbox_mode)
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Remote surface", "远程面"),
                    format!(
                        "{} · {}",
                        self.localized_gateway_remote_label(&security.gateway),
                        self.localized_local_bridge_link_label(bridge)
                    ),
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            row![
                self.detail_row(
                    self.tr("Stored grants", "已存授权"),
                    self.tr(
                        &format!(
                            "{allowed_decisions} allow · {} auth sources",
                            security.auth_provider_count
                        ),
                        &format!(
                            "{allowed_decisions} 条允许 · {} 个凭据源",
                            security.auth_provider_count
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Runtime edge", "运行时边界"),
                    self.tr(
                        &format!(
                            "{} heartbeat · {} bridge process",
                            self.localized_heartbeat_label(runtime.heartbeat),
                            runtime.bridge_processes
                        ),
                        &format!(
                            "{} 心跳 · {} 个 bridge 进程",
                            self.localized_heartbeat_label(runtime.heartbeat),
                            runtime.bridge_processes
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            self.action_block(
                self.tr("Risk drivers", "风险驱动"),
                Some(self.tr(
                    "These are the concrete factors currently widening or constraining the surface.",
                    "这些就是当前正在扩大或收紧安全面的具体因素。",
                )
                .to_string()),
                driver_rows.into(),
            ),
            self.action_block(
                self.tr("Optimization plan", "优化方案"),
                Some(self.tr(
                    "Use the first one or two actions to collapse risk quickly instead of manually hunting settings.",
                    "优先执行前 1 到 2 个动作，直接压缩风险，而不是手动去翻配置。",
                )
                .to_string()),
                optimization_actions,
            ),
        ]
        .spacing(12);

        self.panel_shell_with_subtitle(
            self.tr("Security command center", "安全指挥台"),
            Some(self.localized_security_assessment_title(&assessment)),
            body,
        )
    }

