    fn gateway_access_panel(&self) -> Container<'_, Message> {
        let gateway = &self.snapshot.context.security.gateway;
        let bindings = &self.snapshot.context.channel_bindings;
        let token_ready = gateway.auth_mode == "token"
            && gateway
                .auth_token
                .as_deref()
                .is_some_and(|value| !value.trim().is_empty());
        let enabled_binding_count = bindings.iter().filter(|binding| binding.enabled).count();
        let ready_binding_count = bindings
            .iter()
            .filter(|binding| matches!(binding.status.as_str(), "ready" | "send_only"))
            .count();
        let send_only_count = bindings
            .iter()
            .filter(|binding| binding.status == "send_only")
            .count();
        let partial_count = bindings
            .iter()
            .filter(|binding| binding.status == "partial")
            .count();
        let needs_setup_count = bindings
            .iter()
            .filter(|binding| binding.status == "needs_setup")
            .count();
        let preset_cards = row![
            self.gateway_preset_button(
                GatewayPresetMode::Disabled,
                self.tr("Disabled", "关闭"),
                self.localized_gateway_preset_description(GatewayPresetMode::Disabled),
            ),
            self.gateway_preset_button(
                GatewayPresetMode::LocalOnly,
                self.tr("Local only", "仅本机"),
                self.localized_gateway_preset_description(GatewayPresetMode::LocalOnly),
            ),
            self.gateway_preset_button(
                GatewayPresetMode::Tailscale,
                self.tr("Remote via Tailscale", "通过 Tailscale 远程"),
                self.localized_gateway_preset_description(GatewayPresetMode::Tailscale),
            ),
            self.gateway_preset_button(
                GatewayPresetMode::Custom,
                self.tr("Custom advanced", "高级自定义"),
                self.localized_gateway_preset_description(GatewayPresetMode::Custom),
            ),
        ]
        .spacing(10)
        .wrap();

        let diagnostics =
            gateway
                .diagnostics
                .iter()
                .take(3)
                .fold(Column::new().spacing(8), |column, item| {
                    column.push(self.detail_row(self.tr("Gateway note", "网关提示"), item.clone()))
                });
        let diagnostics_section: Element<'_, Message> = if gateway.diagnostics.is_empty() {
            Space::with_height(Length::Shrink).into()
        } else {
            self.action_block(self.tr("Diagnostics", "诊断"), None, diagnostics.into())
                .into()
        };

        let advanced_editor: Element<'_, Message> = if self.drafts.security_gateway_show_advanced {
            self.editor_block(
                self.tr("Custom endpoint", "自定义入口"),
                None,
                text_input(
                    "https://gateway.example/v1",
                    &self.drafts.security_gateway_custom_url,
                )
                .on_input(Message::UpdateGatewayCustomUrl)
                .style(style::TextInputStyle::Field)
                .padding(12)
                .into(),
            )
            .into()
        } else {
            Space::with_height(Length::Shrink).into()
        };

        let body = column![
            row![
                self.status_chip(format!(
                    "{} · {}",
                    self.tr("Preset", "模式"),
                    self.localized_gateway_preset_label(gateway.preset)
                )),
                self.status_chip(format!(
                    "{} · {}",
                    self.tr("Health", "健康"),
                    self.localized_gateway_health_label(gateway.health)
                )),
                self.status_chip(gateway.checked_label()),
                self.status_chip(self.tr(
                    if token_ready {
                        "Token ready"
                    } else {
                        "Token missing"
                    },
                    if token_ready {
                        "Token 已就绪"
                    } else {
                        "Token 缺失"
                    }
                )),
                self.status_chip(self.tr(
                    &format!("{enabled_binding_count} bindings enabled"),
                    &format!("{enabled_binding_count} 个绑定已启用"),
                )),
            ]
            .spacing(10)
            .wrap(),
            text(self.tr(
                "This is the operator surface for remote gateway policy and external runtime handoff. The localhost bridge is managed separately above, so this panel stays focused on outbound gateway posture.",
                "这里负责远程网关策略和外部运行时转交。上方的 localhost bridge 单独管理，这里只聚焦出站网关姿态。",
            ))
            .font(self.ui_font())
            .size(12)
            .line_height(LineHeight::Relative(1.25))
            .style(style::secondary_text()),
            preset_cards,
            row![
                self.detail_row(
                    self.tr("Binding readiness", "绑定就绪度"),
                    self.tr(
                        &format!(
                            "{enabled_binding_count} enabled · {ready_binding_count} ready · {needs_setup_count} need setup"
                        ),
                        &format!(
                            "{enabled_binding_count} 个启用 · {ready_binding_count} 个就绪 · {needs_setup_count} 个待配置"
                        ),
                    ),
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Route types", "路由类型"),
                    self.tr(
                        &format!("{send_only_count} send-only · {partial_count} partial"),
                        &format!("{send_only_count} 个仅发送 · {partial_count} 个部分能力"),
                    ),
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            self.detail_row(
                self.tr("Next step", "下一步"),
                self.localized_gateway_rollout_step(gateway)
            ),
            row![
                self.detail_row(
                    self.tr("Effective endpoint", "当前入口"),
                    gateway.effective_endpoint.clone()
                )
                .width(Length::FillPortion(1)),
                self.detail_row(
                    self.tr("Gateway token", "网关令牌"),
                    gateway.masked_token()
                )
                .width(Length::FillPortion(1)),
            ]
            .spacing(10),
            row![
                self.detail_row(self.tr("Bind policy", "绑定策略"), gateway.bind.clone()),
                self.detail_row(
                    self.tr("Remote access", "远程访问"),
                    self.localized_gateway_remote_label(gateway)
                ),
            ]
            .spacing(10),
            self.detail_row(
                self.tr("Trusted proxies", "信任代理"),
                if gateway.trusted_proxies.is_empty() {
                    self.tr("None", "无").to_string()
                } else {
                    gateway.trusted_proxies.join(", ")
                }
            ),
            diagnostics_section,
            advanced_editor,
            row![
                self.primary_button(self.tr("Save gateway + security", "保存网关与安全"))
                    .on_press(Message::SaveSecuritySettings),
                self.secondary_button(self.tr("Open channels", "打开渠道"))
                    .on_press(Message::SelectTab(Tab::Channels)),
                self.secondary_button(self.tr("Check gateway", "检查网关"))
                    .on_press(Message::RunGatewayHealthCheck),
                self.secondary_button(self.tr("Copy config", "复制配置"))
                    .on_press(Message::CopyGatewayConfig),
                self.secondary_button(self.tr("Copy token", "复制令牌"))
                    .on_press(Message::CopyGatewayToken),
                self.secondary_button(self.tr("Rotate token", "轮换令牌"))
                    .on_press(Message::RotateGatewayToken),
                self.secondary_button(self.tr("Advanced", "高级"))
                    .on_press(Message::ToggleGatewayAdvanced),
            ]
            .spacing(10)
            .wrap(),
        ]
        .spacing(12);

        self.panel_shell_with_subtitle(
            self.tr("External runtime bridge", "外部运行时桥接"),
            Some(self.tr(
                "Gateway / ACP-style handoff / channels",
                "网关 / ACP 风格转交 / 渠道",
            )),
            body,
        )
    }

    fn security_decisions_panel(&self) -> Container<'_, Message> {
        let security = &self.snapshot.context.security;
        if security.permission_decisions.is_empty() {
            return self.surface_card(
                self.tr("Capability decisions", "能力决策"),
                self.tr(
                    "There are no stored extension capability decisions yet. The active profile is still carrying the policy.",
                    "当前还没有保存的扩展能力决策。权限仍会跟随当前 profile 生效。",
                ),
            );
        }

        let rows = security.permission_decisions.iter().take(10).fold(
            Column::new().spacing(10).push(
                row![
                    self.status_chip(self.tr(
                        &format!("{} stored", security.permission_decisions.len()),
                        &format!("{} 条已保存", security.permission_decisions.len()),
                    )),
                    self.status_chip(self.tr(
                        &format!("{} providers", security.auth_provider_count),
                        &format!("{} 个凭据源", security.auth_provider_count),
                    )),
                ]
                .spacing(8)
                .wrap(),
            ),
            |column, decision| {
                column.push(
                    container(
                        row![
                            column![
                                text(&decision.extension_id)
                                    .font(self.ui_font())
                                    .size(14)
                                    .style(style::heading_text()),
                                text(format!("{} · {}", decision.capability, decision.decided_at))
                                    .font(self.ui_font())
                                    .size(12)
                                    .style(style::secondary_text()),
                            ]
                            .spacing(4)
                            .width(Length::Fill),
                            self.status_chip(if decision.allow { "Allow" } else { "Deny" }),
                        ]
                        .align_items(alignment::Alignment::Center),
                    )
                    .padding([12, 14])
                    .style(style::subtle_card()),
                )
            },
        );

        self.panel_shell(self.tr("Capability decisions", "能力决策"), rows)
    }

