    fn verification_workflow_panel(&self) -> Container<'_, Message> {
        let recommendation = self.verification_recommendation.as_ref();
        let recommendation_error = self.verification_recommendation_error.as_ref();
        let recommended_profile = recommendation.map_or_else(
            || {
                if recommendation_error.is_some() && !self.verification_recommendation_busy {
                    self.tr("Manual", "手动").to_string()
                } else {
                    self.tr("Pending", "加载中").to_string()
                }
            },
            VerifyProfileRecommendation::profile_label,
        );
        let recommendation_reason = recommendation
            .map(|value| value.reason.clone())
            .unwrap_or_else(|| {
                if self.verification_recommendation_busy {
                    self.tr(
                        "Inspecting the workspace to recommend the fastest safe verification profile.",
                        "正在检查工作区，准备推荐最快且安全的验证配置。",
                    )
                    .to_string()
                } else if recommendation_error
                    .is_some_and(|error| error.contains("./verify is not available"))
                {
                    self.tr(
                        "This workspace does not expose the ./verify helper. You can still run or copy a profile manually.",
                        "当前工作区没有提供 ./verify 工具。你仍然可以手动运行或复制验证命令。",
                    )
                    .to_string()
                } else if let Some(error) = recommendation_error {
                    error.clone()
                } else {
                    self.tr(
                        "No recommendation is loaded yet. Refresh to inspect the current change surface.",
                        "当前还没有推荐结果。刷新后会重新检查改动范围。",
                    )
                    .to_string()
                }
            });
        let trigger_summary = recommendation.map_or_else(
            || {
                if recommendation_error.is_some() {
                    self.tr("Workspace probe unavailable.", "工作区探测当前不可用。")
                        .to_string()
                } else {
                    self.tr("No trigger files reported yet.", "当前还没有触发文件。")
                        .to_string()
                }
            },
            VerifyProfileRecommendation::trigger_summary,
        );
        let recommendation_status = if self.verification_recommendation_busy {
            self.status_chip(self.tr("Analyzing workspace", "正在分析工作区"))
        } else if recommendation_error.is_some() {
            self.status_chip_warning(self.tr("Probe unavailable", "探测不可用"))
        } else if let Some(recommendation) = recommendation {
            match recommendation.profile.as_str() {
                "smoke" => self.status_chip_success(self.tr("Fast path", "快速路径")),
                "smoke-extended" | "quick" => {
                    self.status_chip(self.tr("Balanced path", "平衡路径"))
                }
                _ => self.status_chip(self.tr("Deep path", "深度路径")),
            }
        } else {
            self.status_chip(self.tr("Needs refresh", "需要刷新"))
        };

        let workflow_buttons = row![
            self.secondary_button(self.tr("Smoke", "冒烟")).on_press(
                Message::CopyVerificationCommand("./verify --profile smoke".to_string(),)
            ),
            self.secondary_button(self.tr("Extended", "扩展")).on_press(
                Message::CopyVerificationCommand("./verify --profile smoke-extended".to_string(),)
            ),
            self.secondary_button(self.tr("Quick", "快速")).on_press(
                Message::CopyVerificationCommand("./verify --profile quick".to_string(),)
            ),
            self.secondary_button(self.tr("Full", "完整"))
                .on_press(Message::CopyVerificationCommand("./verify".to_string())),
            self.secondary_button(self.tr("Detect", "检测")).on_press(
                Message::CopyVerificationCommand("./verify --recommend-profile".to_string(),)
            ),
        ]
        .spacing(8)
        .wrap();

        let recommendation_helper_card = recommendation_error.map(|error| {
            let summary = if error.contains("./verify is not available") {
                self.tr(
                    "No project verification helper was found here, so recommendation remains optional.",
                    "当前仓库没有项目级验证工具，因此推荐流程会自动退化为可选提示。",
                )
                .to_string()
            } else {
                error.clone()
            };
            container(
                text(summary)
                    .font(self.ui_font())
                    .size(12)
                    .line_height(LineHeight::Relative(1.2))
                    .style(style::secondary_text()),
            )
            .padding([10, 12])
            .style(style::subtle_card())
        });

        let mut body = column![
            row![
                self.status_chip(self.tr("Verification ladder", "验证阶梯")),
                recommendation_status,
                self.status_chip(format!(
                    "{} {}",
                    self.tr("Recommended:", "推荐："),
                    recommended_profile
                )),
            ]
            .spacing(8)
            .wrap(),
            self.detail_row(self.tr("Recommendation", "当前推荐"), recommendation_reason),
            self.detail_row(self.tr("Trigger files", "触发文件"), trigger_summary),
            workflow_buttons,
            row![
                self.secondary_button(self.tr("Copy repo root", "复制仓库根目录"))
                    .on_press(Message::CopyVerificationCommand(
                        self.snapshot.context.cwd.clone(),
                    )),
                self.secondary_button(self.tr("Open repo root", "打开仓库根目录"))
                    .on_press(Message::OpenPath(self.snapshot.context.cwd.clone())),
                if self.verification_recommendation_busy {
                    self.secondary_button(self.tr("Refreshing...", "刷新中"))
                } else {
                    self.secondary_button(self.tr("Refresh recommendation", "刷新推荐"))
                        .on_press(Message::RequestVerificationRecommendation)
                },
            ]
            .spacing(10)
            .wrap(),
        ]
        .spacing(12);

        if let Some(card) = recommendation_helper_card {
            body = body.push(card);
        }

        self.panel_shell(self.tr("Verification", "验证"), body)
    }

