    fn workspace_panel(&self) -> Container<'_, Message> {
        if self.snapshot.top_workspaces().is_empty() {
            return self.panel_shell_with_subtitle(
                self.tr("Workspaces", "工作目录"),
                Some(self.tr("No active workspace", "暂无活跃目录")),
                Column::new().push(
                    text(self.tr(
                        "After you create desktop sessions, this list groups them by cwd automatically.",
                        "创建新的桌面会话后，这里会根据 CWD 自动分组。",
                    ))
                        .style(style::secondary_text()),
                ),
            );
        }

        let rows = self.snapshot.top_workspaces().iter().take(4).fold(
            Column::new().spacing(12),
            |col, ws| {
                let is_focused = self.drafts.workspace_focus == ws.cwd;
                col.push(
                    container(
                        column![
                            column![
                                text(ws.title()).style(style::heading_text()),
                                text(format!(
                                    "{} 会话 · {} 条 · {}",
                                    ws.session_count,
                                    ws.total_messages,
                                    ws.last_active_label()
                                ))
                                .size(13)
                                .style(style::secondary_text()),
                                text(compact_middle(&ws.cwd, 48))
                                    .size(12)
                                    .style(style::accent_text()),
                            ]
                            .spacing(4),
                            row![
                                if is_focused {
                                    self.primary_button(self.tr("Focused", "已聚焦"))
                                } else {
                                    self.secondary_button(self.tr("Focus sessions", "聚焦会话"))
                                }
                                .on_press(Message::FocusWorkspace(ws.cwd.clone())),
                                self.secondary_button(self.tr("Open folder", "打开目录"))
                                    .on_press(Message::OpenPath(ws.cwd.clone())),
                            ]
                            .spacing(10),
                        ]
                        .spacing(10),
                    )
                    .padding([14, 16])
                    .style(style::subtle_card()),
                )
            },
        );

        self.panel_shell_with_subtitle(
            self.tr("Workspaces", "工作目录"),
            Some(self.tr("Workspace groups", "工作区分组")),
            rows,
        )
    }

    fn timeline_panel(&self) -> Container<'_, Message> {
        let latest_title = self
            .snapshot
            .latest_session()
            .map(|session| session.title.as_str())
            .unwrap_or("等待第一条桌面对话");
        let workspace_title = self
            .snapshot
            .top_workspaces()
            .first()
            .map(WorkspaceAggregate::title)
            .unwrap_or_else(|| "等待工作目录".to_string());
        let workspace_label = self
            .snapshot
            .top_workspaces()
            .first()
            .map(WorkspaceAggregate::last_active_label)
            .unwrap_or_else(|| "暂无".to_string());

        let events = [
            (
                self.snapshot.collected_label(),
                "索引".to_string(),
                "桌面快照已重建".to_string(),
            ),
            (
                self.snapshot.stats.last_activity_label(),
                "会话".to_string(),
                latest_title.to_string(),
            ),
            (workspace_label, "目录".to_string(), workspace_title),
        ];

        let rows = events
            .iter()
            .fold(Column::new().spacing(12), |col, (ts, scope, desc)| {
                col.push(
                    container(
                        row![
                            text(ts.clone()).style(style::secondary_text()),
                            container(text(scope.clone()).size(12).style(style::accent_text()))
                                .padding([4, 10])
                                .style(style::status_chip()),
                            text(desc.clone()).style(style::heading_text()),
                        ]
                        .spacing(12)
                        .align_items(alignment::Alignment::Center),
                    )
                    .padding([12, 14])
                    .style(style::subtle_card()),
                )
            });

        self.panel_shell("现场播报", rows)
    }

