    fn panel_shell_with_subtitle<'a>(
        &self,
        title: &str,
        subtitle: Option<&str>,
        body: Column<'a, Message>,
    ) -> Container<'a, Message> {
        let header: Element<'a, Message> = subtitle
            .filter(|label| !label.trim().is_empty())
            .map_or_else(
                || {
                    text(title)
                        .font(self.ui_font())
                        .size(14)
                        .style(style::heading_text())
                        .into()
                },
                |label| {
                    column![
                        text(label)
                            .font(self.ui_font())
                            .size(10)
                            .style(style::secondary_text()),
                        text(title)
                            .font(self.ui_font())
                            .size(14)
                            .style(style::heading_text()),
                    ]
                    .spacing(3)
                    .into()
                },
            );

        container(column![header, body].spacing(8))
            .padding([10, 12])
            .style(style::section_card())
    }

