#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct VerifyProfileRecommendation {
    schema: String,
    profile: String,
    reason: String,
    trigger_files: Vec<String>,
}

impl VerifyProfileRecommendation {
    fn profile_label(&self) -> String {
        self.profile.replace('-', " ")
    }

    fn trigger_summary(&self) -> String {
        if self.trigger_files.is_empty() {
            return "working tree only".to_string();
        }
        let mut files = self
            .trigger_files
            .iter()
            .take(4)
            .cloned()
            .collect::<Vec<_>>();
        if self.trigger_files.len() > files.len() {
            files.push(format!("+{} more", self.trigger_files.len() - files.len()));
        }
        files.join(" · ")
    }
}

