struct ControlWorkbenchSystem {
    system_id: String,
    vault_snapshots: Vec<VaultSnapshot>,
    vault_branches: Vec<VaultBranch>,
    artifacts: Vec<DurableArtifact>,
    memory_partitions: Vec<WorkbenchMemoryPartition>,
    automations: Vec<Automation>,
}

impl ControlWorkbenchSystem {
    fn memory_partition(
        &self,
        partition: crate::memory_v2::MemoryPartition,
    ) -> Option<&WorkbenchMemoryPartition> {
        self.memory_partitions
            .iter()
            .find(|candidate| candidate.partition == partition)
    }

    fn total_memory_entries(&self) -> usize {
        self.memory_partitions
            .iter()
            .map(|partition| partition.entries.len())
            .sum()
    }

    fn frozen_memory_entries(&self) -> usize {
        self.memory_partitions
            .iter()
            .map(|partition| partition.frozen_count)
            .sum()
    }

    fn populated_memory_partition_count(&self) -> usize {
        self.memory_partitions
            .iter()
            .filter(|partition| !partition.entries.is_empty())
            .count()
    }

    fn enabled_automation_count(&self) -> usize {
        self.automations
            .iter()
            .filter(|automation| automation.enabled)
            .count()
    }
}

