#[derive(Debug, Clone, Default)]
struct ControlPlaneSnapshot {
    triage: Option<ControlPlaneTriage>,
    readiness: Vec<ReadinessCheck>,
    tasks: Vec<ControlTask>,
    workers: Vec<ControlWorker>,
    artifacts: Vec<ControlArtifact>,
    approvals: Vec<ControlApproval>,
}

impl ControlPlaneSnapshot {
    fn readiness_counts(&self) -> (usize, usize, usize) {
        let mut ready = 0usize;
        let mut attention = 0usize;
        let mut blocked = 0usize;
        for item in &self.readiness {
            match item.state {
                ReadinessState::Ready => ready += 1,
                ReadinessState::Attention => attention += 1,
                ReadinessState::Blocked => blocked += 1,
            }
        }
        (ready, attention, blocked)
    }

    fn task_count(&self, status: TaskLifecycleState) -> usize {
        self.tasks
            .iter()
            .filter(|task| task.status == status)
            .count()
    }

    fn verified_artifact_count(&self) -> usize {
        self.artifacts
            .iter()
            .filter(|artifact| artifact.state == ArtifactState::Verified)
            .count()
    }
}

