#[derive(Debug, Clone)]
struct GatewayAccessState {
    preset: GatewayPresetMode,
    bind: String,
    auth_mode: String,
    auth_token: Option<String>,
    allow_tailscale: bool,
    tailscale_mode: String,
    trusted_proxies: Vec<String>,
    custom_url: String,
    effective_endpoint: String,
    health: GatewayHealthState,
    diagnostics: Vec<String>,
    checked_at_ms: i64,
}

impl Default for GatewayAccessState {
    fn default() -> Self {
        Self {
            preset: GatewayPresetMode::Disabled,
            bind: "loopback".to_string(),
            auth_mode: "token".to_string(),
            auth_token: None,
            allow_tailscale: false,
            tailscale_mode: "serve".to_string(),
            trusted_proxies: vec!["127.0.0.1".to_string()],
            custom_url: String::new(),
            effective_endpoint: "Direct provider access".to_string(),
            health: GatewayHealthState::Disabled,
            diagnostics: vec!["Gateway is disabled. Provider traffic stays direct.".to_string()],
            checked_at_ms: current_epoch_ms(),
        }
    }
}

impl GatewayAccessState {
    fn masked_token(&self) -> String {
        self.auth_token
            .as_deref()
            .map(mask_gateway_token)
            .unwrap_or_else(|| "Not generated".to_string())
    }

    fn checked_label(&self) -> String {
        relative_time_label(self.checked_at_ms)
    }

    fn remote_access_label(&self) -> &'static str {
        match self.preset {
            GatewayPresetMode::Disabled => "direct only",
            GatewayPresetMode::LocalOnly => "local desktop only",
            GatewayPresetMode::Tailscale => "tailscale serve",
            GatewayPresetMode::Custom => "managed custom endpoint",
        }
    }

    fn health_label(&self) -> &'static str {
        match self.health {
            GatewayHealthState::Disabled => "disabled",
            GatewayHealthState::PolicyReady => "policy ready",
            GatewayHealthState::Reachable => "reachable",
            GatewayHealthState::NeedsAttention => "needs attention",
            GatewayHealthState::Invalid => "invalid",
        }
    }

    fn effective_config_json(&self) -> Value {
        json!({
            "preset": self.preset.code(),
            "bind": self.bind,
            "auth": {
                "mode": self.auth_mode,
                "token": self.auth_token,
            },
            "allowTailscale": self.allow_tailscale,
            "tailscaleMode": self.tailscale_mode,
            "trustedProxies": self.trusted_proxies,
            "customUrl": if self.custom_url.trim().is_empty() {
                Value::Null
            } else {
                Value::String(self.custom_url.clone())
            },
            "effectiveEndpoint": self.effective_endpoint,
            "health": self.health_label(),
            "diagnostics": self.diagnostics,
        })
    }
}

