impl SessionRow {
    fn from_meta(meta: SessionMeta, header: SessionHeaderSummary) -> Self {
        let title = meta
            .name
            .clone()
            .filter(|s| !s.trim().is_empty())
            .unwrap_or_else(|| infer_title_from_cwd(&meta.cwd, &meta.id));

        Self {
            id: meta.id,
            title,
            cwd: meta.cwd,
            path: meta.path,
            message_count: meta.message_count,
            last_active_ms: meta.last_modified_ms,
            agent_profile_id: header.agent_profile_id,
            provider: header.provider,
            model: header.model,
            last_active_label: relative_time_label(meta.last_modified_ms),
        }
    }
}

impl DesktopContext {
    fn doctrine_file_count(&self) -> usize {
        [
            self.workspace_agents_exists,
            self.workspace_memory_exists,
            self.workspace_heartbeat_exists,
        ]
        .into_iter()
        .filter(|exists| *exists)
        .count()
    }

    fn channel_status_counts(&self) -> (usize, usize, usize, usize) {
        let ready = self
            .channel_bindings
            .iter()
            .filter(|binding| binding.status == "ready")
            .count();
        let send_only = self
            .channel_bindings
            .iter()
            .filter(|binding| binding.status == "send_only")
            .count();
        let partial = self
            .channel_bindings
            .iter()
            .filter(|binding| binding.status == "partial")
            .count();
        let needs_setup = self
            .channel_bindings
            .iter()
            .filter(|binding| binding.status == "needs_setup")
            .count();
        (ready, send_only, partial, needs_setup)
    }

    fn skill_trust_counts(&self) -> (usize, usize, usize) {
        let mut trusted = 0usize;
        let mut review = 0usize;
        let mut risky = 0usize;
        for skill in &self.discovered_skills {
            match skill.trust {
                SkillTrustLevel::Trusted => trusted += 1,
                SkillTrustLevel::Review => review += 1,
                SkillTrustLevel::Risky => risky += 1,
            }
        }
        (trusted, review, risky)
    }

    fn gather() -> Self {
        let cwd = native_workspace_root();
        let global_dir = Config::global_dir();
        let global_settings_path =
            Config::settings_path_with_roots(SettingsScope::Global, &global_dir, &cwd);
        let global_models_path = default_models_path(&global_dir);
        let project_settings_path =
            Config::settings_path_with_roots(SettingsScope::Project, &global_dir, &cwd);
        let config = Config::load_with_roots(
            Config::config_path_override_from_env(&cwd).as_deref(),
            &global_dir,
            &cwd,
        )
        .unwrap_or_default();

        let defaults = DesktopDefaultsState {
            default_provider_preset: infer_desktop_provider_preset_id(
                config.default_provider.as_deref().unwrap_or_default(),
                read_settings_string_aliases(&global_settings_path, &["providerPreset"]).as_deref(),
            ),
            default_provider: config.default_provider.clone().unwrap_or_default(),
            default_model: config.default_model.clone().unwrap_or_default(),
            default_base_url: load_provider_base_url_override(
                &global_models_path,
                config.default_provider.as_deref().unwrap_or_default(),
            )
            .unwrap_or_default(),
            starter_agent: config
                .starter_agent
                .clone()
                .unwrap_or_else(|| "main".to_string()),
            desktop_language: config
                .desktop_language
                .clone()
                .or_else(|| {
                    read_settings_string_aliases(
                        &global_settings_path,
                        &["desktop_language", "desktopLanguage"],
                    )
                })
                .filter(|value| !value.trim().is_empty())
                .unwrap_or_else(system_desktop_language_code),
            desktop_theme: read_settings_string_aliases(
                &global_settings_path,
                &["desktop_theme", "desktopTheme"],
            )
            .or_else(|| {
                config
                    .theme
                    .as_deref()
                    .and_then(DesktopThemeMode::parse)
                    .map(|mode| mode.code().to_string())
            })
            .unwrap_or_else(system_desktop_theme_code),
            check_for_updates: config.check_for_updates.unwrap_or(true),
            enable_skill_commands: config.enable_skill_commands(),
        };
        let onboarding = config.onboarding.clone().unwrap_or_default();
        let bridge = config.bridge.clone().unwrap_or_default();
        let system_registry = SystemRegistry::from_config(
            config.systems.as_deref(),
            config.active_system_id.as_deref(),
        );
        let active_system_id = system_registry
            .active_system()
            .map(|system| system.id.clone())
            .unwrap_or_else(|| "maoclaw-desktop".to_string());

        let registry = AgentProfileRegistry::from_config(&config);
        let agent_profiles = build_agent_profiles(&config, &registry);
        let channel_bindings = build_channel_bindings(&config);
        let security = build_security_state(&global_settings_path);
        let systems = build_system_summaries(
            &cwd,
            &active_system_id,
            config.systems.as_deref(),
            &defaults,
            &agent_profiles,
            &channel_bindings,
            &security,
        );
        let agent_choices = agent_profiles
            .iter()
            .map(|profile| AgentChoice {
                id: profile.id.clone(),
                display_name: profile.display_name.clone(),
            })
            .collect();

        let global_skill_paths = read_settings_string_array(&global_settings_path, "skills");
        let project_skill_paths = read_settings_string_array(&project_settings_path, "skills");
        let bundled_skill_catalog_roots = desktop_bundled_skill_catalog_roots(&cwd);
        let mut desktop_skill_paths = config
            .skills
            .clone()
            .unwrap_or_default()
            .into_iter()
            .map(|path| resolve_skill_path(&path, &cwd, &global_dir))
            .collect::<Vec<_>>();
        desktop_skill_paths.extend(bundled_skill_catalog_roots.iter().cloned());
        desktop_skill_paths = dedupe_desktop_paths(desktop_skill_paths);

        let skill_result = load_skills(LoadSkillsOptions {
            cwd: cwd.clone(),
            agent_dir: global_dir.clone(),
            skill_paths: desktop_skill_paths,
            include_defaults: true,
        });

        let discovered_skills = skill_result
            .skills
            .into_iter()
            .map(|skill| {
                let source = if is_under_any_path(&skill.file_path, &bundled_skill_catalog_roots) {
                    "bundle".to_string()
                } else {
                    skill.source
                };
                let (trust, trust_reason) = classify_discovered_skill(
                    &skill.file_path,
                    &source,
                    &cwd,
                    &global_dir,
                    &bundled_skill_catalog_roots,
                );
                DiscoveredSkill {
                    name: skill.name,
                    description: skill.description,
                    source,
                    path: skill.file_path.display().to_string(),
                    trust,
                    trust_reason,
                    disable_model_invocation: skill.disable_model_invocation,
                }
            })
            .collect::<Vec<_>>();

        let skill_diagnostics = skill_result
            .diagnostics
            .into_iter()
            .map(|diag| format!("{}: {}", diag.path.display(), diag.message))
            .collect();
        let workspace_agents_path = cwd.join("AGENTS.md");
        let workspace_memory_path = cwd.join("MEMORY.md");
        let workspace_heartbeat_path = cwd.join("HEARTBEAT.md");
        let workspace_daily_memory_root = cwd.join("memory");

        Self {
            cwd: cwd.display().to_string(),
            active_system_id: active_system_id.clone(),
            systems,
            onboarding: OnboardingState {
                completed: onboarding.completed.unwrap_or(false),
                version: onboarding.version,
                chosen_provider: onboarding.chosen_provider.unwrap_or_default(),
                chosen_model: onboarding.chosen_model.unwrap_or_default(),
                chosen_agent_profile: onboarding.chosen_agent_profile.unwrap_or_default(),
            },
            local_bridge: LocalBridgeState {
                enabled: bridge.enabled,
                port: bridge.port,
                control_plane_url: bridge.control_plane_url.unwrap_or_default(),
                device_label: bridge.device_label.unwrap_or_default(),
                device_id: bridge.device_id,
                allowed_scopes: bridge
                    .allowed_scopes
                    .iter()
                    .map(crate::bridge::BridgeScope::label)
                    .map(str::to_string)
                    .collect(),
            },
            global_settings_path: global_settings_path.display().to_string(),
            global_models_path: global_models_path.display().to_string(),
            project_settings_path: project_settings_path.display().to_string(),
            sessions_dir: Config::sessions_dir().display().to_string(),
            artifact_library_path: cwd
                .join(".pi")
                .join("artifacts")
                .join(&active_system_id)
                .display()
                .to_string(),
            vault_root_path: cwd.join(".pi").join("vault").display().to_string(),
            control_plane_state_path: cwd
                .join(".pi")
                .join("control-plane")
                .join("operator-console.json")
                .display()
                .to_string(),
            control_plane_workers_path: cwd
                .join(".pi")
                .join("control-plane")
                .join("workers.json")
                .display()
                .to_string(),
            workspace_agents_path: workspace_agents_path.display().to_string(),
            workspace_memory_path: workspace_memory_path.display().to_string(),
            workspace_heartbeat_path: workspace_heartbeat_path.display().to_string(),
            workspace_daily_memory_root: workspace_daily_memory_root.display().to_string(),
            workspace_agents_exists: workspace_agents_path.is_file(),
            workspace_memory_exists: workspace_memory_path.is_file(),
            workspace_heartbeat_exists: workspace_heartbeat_path.is_file(),
            workspace_daily_memory_note_count: count_markdown_files_in_dir(
                &workspace_daily_memory_root,
            ),
            global_skills_root: global_dir.join("skills").display().to_string(),
            project_skills_root: cwd
                .join(Config::project_dir())
                .join("skills")
                .display()
                .to_string(),
            bundled_skill_catalog_roots: bundled_skill_catalog_roots
                .iter()
                .map(|path| path.display().to_string())
                .collect(),
            agent_choices,
            agent_profiles,
            channel_bindings,
            security,
            discovered_skills,
            skill_diagnostics,
            defaults,
            global_skill_paths,
            project_skill_paths,
        }
    }

    fn agent_profile(&self, id: &str) -> Option<&AgentProfileSummary> {
        self.agent_profiles.iter().find(|profile| profile.id == id)
    }

    fn active_system(&self) -> Option<&SystemSummary> {
        self.systems
            .iter()
            .find(|system| system.is_active)
            .or_else(|| self.systems.first())
    }

    fn channel_binding(&self, id: &str) -> Option<&ChannelBindingSummary> {
        self.channel_bindings
            .iter()
            .find(|binding| binding.id == id)
    }
}

fn path_is_under(target: &Path, root: &Path) -> bool {
    let target = fs::canonicalize(target).unwrap_or_else(|_| target.to_path_buf());
    let root = fs::canonicalize(root).unwrap_or_else(|_| root.to_path_buf());
    target.starts_with(root)
}

fn is_under_any_path(target: &Path, roots: &[PathBuf]) -> bool {
    roots.iter().any(|root| path_is_under(target, root))
}

fn dedupe_desktop_paths(paths: Vec<PathBuf>) -> Vec<PathBuf> {
    let mut seen = HashSet::new();
    let mut deduped = Vec::new();
    for path in paths {
        let canonical = fs::canonicalize(&path).unwrap_or_else(|_| path.clone());
        if seen.insert(canonical) {
            deduped.push(path);
        }
    }
    deduped
}

fn classify_discovered_skill(
    path: &Path,
    source: &str,
    cwd: &Path,
    global_dir: &Path,
    bundled_skill_catalog_roots: &[PathBuf],
) -> (SkillTrustLevel, String) {
    let normalized = fs::canonicalize(path).unwrap_or_else(|_| path.to_path_buf());
    let normalized_lower = normalized.to_string_lossy().to_ascii_lowercase();
    let project_root = cwd.join(Config::project_dir()).join("skills");
    let global_root = global_dir.join("skills");

    if source == "bundle" || is_under_any_path(&normalized, bundled_skill_catalog_roots) {
        return (
            SkillTrustLevel::Trusted,
            "Bundled starter catalog shipped with the desktop.".to_string(),
        );
    }

    if source == "project" || path_is_under(&normalized, &project_root) {
        return (
            SkillTrustLevel::Trusted,
            "Project-local catalog under .pi/skills.".to_string(),
        );
    }

    if source == "user" || path_is_under(&normalized, &global_root) {
        return (
            SkillTrustLevel::Trusted,
            "Managed global catalog under ~/.pi/agent/skills.".to_string(),
        );
    }

    if normalized_lower.contains("/downloads/")
        || normalized_lower.contains("/desktop/")
        || normalized_lower.contains("/tmp/")
        || normalized_lower.contains("/var/folders/")
        || normalized_lower.contains("\\downloads\\")
        || normalized_lower.contains("\\desktop\\")
        || normalized_lower.contains("\\temp\\")
    {
        return (
            SkillTrustLevel::Risky,
            "Loaded from a transient import location. Review before enabling for operators."
                .to_string(),
        );
    }

    if source == "path" && path_is_under(&normalized, cwd) {
        return (
            SkillTrustLevel::Review,
            "Explicit workspace override path. Check provenance once before sharing it."
                .to_string(),
        );
    }

    if source == "path" {
        return (
            SkillTrustLevel::Risky,
            "External path override outside managed skill roots.".to_string(),
        );
    }

    (
        SkillTrustLevel::Review,
        "Skill provenance is not managed by the built-in catalogs.".to_string(),
    )
}

impl DesktopDrafts {
    fn from_snapshot(snapshot: &DesktopSnapshot) -> Self {
        let selected_agent_profile = snapshot
            .context
            .agent_profile(&snapshot.context.defaults.starter_agent)
            .or_else(|| snapshot.context.agent_profiles.first())
            .map(|profile| profile.id.clone())
            .unwrap_or_else(|| "main".to_string());
        let mut drafts = Self {
            session_filter: String::new(),
            workspace_focus: String::new(),
            session_agent_focus: ALL_AGENT_LANE_ID.to_string(),
            chat_prompt: String::new(),
            chat_attachment_input: String::new(),
            chat_attachment_paths: Vec::new(),
            chat_credential_input: String::new(),
            chat_credential_masked: true,
            session_name_draft: snapshot
                .latest_session()
                .map(|session| session.title.clone())
                .unwrap_or_default(),
            default_provider_preset: snapshot.context.defaults.default_provider_preset.clone(),
            default_provider: snapshot.context.defaults.default_provider.clone(),
            default_model: snapshot.context.defaults.default_model.clone(),
            default_base_url: snapshot.context.defaults.default_base_url.clone(),
            default_api_key_input: String::new(),
            default_api_key_masked: true,
            starter_agent: snapshot.context.defaults.starter_agent.clone(),
            desktop_language: snapshot.context.defaults.desktop_language.clone(),
            desktop_theme: snapshot.context.defaults.desktop_theme.clone(),
            selected_agent_profile,
            custom_agent_id: String::new(),
            agent_display_name: String::new(),
            agent_description: String::new(),
            agent_mode_id: "follow_main".to_string(),
            agent_provider: String::new(),
            agent_model: String::new(),
            agent_skills: String::new(),
            agent_prompts: String::new(),
            selected_channel_binding: snapshot
                .context
                .channel_bindings
                .first()
                .map(|binding| binding.id.clone())
                .unwrap_or_default(),
            channel_enabled: false,
            channel_agent_profile: String::new(),
            channel_field_values: HashMap::new(),
            local_bridge_enabled: snapshot.context.local_bridge.enabled,
            local_bridge_port: snapshot.context.local_bridge.port.to_string(),
            local_bridge_control_plane_url: snapshot.context.local_bridge.control_plane_url.clone(),
            local_bridge_device_label: snapshot.context.local_bridge.device_label.clone(),
            security_profile: snapshot.context.security.profile.clone(),
            security_default_permissive: snapshot.context.security.default_permissive,
            security_allow_dangerous: snapshot.context.security.allow_dangerous,
            security_sandbox_mode: snapshot.context.security.sandbox_mode.clone(),
            security_gateway_preset: snapshot.context.security.gateway.preset,
            security_gateway_custom_url: snapshot.context.security.gateway.custom_url.clone(),
            security_gateway_show_advanced: snapshot.context.security.gateway.preset
                == GatewayPresetMode::Custom,
            security_browser_automation: snapshot.context.security.browser_automation,
            security_conflict_guard: snapshot.context.security.conflict_guard,
            security_scoped_directories: snapshot.context.security.scoped_directories.join("; "),
            check_for_updates: snapshot.context.defaults.check_for_updates,
            enable_skill_commands: snapshot.context.defaults.enable_skill_commands,
            global_skill_paths: snapshot.context.global_skill_paths.join("; "),
            project_skill_paths: snapshot.context.project_skill_paths.join("; "),
        };
        let selected = drafts.selected_agent_profile.clone();
        drafts.select_agent_profile(snapshot, &selected);
        let selected_channel = drafts.selected_channel_binding.clone();
        drafts.select_channel_binding(snapshot, &selected_channel);
        drafts
    }

    fn select_agent_profile(&mut self, snapshot: &DesktopSnapshot, profile_id: &str) {
        if let Some(profile) = snapshot.context.agent_profile(profile_id) {
            self.selected_agent_profile = profile.id.clone();
            self.custom_agent_id =
                suggest_agent_profile_id(&profile.id, &snapshot.context.agent_profiles);
            self.agent_display_name = profile.display_name.clone();
            self.agent_description = profile.description.clone();
            self.agent_mode_id = profile.mode_id.clone();
            self.agent_provider = profile.provider.clone().unwrap_or_default();
            self.agent_model = profile.model.clone().unwrap_or_default();
            self.agent_skills = profile.skills.join("; ");
            self.agent_prompts = profile.prompts.join("; ");
        }
    }

    fn select_channel_binding(&mut self, snapshot: &DesktopSnapshot, binding_id: &str) {
        if let Some(binding) = snapshot.context.channel_binding(binding_id) {
            self.selected_channel_binding = binding.id.clone();
            self.channel_enabled = binding.enabled;
            self.channel_agent_profile = binding.agent_profile.clone();
            self.channel_field_values = binding.config.clone();
        }
    }

    fn channel_text_value(&self, field_id: &str) -> String {
        match self.channel_field_values.get(field_id) {
            Some(ChannelDraftValue::Text(value)) => value.clone(),
            Some(ChannelDraftValue::Bool(value)) => {
                if *value {
                    "true".to_string()
                } else {
                    "false".to_string()
                }
            }
            None => String::new(),
        }
    }

    fn channel_bool_value(&self, field_id: &str) -> bool {
        match self.channel_field_values.get(field_id) {
            Some(ChannelDraftValue::Bool(value)) => *value,
            Some(ChannelDraftValue::Text(value)) => value == "true",
            None => false,
        }
    }
}

