fn build_system_summaries(
    cwd: &Path,
    active_system_id: &str,
    systems: Option<&[SystemProfile]>,
    defaults: &DesktopDefaultsState,
    agent_profiles: &[AgentProfileSummary],
    channel_bindings: &[ChannelBindingSummary],
    security: &SecurityState,
) -> Vec<SystemSummary> {
    let artifact_registry = ArtifactRegistry::new(cwd);
    let mut summaries = systems
        .unwrap_or(&[])
        .iter()
        .map(|system| {
            let top_roles = system
                .team_blueprint
                .as_ref()
                .map(|team| {
                    team.roles
                        .iter()
                        .take(4)
                        .map(|role| role.name.clone())
                        .collect::<Vec<_>>()
                })
                .unwrap_or_default();
            let enabled_memory_count = system.memory_strategy.enabled_buckets().count();
            let total_memory_count = system.memory_strategy.buckets.len();
            let vault_system_root = cwd.join(".pi").join("vault").join(&system.id);
            let snapshot_count = count_json_files_in_dir(&vault_system_root.join("snapshots"));
            let branch_count = count_json_files_in_dir(&vault_system_root.join("branches"));
            SystemSummary {
                id: system.id.clone(),
                name: system.name.clone(),
                template_type: system.template_type.clone(),
                status: system.status.label().to_string(),
                description: system.description.clone().unwrap_or_default(),
                provider: system.provider.clone(),
                model: system.model.clone(),
                role_count: system.role_count(),
                top_roles,
                enabled_memory_count,
                total_memory_count,
                binding_count: system.bindings.len(),
                automation_count: system
                    .automations
                    .iter()
                    .filter(|item| item.enabled)
                    .count(),
                skill_count: system.skills.len(),
                prompt_count: system.prompts.len(),
                default_role: system.routing_policy.default_role.clone(),
                task_route_count: system.routing_policy.task_role_map.len(),
                permission_summary: summarize_permission_policy(&system.permission_policy),
                has_baseline: system.has_baseline(),
                baseline_snapshot_id: system.baseline_snapshot_id.clone(),
                active_snapshot_id: system.active_snapshot_id.clone(),
                current_branch_id: system.current_branch_id.clone(),
                artifact_count: artifact_registry.count_for_system(&system.id),
                snapshot_count,
                branch_count,
                updated_at: system
                    .updated_at
                    .clone()
                    .or_else(|| system.created_at.clone()),
                is_active: system.id == active_system_id,
                is_fallback: false,
            }
        })
        .collect::<Vec<_>>();

    if summaries.is_empty() {
        let standard_memory = MemoryStrategy::standard();
        let enabled_channel_count = channel_bindings
            .iter()
            .filter(|binding| binding.enabled)
            .count();
        summaries.push(SystemSummary {
            id: active_system_id.to_string(),
            name: "maoclaw Desktop Runtime".to_string(),
            template_type: "desktop_runtime".to_string(),
            status: "active".to_string(),
            description: "Fallback system synthesized from desktop defaults until a persisted SystemProfile is saved.".to_string(),
            provider: non_empty_owned(&defaults.default_provider),
            model: non_empty_owned(&defaults.default_model),
            role_count: agent_profiles.len(),
            top_roles: agent_profiles
                .iter()
                .take(4)
                .map(|profile| profile.display_name.clone())
                .collect(),
            enabled_memory_count: standard_memory.enabled_buckets().count(),
            total_memory_count: standard_memory.buckets.len(),
            binding_count: enabled_channel_count,
            automation_count: 0,
            skill_count: 0,
            prompt_count: 0,
            default_role: non_empty_owned(&defaults.starter_agent),
            task_route_count: 0,
            permission_summary: format!(
                "desktop sandbox={} · network={} · browser={}",
                security.sandbox_mode,
                bool_label(security.gateway.preset != GatewayPresetMode::Disabled),
                bool_label(security.browser_automation)
            ),
            has_baseline: false,
            baseline_snapshot_id: None,
            active_snapshot_id: None,
            current_branch_id: None,
            artifact_count: artifact_registry.count_for_system(active_system_id),
            snapshot_count: count_json_files_in_dir(
                &cwd.join(".pi").join("vault").join(active_system_id).join("snapshots"),
            ),
            branch_count: count_json_files_in_dir(
                &cwd.join(".pi").join("vault").join(active_system_id).join("branches"),
            ),
            updated_at: None,
            is_active: true,
            is_fallback: true,
        });
    } else if !summaries.iter().any(|summary| summary.is_active) {
        if let Some(first) = summaries.first_mut() {
            first.is_active = true;
        }
    }

    summaries.sort_by(|left, right| {
        right
            .is_active
            .cmp(&left.is_active)
            .then_with(|| left.name.cmp(&right.name))
    });
    summaries
}

fn build_control_workbench_snapshot(context: &DesktopContext) -> ControlWorkbenchSnapshot {
    let cwd = Path::new(&context.cwd);
    let vault = crate::vault::VaultManager::new(cwd);
    let artifacts = ArtifactRegistry::new(cwd);
    let memory = crate::memory_v2::MemoryStore::new(cwd);
    let automations = crate::automations::AutomationRegistry::new(cwd);

    let mut system_ids = context
        .systems
        .iter()
        .map(|system| system.id.clone())
        .collect::<Vec<_>>();
    if system_ids.is_empty() && !context.active_system_id.trim().is_empty() {
        system_ids.push(context.active_system_id.clone());
    }

    let systems = system_ids
        .into_iter()
        .map(|system_id| {
            let memory_partitions = crate::memory_v2::MemoryPartition::all()
                .iter()
                .copied()
                .map(|partition| {
                    let entries = memory
                        .load_partition(&system_id, partition)
                        .unwrap_or_default();
                    let frozen_count = entries.iter().filter(|entry| entry.frozen).count();
                    let last_ingest_at = entries.last().map(|entry| entry.created_at.clone());
                    WorkbenchMemoryPartition {
                        partition,
                        entries,
                        frozen_count,
                        last_ingest_at,
                    }
                })
                .collect();

            ControlWorkbenchSystem {
                vault_snapshots: vault.list_snapshots(&system_id).unwrap_or_default(),
                vault_branches: vault.list_branches(&system_id).unwrap_or_default(),
                artifacts: artifacts.list_for_system(&system_id).unwrap_or_default(),
                automations: automations.list_for_system(&system_id).unwrap_or_default(),
                memory_partitions,
                system_id,
            }
        })
        .collect();

    ControlWorkbenchSnapshot { systems }
}

fn summarize_permission_policy(policy: &crate::system_profile::PermissionPolicy) -> String {
    [
        format!("bash={}", bool_option_label(policy.allow_bash)),
        format!("write={}", bool_option_label(policy.allow_file_write)),
        format!("network={}", bool_option_label(policy.allow_network)),
        format!("browser={}", bool_option_label(policy.allow_browser)),
    ]
    .join(" · ")
}

fn bool_option_label(value: Option<bool>) -> &'static str {
    match value {
        Some(true) => "on",
        Some(false) => "off",
        None => "inherit",
    }
}

fn bool_label(value: bool) -> &'static str {
    if value { "on" } else { "off" }
}

fn non_empty_owned(value: &str) -> Option<String> {
    let trimmed = value.trim();
    (!trimmed.is_empty()).then(|| trimmed.to_string())
}

fn build_agent_profiles(
    config: &Config,
    registry: &AgentProfileRegistry,
) -> Vec<AgentProfileSummary> {
    let builtin_by_id = builtin_profiles()
        .into_iter()
        .map(|profile| (profile.id.clone(), profile))
        .collect::<HashMap<_, _>>();
    let overrides = config.agent_profiles.clone().unwrap_or_default();

    registry
        .all()
        .iter()
        .map(|profile| {
            let builtin = builtin_by_id.get(&profile.id);
            let override_cfg = overrides.get(&profile.id);
            let has_skills_override = override_cfg.and_then(|cfg| cfg.skills.as_ref()).is_some();
            let skill_scope = if has_skills_override {
                if profile.skills.is_empty() {
                    "Per-agent bundle disabled".to_string()
                } else {
                    "Per-agent custom bundle".to_string()
                }
            } else if builtin.is_some_and(|base| !base.skills.is_empty()) {
                "Shipped profile bundle".to_string()
            } else {
                "Global-only".to_string()
            };

            AgentProfileSummary {
                id: profile.id.clone(),
                display_name: profile.display_name.clone(),
                description: profile.description.clone(),
                mode_id: profile.mode.as_str().to_string(),
                mode_label: profile.mode_label(),
                provider: (profile.mode == crate::agent_profiles::AgentProfileMode::Override)
                    .then(|| profile.provider.clone())
                    .flatten(),
                model: (profile.mode == crate::agent_profiles::AgentProfileMode::Override)
                    .then(|| profile.model.clone())
                    .flatten(),
                skills: profile.skills.clone(),
                builtin_skills: builtin.map_or_else(Vec::new, |base| base.skills.clone()),
                prompts: profile.prompts.clone(),
                skill_scope,
                has_customizations: override_cfg.is_some(),
                is_builtin: builtin.is_some(),
                base_display_name: builtin.map(|base| base.display_name.clone()),
                base_description: builtin.map(|base| base.description.clone()),
                base_mode_id: builtin.map(|base| base.mode.as_str().to_string()),
                base_provider: builtin.and_then(|base| base.provider.clone()),
                base_model: builtin.and_then(|base| base.model.clone()),
                base_prompts: builtin.map_or_else(Vec::new, |base| base.prompts.clone()),
            }
        })
        .collect()
}

