fn build_channel_bindings(config: &Config) -> Vec<ChannelBindingSummary> {
    let mut by_id = config
        .bindings
        .clone()
        .unwrap_or_default()
        .into_iter()
        .map(|binding| (binding.id.clone(), binding))
        .collect::<HashMap<_, _>>();

    let mut merged = Vec::new();
    for template in default_channel_bindings() {
        if let Some(existing) = by_id.remove(&template.id) {
            merged.push(merge_channel_binding(template, existing));
        } else {
            merged.push(template);
        }
    }
    merged.extend(by_id.into_values());
    merged.sort_by(|left, right| left.id.cmp(&right.id));

    merged
        .into_iter()
        .map(channel_binding_summary)
        .collect::<Vec<_>>()
}

fn merge_channel_binding(template: BindingConfig, existing: BindingConfig) -> BindingConfig {
    let config = match (template.config, existing.config) {
        (Some(Value::Object(mut base)), Some(Value::Object(other))) => {
            for (key, value) in other {
                base.insert(key, value);
            }
            Some(Value::Object(base))
        }
        (_, some @ Some(_)) => some,
        (some @ Some(_), None) => some,
        (None, None) => None,
    };

    BindingConfig {
        id: existing.id,
        platform: if existing.platform.is_empty() {
            template.platform
        } else {
            existing.platform
        },
        enabled: existing.enabled.or(template.enabled),
        agent_profile: existing.agent_profile.or(template.agent_profile),
        config,
    }
}

