fn save_agent_profile_override(
    snapshot: &DesktopSnapshot,
    drafts: &DesktopDrafts,
) -> Result<String, String> {
    let profile = snapshot
        .context
        .agent_profile(&drafts.selected_agent_profile)
        .ok_or_else(|| "Selected agent profile is missing".to_string())?;
    let cwd = native_workspace_root();
    let global_dir = Config::global_dir();
    let global_settings_path =
        Config::settings_path_with_roots(SettingsScope::Global, &global_dir, &cwd);
    let existing = read_agent_profile_overrides(&global_settings_path);
    let mut next = existing;

    if let Some(override_value) = canonical_agent_override(profile, drafts) {
        next.insert(profile.id.clone(), override_value);
    } else {
        next.remove(&profile.id);
    }

    let patch = if next.is_empty() {
        json!({
            "agentProfiles": Value::Null,
            "agent_profiles": Value::Null
        })
    } else {
        json!({
            "agentProfiles": Value::Null,
            "agent_profiles": Value::Object(next)
        })
    };

    Config::patch_settings_with_roots(SettingsScope::Global, &global_dir, &cwd, patch)
        .map(|path| {
            format!(
                "Saved profile override for {} in {}",
                profile.id,
                path.display()
            )
        })
        .map_err(|err| format!("Failed to save agent profile: {err}"))
}

fn create_agent_profile(
    snapshot: &DesktopSnapshot,
    drafts: &DesktopDrafts,
) -> Result<(String, String), String> {
    let cwd = native_workspace_root();
    let global_dir = Config::global_dir();
    create_agent_profile_with_roots(snapshot, drafts, &cwd, &global_dir)
}

fn create_agent_profile_with_roots(
    snapshot: &DesktopSnapshot,
    drafts: &DesktopDrafts,
    cwd: &Path,
    global_dir: &Path,
) -> Result<(String, String), String> {
    let global_settings_path =
        Config::settings_path_with_roots(SettingsScope::Global, global_dir, cwd);
    let mut next = read_agent_profile_overrides(&global_settings_path);
    let profile_id = sanitize_agent_profile_id(&drafts.custom_agent_id);
    if profile_id.is_empty() {
        return Err("Custom agent id cannot be empty".to_string());
    }
    if snapshot.context.agent_profile(&profile_id).is_some() || next.contains_key(&profile_id) {
        return Err(format!("Agent profile {profile_id} already exists"));
    }

    let profile_value = custom_agent_profile_value(drafts)?;
    next.insert(profile_id.clone(), profile_value);

    let patch = json!({
        "agentProfiles": Value::Null,
        "agent_profiles": Value::Object(next)
    });

    Config::patch_settings_with_roots(SettingsScope::Global, global_dir, cwd, patch)
        .map(|path| {
            (
                format!(
                    "Created custom profile {} in {}",
                    profile_id,
                    path.display()
                ),
                profile_id,
            )
        })
        .map_err(|err| format!("Failed to create agent profile: {err}"))
}

