fn save_chat_provider_credential(provider: String, key: String) -> Result<String, String> {
    let provider = provider.trim().to_string();
    let key = key.trim().to_string();
    if provider.is_empty() {
        return Err("Credential target provider is empty".to_string());
    }
    if key.is_empty() {
        return Err("API key cannot be empty".to_string());
    }

    let mut auth = load_default_auth(&Config::auth_path())
        .map_err(|err| format!("Failed to load desktop auth store: {err}"))?;
    auth.set(provider.clone(), AuthCredential::ApiKey { key });
    auth.save()
        .map_err(|err| format!("Failed to save desktop auth store: {err}"))?;

    Ok(format!("Credential saved for {provider}"))
}

fn save_local_bridge_settings(drafts: &DesktopDrafts) -> Result<String, String> {
    let cwd = native_workspace_root();
    let global_dir = Config::global_dir();
    let port_text = drafts.local_bridge_port.trim();
    let port = if port_text.is_empty() {
        crate::bridge::DEFAULT_BRIDGE_PORT
    } else {
        port_text
            .parse::<u16>()
            .map_err(|_| "Bridge port must be a valid number between 0 and 65535".to_string())?
    };
    let control_plane_url = drafts.local_bridge_control_plane_url.trim();
    if !control_plane_url.is_empty() {
        let url = Url::parse(control_plane_url)
            .map_err(|err| format!("Control plane URL is invalid: {err}"))?;
        if !matches!(url.scheme(), "http" | "https") {
            return Err("Control plane URL must use http or https".to_string());
        }
        if url.host_str().is_none() {
            return Err("Control plane URL must include a host".to_string());
        }
    }

    let patch = json!({
        "bridge": {
            "enabled": drafts.local_bridge_enabled,
            "port": port,
            "control_plane_url": if control_plane_url.is_empty() {
                Value::Null
            } else {
                Value::String(control_plane_url.to_string())
            },
            "device_label": if drafts.local_bridge_device_label.trim().is_empty() {
                Value::Null
            } else {
                Value::String(drafts.local_bridge_device_label.trim().to_string())
            },
        }
    });

    Config::patch_settings_with_roots(SettingsScope::Project, &global_dir, &cwd, patch)
        .map(|path| format!("Saved local bridge settings in {}", path.display()))
        .map_err(|err| format!("Failed to save local bridge settings: {err}"))
}

fn forget_default_provider_credential(provider: String) -> Result<String, String> {
    forget_provider_credential_at_path(&Config::auth_path(), provider)
}

fn forget_provider_credential_at_path(
    auth_path: &Path,
    provider: String,
) -> Result<String, String> {
    let provider = provider.trim().to_string();
    if provider.is_empty() {
        return Err("Default provider is empty".to_string());
    }

    let canonical_provider = canonical_provider_id(&provider).unwrap_or(provider.as_str());
    let mut auth = load_default_auth(auth_path)
        .map_err(|err| format!("Failed to load desktop auth store: {err}"))?;
    let mut removed = auth.remove(&provider);
    if canonical_provider != provider {
        removed |= auth.remove(canonical_provider);
    }
    auth.save()
        .map_err(|err| format!("Failed to save desktop auth store: {err}"))?;

    if removed {
        Ok(format!("Removed saved credential for {canonical_provider}"))
    } else {
        Ok(format!(
            "No saved credential found for {canonical_provider}"
        ))
    }
}

