    fn write_session_preview_fixture(path: &Path, prompts: &[&str]) {
        use std::io::Write as _;

        let mut header = SessionHeader::default();
        header.cwd = path
            .parent()
            .unwrap_or_else(|| Path::new("/tmp"))
            .display()
            .to_string();
        header.provider = Some("openai".to_string());
        header.model_id = Some("gpt-5".to_string());

        let mut file = File::create(path).expect("create session fixture");
        writeln!(
            file,
            "{}",
            serde_json::to_string(&header).expect("serialize header")
        )
        .expect("write header");

        for (index, prompt) in prompts.iter().enumerate() {
            let entry = SessionEntry::Message(crate::session::MessageEntry {
                base: crate::session::EntryBase {
                    id: Some(format!("msg-{index}")),
                    parent_id: None,
                    timestamp: format!("2026-03-18T09:{index:02}:00.000Z"),
                },
                message: SessionMessage::User {
                    content: UserContent::Text((*prompt).to_string()),
                    timestamp: Some(index as i64),
                },
            });
            writeln!(
                file,
                "{}",
                serde_json::to_string(&entry).expect("serialize entry")
            )
            .expect("write entry");
        }
    }

