    #[test]
    fn gateway_legacy_direct_maps_to_disabled_state() {
        let mut desktop_security = serde_json::Map::new();
        desktop_security.insert(
            "gatewayMode".to_string(),
            Value::String("direct".to_string()),
        );
        let state = build_gateway_access_state(&desktop_security);
        assert_eq!(state.preset, GatewayPresetMode::Disabled);
        assert_eq!(state.health, GatewayHealthState::Disabled);
    }

    #[test]
    fn gateway_local_preset_generates_token_patch() {
        let current = GatewayAccessState::default();
        let drafts = DesktopDrafts {
            security_gateway_preset: GatewayPresetMode::LocalOnly,
            ..DesktopDrafts::default()
        };

        let patch = build_gateway_settings_patch(&current, &drafts).expect("patch");
        assert_eq!(patch["legacyMode"], "loopback");
        assert_eq!(patch["gateway"]["preset"], "local_only");
        assert_eq!(patch["gateway"]["bind"], "loopback");
        assert_eq!(patch["gateway"]["auth"]["mode"], "token");
        assert!(
            patch["gateway"]["auth"]["token"]
                .as_str()
                .is_some_and(|value| value.starts_with("mcw_"))
        );
    }

