    #[test]
    fn rpc_prompt_error_marks_504_as_retryable_timeout() {
        let retry_state = RpcRetryState {
            attempts: 3,
            max_attempts: Some(3),
            completed: true,
            success: Some(false),
        };

        let formatted = format_rpc_prompt_error(
            "Provider error: openai: OpenAI upstream timeout (HTTP 504): Gateway Timeout",
            None,
            &retry_state,
        );

        assert!(formatted.contains("timed out upstream"));
        assert!(formatted.contains("Automatic retries exhausted (3/3)."));
        assert!(formatted.contains("custom gateway/base URL timeout"));
    }

