    #[test]
    fn pending_prompt_only_renders_inside_target_session() {
        let mut shell = fresh_desktop_shell();
        shell.pending_chat_prompt = Some("follow up".to_string());
        shell.pending_chat_session_path = Some("/tmp/target.jsonl".to_string());
        shell.chat_run_state = ChatRunState::Accepted;

        shell.selected_session_path = Some("/tmp/other.jsonl".to_string());
        assert_eq!(shell.pending_chat_prompt_for_current_view(), None);
        assert_eq!(shell.effective_chat_run_state(None), ChatRunState::Live);

        shell.selected_session_path = Some("/tmp/target.jsonl".to_string());
        assert_eq!(
            shell.pending_chat_prompt_for_current_view(),
            Some("follow up")
        );
        assert_eq!(shell.effective_chat_run_state(None), ChatRunState::Accepted);
    }

