    #[test]
    fn queued_prompts_only_render_for_matching_session() {
        let mut shell = fresh_desktop_shell();
        shell.queued_chat_prompts.push_back(QueuedChatPrompt {
            prompt: "first".to_string(),
            session_path: Some("/tmp/target.jsonl".to_string()),
            defaults: None,
        });
        shell.queued_chat_prompts.push_back(QueuedChatPrompt {
            prompt: "second".to_string(),
            session_path: Some("/tmp/other.jsonl".to_string()),
            defaults: None,
        });

        shell.selected_session_path = Some("/tmp/target.jsonl".to_string());
        assert_eq!(shell.queued_prompts_for_current_view().count(), 1);

        shell.selected_session_path = Some("/tmp/other.jsonl".to_string());
        assert_eq!(shell.queued_prompts_for_current_view().count(), 1);

        shell.selected_session_path = None;
        assert_eq!(shell.queued_prompts_for_current_view().count(), 0);
    }

